terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Route 53 query logging requires us-east-1
}

# Hosted zone named "primary"
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

# CloudWatch Log Group for Route 53 query logging
resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "aws_route53_example_com"
  retention_in_days = 14
}

# CloudWatch Log Resource Policy to allow Route 53 to create log streams and put log events
resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_name     = "route53-query-logging-policy"
  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.aws_route53_example_com.arn}:*"
      }
    ]
  })
}

# Associate query logging configuration with the hosted zone
resource "aws_route53_query_log" "primary_query_log" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53_query_logging_policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

