terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (update region as needed)
provider "aws" {
  region = "us-east-1"
}

# VPC where the private hosted zone will be associated
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "example-vpc"
  }
}

# Private hosted zone
resource "aws_route53_zone" "private" {
  name = "example.internal"

  vpc {
    vpc_id = aws_vpc.example.id
  }

  tags = {
    Name = "example-private-zone"
  }
}

# Route 53 zone association - associates the private hosted zone with another VPC
resource "aws_route53_zone_association" "example" {
  zone_id = aws_route53_zone.private.id

  vpc_id = aws_vpc.example.id  # Can reference a different VPC ID
}
```

This configuration creates:
- A VPC
- A private Route 53 hosted zone associated with that VPC
- A zone association resource linking the hosted zone to the VPC (valid for demonstrating the resource usage)

