  zone_id = aws_route53_zone.main.zone_id
  name    = "primary.main.example.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_db_instance.primary.endpoint]

  depends_on = [aws_db_instance.primary]
}

resource "aws_route53_record" "db_replicas" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replicas.main.example.com"
  type    = "A"

  set_identifier = "replica-1"
  weighted_routing_policy {
    weight = 50
  }

  health_check_id = aws_route53_health_check.replica_1.id

  alias {
    name                   = aws_db_instance.replica_1.endpoint
    zone_id                = "Z1UJRXOUMOOFQ8" # RDS alias zone ID (varies by region)
    evaluate_target_health = true
  }

  depends_on = [aws_db_instance.replica_1]
}

resource "aws_route53_record" "db_replicas_replica2" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "replicas.main.example.com"
  type    = "A"

  set_identifier = "replica-2"
  weighted_routing_policy {
    weight = 50
  }

  health_check_id = aws_route53_health_check.replica_2.id

  alias {
    name                   = aws_db_instance.replica_2.endpoint
    zone_id                = "Z1UJRXOUMOOFQ8" # RDS alias zone ID
    evaluate_target_health = true
  }

  depends_on = [aws_db_instance.replica_2]
}

