}

# IAM Role for EC2 instances in Elastic Beanstalk
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach AWS managed policy for Elastic Beanstalk EC2 role
resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# IAM Instance Profile for EC2
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_application" {
  name = "my_application"
}

# Elastic Beanstalk Application Version (sample)
resource "aws_s3_bucket" "eb_app_bucket" {
  bucket = "my-eb-app-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_object" "app_version" {
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = "app.zip"
  source = "app.zip"  # Replace with path to your application zip file
  etag   = filemd5("app.zip")
}

resource "aws_elastic_beanstalk_application_version" "default" {
  name   = "v1.0"
  application = aws_elastic_beanstalk_application.my_application.name
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = aws_s3_object.app_version.id
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "my_environment" {
  name                = "my-environment"
  application         = aws_elastic_beanstalk_application.my_application.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = ""  # Specify your VPC ID if needed
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = ""  # Specify your subnet IDs (comma-separated)
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "APP_VERSION"
    value     = aws_elastic_beanstalk_application_version.default.name
  }

  depends_on = [
    aws_elastic_beanstalk_application_version.default,
    aws_iam_instance_profile.eb_ec2_profile
  ]
}

