provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# IAM Role for EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach AWS managed policy to the role
resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_api_app" {
  name = "my_api_app"
}

# Elastic Beanstalk Application Version (placeholder - replace with your app zip)
resource "aws_s3_bucket" "eb_app_bucket" {
  bucket = "my-api-app-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_object" "app_version" {
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = "app.zip"
  source = "app.zip"  # Replace with path to your application zip file
}

resource "aws_elastic_beanstalk_application_version" "app_version" {
  name   = "v1.0"
  application = aws_elastic_beanstalk_application.my_api_app.name
  bucket = aws_s3_bucket.eb_app_bucket.id
  key    = aws_s3_object.app_version.key
}

# Launch Configuration for Auto Scaling
resource "aws_launch_configuration" "eb_launch_config" {
  name_prefix                 = "eb-launch-"
  image_id                    = "ami-0c02fb55956c7d316"  # Amazon Linux 2 for EB
  instance_type               = "t3.micro"
  iam_instance_profile        = aws_iam_instance_profile.eb_ec2_profile.name
  security_groups             = [aws_security_group.eb_sg.id]

  user_data = base64encode(<<-EOF
#!/bin/bash
echo "Configuring Elastic Beanstalk instance..."
EOF
  )

  lifecycle {
    create_before_destroy = true
  }
}

# Security Group for EB
resource "aws_security_group" "eb_sg" {
  name_prefix = "eb-sg-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Data source for default VPC
data "aws_vpc" "default" {
  default = true
}

# Auto Scaling Group
resource "aws_autoscaling_group" "eb_asg" {
  name                = "eb-asg"
  launch_configuration = aws_launch_configuration.eb_launch_config.name
  vpc_zone_identifier = data.aws_subnets.default.ids
  min_size            = 2
  max_size            = 4
  desired_capacity    = 2
  health_check_type   = "ELB"
  health_check_grace_period = 300

  tag {
    key                 = "Name"
    value               = "EB-ASG"
    propagate_at_launch = true
  }
}

# Auto Scaling Policy - Scale Out (CPU > 70%)
resource "aws_autoscaling_policy" "scale_out" {
  name                   = "scale-out"
  scaling_adjustment     = 1
  adjustment_type        = "ChangeInCapacity"
  cooldown              = 300
  autoscaling_group_name = aws_autoscaling_group.eb_asg.name
}

# Auto Scaling Policy - Scale In (CPU < 30%)
resource "aws_autoscaling_policy" "scale_in" {
  name                   = "scale-in"
  scaling_adjustment     = -1
  adjustment_type        = "ChangeInCapacity"
  cooldown              = 300
  autoscaling_group_name = aws_autoscaling_group.eb_asg.name
}

# CloudWatch Alarm for High CPU (Scale Out)
resource "aws_cloudwatch_metric_alarm" "high_cpu" {
  alarm_name          = "eb-high-cpu"
  comparison_operator = "GreaterThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = "300"
  statistic           = "Average"
  threshold           = "70"
  alarm_description   = "This metric monitors ec2 cpu utilization exceeding 70%"
  alarm_actions       = [aws_autoscaling_policy.scale_out.arn]
  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.eb_asg.name
  }
}

# CloudWatch Alarm for Low CPU (Scale In)
resource "aws_cloudwatch_metric_alarm" "low_cpu" {
  alarm_name          = "eb-low-cpu"
  comparison_operator = "LessThanThreshold"
  evaluation_periods  = "2"
  metric_name         = "CPUUtilization"
  namespace           = "AWS/EC2"
  period              = "300"
  statistic           = "Average"
  threshold           = "30"
  alarm_description   = "This metric monitors ec2 cpu utilization below 30%"
  alarm_actions       = [aws_autoscaling_policy.scale_in.arn]
  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.eb_asg.name
  }
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "my_api_env" {
  name                = "my-api-env"
  application         = aws_elastic_beanstalk_application.my_api_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.5 running .NET Core"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
