}

# S3 Bucket for application artifacts
resource "aws_s3_bucket" "app_bucket" {
  bucket = "sampleapril26426"
}

resource "aws_s3_bucket_ownership_controls" "app_bucket" {
  bucket = aws_s3_bucket.app_bucket.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "app_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.app_bucket]

  bucket = aws_s3_bucket.app_bucket.id
  acl    = "private"
}

# S3 Object for application version
resource "aws_s3_object" "app_version" {
  bucket = aws_s3_bucket.app_bucket.id
  key    = "examplebucket_object"
  source = "path/to/your/application.zip"  # Replace with actual path to your app zip
  etag   = filemd5("path/to/your/application.zip")
}

# IAM Role for EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy attachments for Elastic Beanstalk worker environment
resource "aws_iam_role_policy_attachment" "eb_worker_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "eb_web_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

resource "aws_iam_role_policy_attachment" "eb_cloudwatch_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchAgentServerPolicy"
}

# SQS Queue for worker environment
resource "aws_sqs_queue" "batch_job_queue" {
  name                      = "batch_job_queue"
  delay_seconds             = 0
  message_retention_seconds = 86400  # 24 hours
  receive_wait_time_seconds = 10
}

# Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "batch_job_app" {
  name        = "batch_job_app"
  description = "Application for batch processing jobs"
}

# Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "version" {
  name        = "version"
  application = aws_elastic_beanstalk_application.batch_job_app.name
  bucket      = aws_s3_bucket.app_bucket.id
  key         = aws_s3_object.app_version.id
}

# Launch Configuration for Worker Environment
resource "aws_launch_template" "eb_worker" {
  name_prefix   = "eb-worker-"
  image_id      = data.aws_ami.amazon_linux.id
  instance_type = "t3.micro"

  iam_instance_profile {
    name = aws_iam_instance_profile.eb_ec2_profile.name
  }

  vpc_security_group_ids = [aws_security_group.eb_worker.id]

  user_data = base64encode(templatefile("${path.module}/worker_user_data.tpl", {
    queue_url = aws_sqs_queue.batch_job_queue.url
  }))
}

# Elastic Beanstalk Worker Environment
resource "aws_elastic_beanstalk_environment" "batch_worker" {
  name                = "batch-worker-env"
  application         = aws_elastic_beanstalk_application.batch_job_app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"  # Worker tier

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "InstanceType"
    value     = "t3.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "SQS_QUEUE_URL"
    value     = aws_sqs_queue.batch_job_queue.url
  }

  setting {
    namespace = "aws:elasticbeanstalk:workerqueue"
    name      = "QueueURL"
    value     = aws_sqs_queue.batch_job_queue.url
  }

  setting {
    namespace = "aws:elasticbeanstalk:workerqueue"
    name      = "MessageBatchSize"
    value     = "10"
  }

  version_label = aws_elastic_beanstalk_application_version.version.name

  depends_on = [
    aws_iam_role_policy_attachment.eb_worker_policy,
    aws_iam_role_policy_attachment.eb_web_policy,
    aws_iam_role_policy_attachment.eb_cloudwatch_policy
  ]
}

# Security Group for Worker Environment
resource "aws_security_group" "eb_worker" {
  name_prefix = "eb-worker-sg-"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict as needed
  }

  egress {
    from_port   = 0
