}

# Data sources
data "aws_ami" "amazon_linux" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["al2023-ami-*-x86_64-kernel-*"]
  }
}

data "aws_vpc" "default" {
  default = true
}
```

**Note:** Create a `worker_user_data.tpl` file in the same directory with the following content for the worker daemon:

```bash
#!/bin/bash
yum update -y
yum install -y awscli
mkdir -p /var/log/eb-sqsd
echo "[default]" > /etc/awscli/config
echo "region = us-east-1" >> /etc/awscli/config
/opt/elasticbeanstalk/tasks/cron/cronrestart.sh
/opt/elasticbeanstalk/tasks/cron/cleanlogs.sh
```

