terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Hosted Zone
resource "aws_route53_zone" "main" {
  name = "example.com"  # Replace with your domain
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp" {
  name = "myapp"
}

# S3 Bucket for application version (unique name)
resource "aws_s3_bucket" "app_bucket" {
  bucket = "myapp-eb-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "app_bucket_versioning" {
  bucket = aws_s3_bucket.app_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 Object for application version
resource "aws_s3_object" "examplebucket_object" {
  bucket = aws_s3_bucket.app_bucket.id
  key    = "app-version.zip"
  source = "app-version.zip"  # Path to your application zip file
}

# IAM Role for EC2
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# Attach AWSElasticBeanstalkWebTier policy
resource "aws_iam_role_policy_attachment" "eb_ec2_web_tier" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Instance Profile
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application Version
resource "aws_elastic_beanstalk_application_version" "version" {
  name   = "version"
  application = aws_elastic_beanstalk_application.myapp.name
  bucket = aws_s3_bucket.app_bucket.id
  key    = aws_s3_object.examplebucket_object.id
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "eb_env" {
  name                = "eb-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = ""  # Specify your VPC ID if needed
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = ""  # Specify your subnet IDs
  }

  depends_on = [aws_iam_instance_profile.eb_ec2_profile]
}

# Route 53 Record to point to Elastic Beanstalk
resource "aws_route53_record" "eb_env" {
  zone_id = aws_route53_zone.main.zone_id
  name    = aws_route53_zone.main.name
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.eb_env.cname
    zone_id                = aws_elastic_beanstalk_environment.eb_env.cname_zone_id
    evaluate_target_health = false
  }
}

# Output the nameservers for the hosted zone
output "nameservers" {
  value = aws_route53_zone.main.name_servers
}

# Output the Elastic Beanstalk environment URL
output "eb_environment_url" {
  value = aws_elastic_beanstalk_environment.eb_env.cname
}
