  }
}

# Route 53 Hosted Zone
data "aws_route53_zone" "main" {
  name         = "example.com" # Replace with your domain
  private_zone = false
}

# Blue A record with Weighted Routing Policy (initially 100% traffic)
resource "aws_route53_record" "blue" {
  zone_id = data.aws_route53_zone.main.zone_id
  name    = "app.example.com" # Replace with your subdomain
  type    = "A"

  set_identifier = "blue"
  weighted_routing_policy {
    region          = "us-east-1"
    failovers       = []
    weight          = 100
  }

  aliases {
    name                   = aws_elastic_beanstalk_environment.blue.cname
    zone_id                = aws_elastic_beanstalk_environment.blue.cname_zone_id
    evaluate_target_health = true
  }
}

# Green A record with Weighted Routing Policy (initially 0% traffic)
