resource "aws_db_subnet_group" "eb_db_subnet_group" {
  name       = "eb-db-subnet-group"
  subnet_ids = data.aws_subnets.default.ids  # Assumes default subnets exist

  tags = {
    Name = "EB DB subnet group"
  }
