  default = true
}

resource "aws_db_instance" "default" {
  identifier             = "default"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  db_subnet_group_name   = aws_db_subnet_group.eb_db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.eb_db.id]
  username               = "admin"
  password               = "SecurePassword123!"  # Use secrets manager in production
  skip_final_snapshot    = true
  publicly_accessible    = false

  tags = {
    Name = "EB Default DB"
  }
}

