  name = "my-app"
}

resource "aws_elastic_beanstalk_application_version" "blue" {
  name        = "v1.0-blue"
  application = aws_elastic_beanstalk_application.app.name
  bucket      = "my-eb-bucket"  # Upload your app zip to this S3 bucket
