  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  depends_on = [aws_db_instance.my_db]
}

# Blue/Green Deployment - Swap URLs (Green becomes production)
