```hcl
provider "aws" {
  region = "us-west-2"
}

# RDS Database
resource "aws_db_snapshot" "pre_deployment_snapshot" {
  db_instance_identifier = aws_db_instance.my_db.id
  db_snapshot_identifier = "my-db-pre-deployment-snapshot"
}

resource "aws_db_instance" "my_db" {
  identifier             = "my_db"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  storage_type           = "gp2"
  username               = "admin"
  password               = "SecurePassword123!"
  publicly_accessible    = false
  skip_final_snapshot    = true

  # Ensure snapshot is taken before any changes (used in deployment process)
  lifecycle {
    ignore_changes = [engine_version]
  }
}

# VPC and Subnets (required for RDS and EB)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "eb-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "private-b"
  }
}

resource "aws_subnet" "public_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.101.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "public-a"
  }
}

resource "aws_subnet" "public_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.102.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "public-b"
  }
}

# Internet Gateway and NAT for EB
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.public_a.id
  depends_on    = [aws_internet_gateway.main]
}

resource "aws_eip" "nat" {
  vpc = true
}

# Route Tables
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }
}

resource "aws_route_table_association" "public_a" {
  subnet_id      = aws_subnet.public_a.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_b" {
  subnet_id      = aws_subnet.public_b.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_a.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.private.id
}

# Security Groups
resource "aws_security_group" "rds_sg" {
  vpc_id = aws_vpc.main.id
  name   = "rds-sg"

  ingress {
    from_port       = 3306
    to_port         = 3306
    protocol        = "tcp"
    security_groups = [aws_security_group.eb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "eb_sg" {
  vpc_id = aws_vpc.main.id
  name   = "eb-sg"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]
}

# Instance Profile for EB
resource "aws_iam_role" "ec2_eb_role" {
  name = "ec2_eb_role1"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "ec2.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_instance_profile" "ec2_eb_profile1" {
  name = "ec2_eb_profile1"
  role = aws_iam_role.ec2_eb_role.name
}

resource "aws_iam_role_policy" "ec2_eb_policy" {
  name = "ec2_eb_policy"
  role = aws_iam_role.ec2_eb_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "rds:DescribeDBInstances",
          "rds:DescribeDBSnapshots",
          "rds:CreateDBSnapshot",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = "s3:*"
        Resource = "*"
      }
    ]
  })
}

# Blue/Green Elastic Beanstalk Environments
resource "aws_elastic_beanstalk_application" "app" {
  name = "my-app"
}

resource "aws_elastic_beanstalk_application_version" "blue" {
  name        = "v1.0-blue"
  application = aws_elastic_beanstalk_application.app.name
  bucket      = "my-eb-bucket"  # Upload your app zip to this S3 bucket
  key         = "app-blue.zip"
}

resource "aws_elastic_beanstalk_application_version" "green" {
  name        = "v1.0-green"
  application = aws_elastic_beanstalk_application.app.name
  bucket      = "my-eb-bucket"
  key         = "app-green.zip"
}

# Blue Environment
resource "aws_elastic_beanstalk_environment" "blue" {
  name                = "blue-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.main.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "${aws_subnet.private_a.id},${aws_subnet.private_b.id}"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = "${aws_subnet.public_a.id},${aws_subnet.public_b.id}"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "ec2_eb_profile1"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.my_db.identifier
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBUser"
    value     = "admin"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPassword"
    value     = "SecurePassword123!"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  depends_on = [aws_db_instance.my_db]
}

# Green Environment
resource "aws_elastic_beanstalk_environment" "green" {
  name                = "green-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"
  version_label       = aws_elastic_beanstalk_application_version.green.name

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.main.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "${aws_subnet.private_a.id},${aws_subnet.private_b.id}"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = "${aws_subnet.public_a.id},${aws_subnet.public_b.id}"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "ec2_eb_profile1"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.my_db.identifier
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBUser"
    value     = "admin"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPassword"
    value     = "SecurePassword123!"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:healthreporting:system"
    name      = "SystemType"
    value     = "enhanced"
  }

  depends_on = [aws_db_instance.my_db]
}

# Blue/Green Deployment - Swap URLs (Green becomes production)
resource "aws_elastic_beanstalk_environment" "production" {
  name                = "production"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"
  version_label       = aws_elastic_beanstalk_application_version.green.name

  # Copy all settings from blue environment
  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = aws_vpc.main.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = "${aws_subnet.private_a.id},${aws_subnet.private_b.id}"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = "${aws_subnet.public_a.id},${aws_subnet.public_b.id}"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "ec2_eb_profile1"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceIdentifier"
    value     = aws_db_instance.my_db.identifier
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBUser"
    value     = "admin"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPassword"
    value     = "SecurePassword123!"
  }

  depends_on = [aws_db_snapshot.pre_deployment_snapshot]
}

# Outputs
output "blue_environment_url" {
  value = aws_elastic_beanstalk_environment.blue.cname
}

output "green_environment_url" {
  value = aws_elastic_beanstalk_environment.green.cname
}

output "production_environment_url" {
  value = aws_elastic_beanstalk_environment.production.cname
}

output "rds_endpoint" {
  value = aws_db_instance.my_db.endpoint
}

output "db_snapshot_id" {
  value = aws_db_snapshot.pre_deployment_snapshot.id
}
```

This configuration creates:

1. **RDS database** named `my_db` with automatic snapshot capability
2. **Instance profile** `ec2_eb_profile1` with necessary permissions
3. **Complete VPC infrastructure** for private RDS and public EB load balancers
4. **Blue/Green EB environments** sharing the same RDS database
5. **Pre-deployment snapshot** taken before environment updates
6. **Production swap** mechanism where green becomes production

**Deployment Process:**
```
1. terraform apply (creates blue as initial environment)
2. Upload new app version to S3
3. Update green environment with new version
4. Swap URLs (green → production, blue → staging)
5. Snapshot taken automatically before DB-related changes
```

Upload your application ZIP files to S3 bucket `my-eb-bucket` as `app-blue.zip` and `app-green.zip`.

