  vpc_id = aws_vpc.eb_vpc.id

  tags = {
    Name = "eb_igw"
  }
}

# Public Subnet 1
resource "aws_subnet" "eb_subnet_public_1" {
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1a"

  tags = {
    Name = "eb_subnet_public_1"
  }
}

# Public Subnet 2
resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id                  = aws_vpc.eb_vpc.id
  cidr_block              = "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone       = "us-east-1b"

  tags = {
    Name = "eb_subnet_public_2"
  }
}

# Public Route Table
resource "aws_route_table" "eb_public_rt" {
  vpc_id = aws_vpc.eb_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.eb_igw.id
  }

  tags = {
    Name = "eb_public_rt"
  }
}

# Route Table Association - Subnet 1
resource "aws_route_table_association" "eb_public_rt_assoc_1" {
  subnet_id      = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.eb_public_rt.id
}

# Route Table Association - Subnet 2
resource "aws_route_table_association" "eb_public_rt_assoc_2" {
  subnet_id      = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.eb_public_rt.id
}

# Security Group for EB and RDS
resource "aws_security_group" "eb_env_sg" {
  name_prefix = "eb_env_sg"
  vpc_id      = aws_vpc.eb_vpc.id

  # Allow HTTP inbound
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow HTTPS inbound
  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH inbound (optional)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "eb_env_sg"
  }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "eb_rds_subnet_group" {
  name       = "eb-rds-subnet-group"
  subnet_ids = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]

  tags = {
    Name = "eb_rds_subnet_group"
  }
}

# Shared RDS Database
resource "aws_db_instance" "shared_rds" {
  identifier              = "shared_rds"
  engine                  = "mysql"
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  max_allocated_storage   = 100
  storage_type            = "gp2"
  db_name                 = "shared_db"
  username                = "admin"
  password                = "SecurePassword123!"  # Use secrets manager in production
  db_subnet_group_name    = aws_db_subnet_group.eb_rds_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.eb_env_sg.id]
  publicly_accessible     = true
  skip_final_snapshot     = true
  backup_retention_period = 7

  tags = {
    Name = "shared_rds"
  }
}

# Elastic Beanstalk Environment 1
