provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Variables for customization
variable "domain_name" {
  description = "The domain name to manage"
  type        = string
  default     = "example.com"
}

variable "hosted_zone_id" {
  description = "The Route53 Hosted Zone ID for the domain"
  type        = string
  # Set this to your actual hosted zone ID
}

# IAM instance profile for EC2
resource "aws_iam_instance_profile" "eb_ec2_profile1" {
  name = "eb_ec2_profile1"
  role = aws_iam_role.eb_ec2_role.name
}

resource "aws_iam_role" "eb_ec2_role" {
  name = "eb-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_worker_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorkerTier"
}

resource "aws_iam_role_policy_attachment" "eb_web_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "myapp" {
  name = "myapp"
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"  # Node.js/Python/etc stack

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = ""  # Specify your VPC ID if needed
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = ""  # Specify your subnet IDs
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile1.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  depends_on = [aws_iam_instance_profile.eb_ec2_profile1]
}

# RDS Database
resource "aws_db_subnet_group" "myapp_db_subnet_group" {
  name       = "myapp-db-subnet-group"
  subnet_ids = []  # Specify your DB subnet IDs here
}

resource "aws_db_instance" "myapp_db" {
  identifier             = "myapp-db"
  engine                 = "mysql"
  engine_version         = "8.0"
  instance_class         = "db.t3.micro"
  allocated_storage      = 20
  db_subnet_group_name   = aws_db_subnet_group.myapp_db_subnet_group.name
  vpc_security_group_ids = []  # Specify your DB security group IDs
  username               = "admin"
  password               = "SecurePassword123!"  # Use secrets manager in production
  skip_final_snapshot    = true
  publicly_accessible    = false
}

# Route 53 Record to point to Elastic Beanstalk
resource "aws_route53_record" "myenv" {
  zone_id = var.hosted_zone_id
  name    = "myenv.${var.domain_name}"
  type    = "A"

  alias {
