terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"

      configuration_aliases = [ aws.us_east_1, aws.eu_west_1 ]
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  alias  = "us_east_1"
  region = "us-east-1"

