  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.us_east.cname
    zone_id                = aws_elastic_beanstalk_environment.us_east.cname_zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "eu_west_alias" {
  provider = aws.use1
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west-1.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.eu_west.cname
    zone_id                = data.aws_elastic_beanstalk_hosted_zone.eu_west.id
    evaluate_target_health = false
  }
}

# Note: You'll need to replace 'example.com' with your actual domain
resource "aws_route53_zone" "main" {
  provider = aws.use1
  name     = "example.com"
}

# Data source for EU hosted zone ID
data "aws_elastic_beanstalk_hosted_zone" "eu_west" {
  provider = aws.euw1
  region   = "eu-west-1"
}
```

**Note:** Replace `"example.com"` with your actual domain name. The configuration includes VPCs, subnets, security groups, IAM roles/profiles, RDS databases connected to Elastic Beanstalk environments, and Route 53 alias records pointing to the EB environments in both regions. The instance profile name "eb_ec2_profile3" is used as requested.

