    key                 = "Environment"
    value               = "green"
    propagate_at_launch = true
  }
}

# ALB Security Group
resource "aws_security_group" "alb_sg" {
  name_prefix = "alb-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# EC2 Security Group
resource "aws_security_group" "ec2_sg" {
  name_prefix = "ec2-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 80
    to_port         = 80
    protocol        = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "myapp.example.com"
}

# Health Checks
resource "aws_route53_health_check" "blue" {
  fqdn              = aws_lb.blue.dns_name
  port              = 80
  type              = "HTTP"
  request_interval  = 30
  failure_threshold = 3
  matcher           = "200"

  tags = {
    Environment = "blue"
  }
}

resource "aws_route53_health_check" "green" {
  fqdn              = aws_lb.green.dns_name
  port              = 80
  type              = "HTTP"
  request_interval  = 30
  failure_threshold = 3
  matcher           = "200"

  tags = {
    Environment = "green"
  }
}

# Blue/Green Failover Routing Policy - Blue Primary, Green Secondary
resource "aws_route53_record" "app" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "A"

  set_identifier = "blue-primary"
  failover_routing_policy = "PRIORITY"

  failover {
    type = "PRIMARY"
    health_check_id = aws_route53_health_check.blue.id
  }

  aliases {
    name                   = aws_lb.blue.dns_name
    zone_id                = aws_lb.blue.zone_id
    evaluate_target_health = true
  }
}

resource "aws_route53_record" "app_green" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.myapp.example.com"
  type    = "A"

  set_identifier = "green-secondary"
  failover_routing_policy = "PRIORITY"

  failover {
    type = "SECONDARY"
    health_check_id = aws_route53_health_check.green.id
  }

  aliases {
    name                   = aws_lb.green.dns_name
    zone_id                = aws_lb.green.zone_id
    evaluate_target_health = true
  }
}

# Route table associations
resource "aws_route_table_association" "public_a" {
  subnet_id      = aws_subnet.public_a.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_a.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.private.id
}

# Outputs
output "dns_name" {
  value = "app.myapp.example.com"
}

output "hosted_zone_id" {
  value = aws_route53_zone.primary.zone_id
}

output "blue_alb_dns" {
  value = aws_lb.blue.dns_name
}

output "green_alb_dns" {
  value = aws_lb.green.dns_name
}

output "db_endpoint" {
  value = aws_db_instance.myapp_db.endpoint
}
```

**Note:** Create these user data template files in your Terraform directory:

**blue_userdata.sh:**
```bash
#!/bin/bash
yum update -y
yum install -y httpd
systemctl start httpd
systemctl enable httpd
echo "<h1>Blue Environment - $(hostname)</h1><p>Connected to RDS: ${db_endpoint}</p>" > /var/www/html/index.html
```

**green_userdata.sh:**
```bash
#!/bin/bash
yum update -y
yum install -y httpd
systemctl start httpd
systemctl enable httpd
echo "<h1>Green Environment - $(hostname)</h1><p>Connected to RDS: ${db_endpoint}</p>" > /var/www/html/index.html
```

This configuration provides:
- Shared RDS database (`myapp_db`)
- Blue/Green environments with ALBs and Auto Scaling Groups
- Instance profile (`eb_ec2_profile`)
- Route 53 with **failover routing policy** (Blue primary, Green secondary)
- Health checks for automatic failover
- Blue starts with instances, Green starts scaled to 0 (scale up for deployments)

