# Terraform configuration for an AWS Elastic Beanstalk Application template
# This creates an Elastic Beanstalk application, environment, and supporting resources

provider "aws" {
  region = var.aws_region
}

# Variables
variable "aws_region" {
  description = "AWS region"
  type        = string
  default     = "us-east-1"
}

variable "application_name" {
  description = "Name of the Elastic Beanstalk application"
  type        = string
  default     = "my-eb-app"
}

variable "environment_name" {
  description = "Name of the Elastic Beanstalk environment"
  type        = string
  default     = "my-eb-env"
}

variable "instance_type" {
  description = "EC2 instance type for the environment"
  type        = string
  default     = "t3.micro"
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name = var.application_name

  tags = {
    Name        = var.application_name
    Environment = "Production"
  }
}

# Elastic Beanstalk Application Version (for sample app)
resource "aws_s3_bucket" "eb_artifacts" {
  bucket = "${var.application_name}-artifacts-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_object" "sample_app" {
  bucket = aws_s3_bucket.eb_artifacts.id
  key    = "sample.zip"
  source = "sample-app.zip"  # Place your application zip file here
  etag   = filemd5("sample-app.zip")
}

resource "aws_elastic_beanstalk_application_version" "sample_version" {
  name    = "sample-v1"
  application = aws_elastic_beanstalk_application.app.name
  bucket  = aws_s3_bucket.eb_artifacts.id
  key     = aws_s3_object.sample_app.key

  depends_on = [aws_s3_object.sample_app]
}

# Launch Configuration for Auto Scaling Group
resource "aws_launch_configuration" "eb_launch_config" {
  name_prefix                 = "${var.environment_name}-"
  image_id                    = data.aws_ami.amazon_linux.id
  instance_type               = var.instance_type
  security_groups             = [aws_security_group.eb_sg.id]
  iam_instance_profile        = aws_iam_instance_profile.eb_profile.name

  user_data = base64encode(<<-EOF
#!/bin/bash
yum update -y
EOF
  )

  lifecycle {
    create_before_destroy = true
  }
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "env" {
  name                = var.environment_name
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.0.7 running Corretto 17"  # Node.js/Python/Java/etc.

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_profile.name
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "3"
  }

  setting {
    namespace = "aws:elasticbeanstalk:application"
    name      = "Application Healthcheck URL"
    value     = "/"
  }

  version_label = aws_elastic_beanstalk_application_version.sample_version.id

  depends_on = [
    aws_elastic_beanstalk_application_version.sample_version,
    aws_iam_instance_profile.eb_profile,
    aws_iam_role.eb_service_role,
    aws_iam_role.eb_instance_role
  ]

  tags = {
    Name        = var.environment_name
    Environment = "Production"
  }
}

# Supporting Resources

# Security Group
resource "aws_security_group" "eb_sg" {
  name_prefix = "${var.environment_name}-sg"
  vpc_id      = data.aws_vpc.default.id

  ingress {
    description = "HTTP"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "SSH"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "${var.environment_name}-sg"
  }
}

# IAM Roles
resource "aws_iam_role" "eb_service_role" {
  name = "${var.application_name}-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_service_policy" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

resource "aws_iam_role" "eb_instance_role" {
  name = "${var.application_name}-instance-role"

  assume_role_policy = jsonencode({
