  name = var.app_name

  tags = {
    Name = var.app_name
  }
}

# Go Platform Solution Stack ARN (Amazon Linux 2 with Go 1.21)
resource "aws_elastic_beanstalk_application_version" "go_app_version" {
  name        = "v1.0.0"
  application = aws_elastic_beanstalk_application.go_app.name
  bucket      = aws_s3_bucket.eb_app_bucket.bucket
  key         = "go-app-v1.0.0.zip"
  # Upload your Go app zip file to this S3 location

  tags = {
    Name = "go-app-v1.0.0"
  }
}

# Elastic Beanstalk Environment
resource "aws_elastic_beanstalk_environment" "go_env" {
  name                = var.env_name
  application         = aws_elastic_beanstalk_application.go_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.5.5 running Go 1.21" # Latest Go platform

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = data.aws_vpc.default.id
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "Subnets"
    value     = join(",", data.aws_subnets.default.ids)
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "ELBSubnets"
    value     = join(",", data.aws_subnets.default.ids)
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "AssocPublicIp"
    value     = "false"
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service_role.name
  }

  setting {
    namespace = "aws:elb:loadbalancer"
    name      = "SecurityGroups"
    value     = aws_security_group.eb_sg.id
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "PORT"
    value     = "8080"
  }

  setting {
    namespace = "aws:elasticbeanstalk:container:go"
    name      = "ApplicationPort"
    value     = "8080"
  }

  # Deploy the application version
  version_label = aws_elastic_beanstalk_application_version.go_app_version.name

  tags = {
    Name = var.env_name
  }
}

# Output
output "eb_environment_url" {
  description = "URL of the Elastic Beanstalk environment"
  value       = "http://${aws_elastic_beanstalk_environment.go_env.cname}"
}

output "s3_bucket_name" {
  description = "S3 bucket name for application versions"
  value       = aws_s3_bucket.eb_app_bucket.bucket
}
```

**Usage Notes:**
1. Deploy your Go application as a `go-app-v1.0.0.zip` to the S3 bucket created
2. Configure your Go app to listen on port `8080` (EB Go container default)
3. Run `terraform init`, `terraform plan`, `terraform apply`
4. Access your app at the output `eb_environment_url`
5. Update app versions by uploading new zips to S3 and creating new `aws_elastic_beanstalk_application_version` resources

