  bucket = "my-eb-app-source-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_versioning" "eb_source_versioning" {
  bucket = aws_s3_bucket.eb_source.id
  versioning_configuration {
    status = "Enabled"
  }
}

# IAM role for Elastic Beanstalk service
resource "aws_iam_role" "eb_service_role" {
  name = "aws-elasticbeanstalk-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_service_policy" {
  role       = aws_iam_role.eb_service_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkService"
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "app" {
  name = "my-sample-app"
}

# Application version lifecycle configuration
resource "aws_elastic_beanstalk_application_version_lifecycle" "app_lifecycle" {
  application = aws_elastic_beanstalk_application.app.name

  max_count_rule {
    enabled = true
    max_count_limit = 20
    delete_source_from_s3 = true
  }

  max_age_rule {
    enabled = true
    max_age_limit = 180
    delete_source_from_s3 = true
  }
}

# Sample application version (upload a zip file to S3)
resource "aws_s3_object" "app_version" {
  bucket = aws_s3_bucket.eb_source.id
  key    = "app-v1.0.zip"
  source = "sample-app.zip"  # Replace with path to your application zip file
  etag   = filemd5("sample-app.zip")
}

resource "aws_elastic_beanstalk_application_version" "default" {
  name   = "v1.0"
  application = aws_elastic_beanstalk_application.app.name
  bucket = aws_s3_bucket.eb_source.id
  key    = aws_s3_object.app_version.key

  depends_on = [
    aws_elastic_beanstalk_application_version_lifecycle.app_lifecycle,
    aws_s3_object.app_version
  ]
}

# Default environment (optional - for complete setup)
resource "aws_iam_role" "eb_instance_role" {
  name = "aws-elasticbeanstalk-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eb_worker_policy" {
  role       = aws_iam_role.eb_instance_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWorker"
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "aws-elasticbeanstalk-ec2-role"
  role = aws_iam_role.eb_instance_role.name
}

resource "aws_elastic_beanstalk_environment" "env" {
  name                = "my-sample-env"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.1.5 running Corretto 17"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_service_role.name
  }

  version_label = aws_elastic_beanstalk_application_version.default.name

  depends_on = [aws_elastic_beanstalk_application_version.default]
}
```

**Note:** Replace `"sample-app.zip"` with the actual path to your application source bundle ZIP file. The lifecycle policy will automatically manage application versions by deleting old versions from S3 after 180 days or when exceeding 20 versions total.

