}

# Additional policy for GitHub source access and S3 logs/cache
resource "aws_iam_policy" "codebuild_extra" {
  name = "codebuild-example-extra-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
