        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = "codebuild:BatchGetBuilds"
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_extra" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_extra.arn
}

# S3 bucket for cache (CodeBuild cache requires an S3 bucket)
resource "aws_s3_bucket" "codebuild_cache" {
  bucket = "my-codebuild-cache-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_versioning" "codebuild_cache" {
  bucket = aws_s3_bucket.codebuild_cache.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with GitHub source, env vars, and cache"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = "your-github-token-here" # Replace with actual token or use secrets manager
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "APP_NAME"
      value = "my-app"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "ENVIRONMENT"
      value = "staging"
      type  = "PLAINTEXT"
    }
  }

  source {
    type     = "GITHUB"
    location = "https://github.com/yourusername/your-repo.git" # Replace with your GitHub repo

    git_clone_depth = 1
  }

  cache {
    type  = "S3"
    location = aws_s3_bucket.codebuild_cache.bucket
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-project"
      stream_name = "example-stream"
    }
  }

  tags = {
    Environment = "dev"
    Project     = "example"
  }
}

