}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-example-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM role policy attachment for CodeBuild service role
resource "aws_iam_role_policy_attachment" "codebuild_basic" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminPolicy"  # Use managed policy or create custom
}

# Additional policy for S3 access (artifacts)
resource "aws_iam_policy" "codebuild_s3_policy" {
  name = "codebuild-s3-artifacts-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = "arn:aws:s3:::codebuild-artifacts-*/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:CreateBucket"
        ]
        Resource = "arn:aws:s3:::codebuild-artifacts-*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_s3_policy.arn
}

# S3 bucket for artifacts
resource "aws_s3_bucket" "codebuild_artifacts" {
  bucket = "codebuild-artifacts-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_ownership_controls" "codebuild_artifacts" {
  bucket = aws_s3_bucket.codebuild_artifacts.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "codebuild_artifacts" {
  depends_on = [aws_s3_bucket_ownership_controls.codebuild_artifacts]
  bucket     = aws_s3_bucket.codebuild_artifacts.id
  acl        = "private"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# CodeBuild Project
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with GitHub source"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    name = "example-artifacts"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    namespace_type = "NONE"
    packaging = "ZIP"
  }

  cache {
    type  = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
  }

  source {
    type                = "GITHUB"
    location            = "https://github.com/example-user/example-repo.git"
    git_clone_depth     = 1
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = "your-github-token-here"  # Replace with actual token or use Secrets Manager
      type  = "PLAINTEXT"
    }
  }

  source_version = "master"

  tags = {
    Name = "example-codebuild-project"
  }
}

