resource "aws_codebuild_project" "example" {
  name          = "example-project"
  description   = "Example CodeBuild project with GitHub source"
  service_role  = aws_iam_role.codebuild_role.arn

  source {
    type     = "GITHUB"
    location = "https://github.com/yourusername/yourrepo.git"

    git_clone_depth = 1
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = "your-github-token-here"  # Use secrets manager in production
      type  = "PLAINTEXT"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "example-project-log-stream"
    }

    s3_logs {
      status   = "DISABLED"
      # Uncomment and configure if S3 logs needed
      # s3_bucket_name = "your-log-bucket"
      # s3_object_prefix = "codebuild/"
    }
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type  = "NO_CACHE"
  }

  # Example buildspec (inline)
  buildspec = yamlencode({
    version = "0.2"
    phases = {
      install = {
        commands = ["echo 'Installing dependencies...'"]
      }
      build = {
        commands = ["echo 'Building...'"]
      }
    }
  })

  tags = {
    Environment = "example"
  }
}

