# CodeBuild project
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with batch configuration"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false
  }

  source {
    type      = "NO_SOURCE"
    buildspec = <<-EOF
version: 0.2

phases:
  pre_build:
    commands:
      - echo Logging in to Amazon ECR...
      - aws --version
  build:
    commands:
      - echo Build started...
  post_build:
    commands:
      - echo Build completed...
EOF
  }

  # Batch configuration
  build_batch_config {
    service_role = aws_iam_role.codebuild_role.arn

    batch_timeout_in_minutes = 60

    combine_builds {
      restrictions {
        max_commits       = 20
        max_agent_env_vars = 20
        max_agent_vars     = 20
        max_artifacts     = 20
        max_files         = 10000
        max_report_artifact_size_in_mib = 100
      }
    }
  }
}

# Output the project ARN
output "codebuild_project_arn" {
  value = aws_codebuild_project.example.arn
}
