# CodeBuild project with secondary sources and artifacts
resource "aws_codebuild_project" "example" {
  name          = "example-codebuild-project"
  description   = "Example CodeBuild project with secondary sources and artifacts"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type                   = "S3"
    name                   = "primary-artifact"
    location               = aws_s3_bucket.primary_source.bucket
    namespace_type         = "NONE"
    packaging              = "ZIP"
    override_artifact_name = true
  }

  secondary_artifacts {
    name                   = "secondary-artifact"
    type                   = "S3"
    location               = aws_s3_bucket.secondary_source.bucket
    namespace_type         = "NONE"
    packaging              = "ZIP"
    override_artifact_name = true
  }

  source {
    type     = "S3"
    location = aws_s3_bucket.primary_source.bucket
    buildspec = "buildspec.yml"
  }

  secondary_sources {
    source_identifier = "secondary-s3-source"
    type              = "S3"
    location          = aws_s3_bucket.secondary_source.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "ENV_VAR1"
      value = "example-value-1"
    }

    environment_variable {
      name  = "ENV_VAR2"
      value = "example-value-2"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "SECRET_VAR"
      value = "secret-example"
      type  = "SECRETS_MANAGER"
      # Assumes a secret exists in Secrets Manager with this ARN
      # resource = "arn:aws:secretsmanager:region:account:secret:secret-name-xyz"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-project"
      stream_name = "example-stream"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.primary_source.bucket}/logs"
    }
  }

  tags = {
    Environment = "example"
  }
}

