# Intent
resource "aws_lex_bot_intent" "order_food_intent" {
  name                        = "OrderFoodIntent"
  description                 = "Intent for ordering food"
  fulfillment_activity {
    type = "ReturnParameters"
  }
}

# Slot Types
resource "aws_lex_bot_slot_type" "food_type" {
  name         = "FoodType"
  description  = "Type of food"
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    name  = "Pizza"
    synonyms = ["pizza", "pie"]
  }
  enumeration_value {
    name  = "Burger"
    synonyms = ["burger", "hamburger"]
  }
  enumeration_value {
    name  = "Salad"
    synonyms = ["salad", "greens"]
  }
}

resource "aws_lex_bot_slot_type" "size_type" {
  name         = "SizeType"
  description  = "Size of the order"
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    name  = "Small"
    synonyms = ["small", "s"]
  }
  enumeration_value {
    name  = "Medium"
    synonyms = ["medium", "m"]
  }
  enumeration_value {
    name  = "Large"
    synonyms = ["large", "l"]
  }
}

# Slots
resource "aws_lex_bot_slot" "food_slot" {
  name                  = "Food"
  slot_type             = aws_lex_bot_slot_type.food_type.name
  slot_constraint       = "Required"
  priority              = 1
  message_selection_strategy = "PriceLowest"

  value_elicitation_prompt {
    messages {
      content_type = "PlainText"
      content      = "What food would you like to order?"
    }
  }
}

resource "aws_lex_bot_slot" "size_slot" {
  name                  = "Size"
  slot_type             = aws_lex_bot_slot_type.size_type.name
  slot_constraint       = "Required"
  priority              = 2
  message_selection_strategy = "PriceLowest"

  value_elicitation_prompt {
    messages {
      content_type = "PlainText"
      content      = "What size would you like?"
    }
  }
}

resource "aws_lex_bot_slot" "quantity_slot" {
  name                  = "Quantity"
  slot_type             = "AMAZON.NUMBER"
  slot_constraint       = "Optional"
  priority              = 3

  value_elicitation_prompt {
    messages {
      content_type = "PlainText"
      content      = "How many would you like?"
    }
  }
}

