terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Lex Bot IAM Role
resource "aws_iam_role" "lex_bot_role" {
  name = "LexBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexFullAccess"
}

# Intent
resource "aws_lex_bot_intent" "order_food_intent" {
  name                        = "OrderFoodIntent"
  description                 = "Intent for ordering food"
  fulfillment_activity {
    type = "ReturnParameters"
  }
}

# Slot Types
resource "aws_lex_bot_slot_type" "food_type" {
  name         = "FoodType"
  description  = "Type of food"
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    name  = "Pizza"
    synonyms = ["pizza", "pie"]
  }
  enumeration_value {
    name  = "Burger"
    synonyms = ["burger", "hamburger"]
  }
  enumeration_value {
    name  = "Salad"
    synonyms = ["salad", "greens"]
  }
}

resource "aws_lex_bot_slot_type" "size_type" {
  name         = "SizeType"
  description  = "Size of the order"
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    name  = "Small"
    synonyms = ["small", "s"]
  }
  enumeration_value {
    name  = "Medium"
    synonyms = ["medium", "m"]
  }
  enumeration_value {
    name  = "Large"
    synonyms = ["large", "l"]
  }
}

# Slots
resource "aws_lex_bot_slot" "food_slot" {
  name                  = "Food"
  slot_type             = aws_lex_bot_slot_type.food_type.name
  slot_constraint       = "Required"
  priority              = 1
  message_selection_strategy = "PriceLowest"

  value_elicitation_prompt {
    messages {
      content_type = "PlainText"
      content      = "What food would you like to order?"
    }
  }
}

resource "aws_lex_bot_slot" "size_slot" {
  name                  = "Size"
  slot_type             = aws_lex_bot_slot_type.size_type.name
  slot_constraint       = "Required"
  priority              = 2
  message_selection_strategy = "PriceLowest"

  value_elicitation_prompt {
    messages {
      content_type = "PlainText"
      content      = "What size would you like?"
    }
  }
}

resource "aws_lex_bot_slot" "quantity_slot" {
  name                  = "Quantity"
  slot_type             = "AMAZON.NUMBER"
  slot_constraint       = "Optional"
  priority              = 3

  value_elicitation_prompt {
    messages {
      content_type = "PlainText"
      content      = "How many would you like?"
    }
  }
}

# Lex Bot Version
resource "aws_lex_bot_version" "order_food_bot" {
  name           = "OrderFoodBot"
  bot_locale_name = "en_US"

  intent {
    intent_name    = aws_lex_bot_intent.order_food_intent.name
    intent_priority = 1
  }

  slot {
    name             = aws_lex_bot_slot.food_slot.name
    slot_constraint  = aws_lex_bot_slot.food_slot.slot_constraint
    slot_type        = aws_lex_bot_slot.food_slot.slot_type
    value_elicitation_prompt {
      messages {
        content_type = "PlainText"
        content      = aws_lex_bot_slot.food_slot.value_elicitation_prompt[0].messages[0].content
      }
    }
  }

  slot {
    name             = aws_lex_bot_slot.size_slot.name
    slot_constraint  = aws_lex_bot_slot.size_slot.slot_constraint
    slot_type        = aws_lex_bot_slot.size_slot.slot_type
    value_elicitation_prompt {
      messages {
        content_type = "PlainText"
        content      = aws_lex_bot_slot.size_slot.value_elicitation_prompt[0].messages[0].content
      }
    }
  }

  slot {
    name             = aws_lex_bot_slot.quantity_slot.name
    slot_constraint  = aws_lex_bot_slot.quantity_slot.slot_constraint
    slot_type        = aws_lex_bot_slot.quantity_slot.slot_type
    value_elicitation_prompt {
      messages {
        content_type = "PlainText"
        content      = aws_lex_bot_slot.quantity_slot.value_elicitation_prompt[0].messages[0].content
      }
    }
  }
}

# Lex Bot Alias
resource "aws_lex_bot_alias" "order_food_bot_alias" {
  name                = "Prod"
  bot_version         = aws_lex_bot_version.order_food_bot.version
  bot_name            = aws_lex_bot_version.order_food_bot.name
  bot_locale_name     = "en_US"

  conversation_log_configuration {
    log_group_name = aws_cloudwatch_log_group.lex_bot_logs.name
  }
}

# CloudWatch Log Group for Lex
resource "aws_cloudwatch_log_group" "lex_bot_logs" {
  name              = "/aws/lex/order-food-bot"
  retention_in_days = 14
}

# Lex Bot Policy for CloudWatch Logs
resource "aws_iam_role_policy" "lex_cloudwatch_policy" {
  name = "LexCloudWatchPolicy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = aws_cloudwatch_log_group.lex_bot_logs.arn
      }
    ]
  })
}
