      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Lex Bot for Pizza Ordering
resource "aws_lex_bot" "pizza_ordering_bot" {
  name                               = "PizzaOrderingBot"
  description                        = "Lex bot for ordering pizzas"
  abort_statement {
    message {
      content    = "Sorry, I could not process your request. Goodbye!"
      content_type = "PlainText"
    }
  }
  create_version                    = true
  idle_session_ttl_in_seconds       = 300
  child_directed                    = false

  locale_configuration {
    locale               = "en_US"
    description          = "English (US) locale for pizza ordering"
    voice_settings {
      voice_id = "Joanna"
    }
    nlu_confidence_threshold = 0.25

    intent {
      intent_name      = "OrderPizzaIntent"
      intent_priority  = 1
    }
  }

  voice_id = "Joanna"

  # Conclusion statement (played when the intent is fulfilled)
  conclusion_statement {
    message {
      content    = "Great! Your pizza order has been placed successfully. It will be delivered shortly. Thank you for choosing Pizza Palace!"
      content_type = "PlainText"
    }
  }
}

# Custom vocabulary (optional but recommended for pizza ordering)
resource "aws_lex_bot_voice_settings" "pizza_bot_voice" {
  bot_id = aws_lex_bot.pizza_ordering_bot.id
  locale_id = "en_US"

  voice_settings {
    voice_id = "Joanna"
    status   = "InService"
  }
}

# IAM role for Lex bot (required)
resource "aws_iam_role" "lex_bot_role" {
  name = "LexPizzaBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_basic_execution" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Output the bot ID
output "lex_bot_id" {
  value = aws_lex_bot.pizza_ordering_bot.id
}

output "lex_bot_arn" {
  value = aws_lex_bot.pizza_ordering_bot.arn
}

