provider "aws" {
  region = "us-east-1"
}

# IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "lex-bot-trip-booking-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "lex-bot-trip-booking-policy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lex Bot for Trip Booking
resource "aws_lex_bot" "trip_booking_bot" {
  name                               = "TripBookingBot"
  description                        = "Bot for booking trips including destination, dates, and passengers"
  role_arn                           = aws_iam_role.lex_bot_role.arn
  process_behavior                   = "BUILD"
  idle_session_ttl_in_seconds        = 300
  child_directed                     = false
  detect_sentiment                   = false

  abort_statement {
    message {
      content    = "Sorry, I couldn't process your request. Please try again."
      content_type = "PlainText"
    }
  }

  voice_id = "Joanna"

  intent {
    name = "BookTrip"
  }
}

# Lex Bot Version
resource "aws_lex_bot_version" "trip_booking_bot_version" {
  name          = aws_lex_bot.trip_booking_bot.name
  bot_version   = "1"
  checksum      = aws_lex_bot.trip_booking_bot.checksum

  depends_on = [aws_lex_bot.trip_booking_bot]
}

# Lex Bot Alias
resource "aws_lex_bot_alias" "trip_booking_bot_alias" {
  name                     = "Prod"
  bot_name                 = aws_lex_bot.trip_booking_bot.name
  bot_version              = aws_lex_bot_version.trip_booking_bot_version.bot_version
  description              = "Production alias for trip booking bot"
  conversation_logs {
    log_settings {
      destination              = aws_cloudwatch_log_group.lex_bot_log_group.name
      kms_key_arn              = null
      log_level                = "INFO"
    }
  }
}

# CloudWatch Log Group for Lex
resource "aws_cloudwatch_log_group" "lex_bot_log_group" {
  name              = "/aws/lex/trip-booking-bot"
  retention_in_days = 7
}

# Lex Intent - BookTrip
resource "aws_lex_intent" "book_trip" {
  name                               = "BookTrip"
  description                        = "Intent to book a trip"

  fulfillment_activity {
    type = "ReturnIntent"
    fulfillment_activity {
      code_hook {
        message_version = "1.0"
        uri             = "arn:aws:lambda:us-east-1:123456789012:function:TripBookingHandler"
      }
    }
  }

  sample_utterances {
    utterance = "I want to book a trip"
  }
  sample_utterances {
    utterance = "book a vacation"
  }
  sample_utterances {
    utterance = "plan a trip"
  }

  slot {
    name           = "Destination"
    slot_constraint = "Required"
    slot_type      = "AMAZON_CITY"
    priority       = 1
    message {
      content      = "Where would you like to travel?"
      content_type = "PlainText"
    }
    response_card {
      title = "Select Destination"
      content_type = "application/vnd.amazonaws.card.generic"
    }
  }

  slot {
    name           = "DepartureDate"
    slot_constraint = "Required"
    slot_type      = "AMAZON_DATE"
    priority       = 2
    message {
      content      = "When do you want to depart?"
      content_type = "PlainText"
    }
  }

  slot {
    name           = "ReturnDate"
    slot_constraint = "Required"
    slot_type      = "AMAZON_DATE"
    priority       = 3
    message {
      content      = "When do you want to return?"
      content_type = "PlainText"
    }
  }

  slot {
    name           = "NumberOfPeople"
    slot_constraint = "Required"
    slot_type      = "AMAZON_NUMBER"
    priority       = 4
    message {
      content      = "How many people are traveling?"
      content_type = "PlainText"
    }
    value_elicitation_prompt {
      message {
        content      = "How many passengers?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    message {
      content      = "You want to book a trip to {Destination} from {DepartureDate} to {ReturnDate} for {NumberOfPeople} people. Is that correct?"
      content_type = "PlainText"
    }
    max_attempts = 3
  }

  rejection_statement {
    message {
      content      = "I don't understand. Please try again."
      content_type = "PlainText"
    }
  }

  conclusion_statement {
    message {
      content      = "Your trip has been booked! Reference number is TRIP-{DepartureDate}. Have a great trip!"
      content_type = "PlainText"
    }
  }

  dialog_code_hook {
    message_version = "1.0"
    uri             = "arn:aws:lambda:us-east-1:123456789012:function:TripBookingDialogHandler"
  }

  depends_on = [aws_lex_bot.trip_booking_bot]
}

# Lex Slot Type for Trip Preferences (custom)
resource "aws_lex_slot_type" "trip_preferences" {
  name          = "TripPreferences"
  description   = "Preferences for trip booking"
  value_selection_strategy = "ORIGINAL_VALUE"
  enumeration_value {
    name  = "beach"
    synonyms = ["beach vacation", "seaside", "ocean"]
  }
  enumeration_value {
    name  = "city"
    synonyms = ["urban", "city break", "metropolis"]
  }
  enumeration_value {
    name  = "adventure"
    synonyms = ["adventure trip", "outdoor", "extreme"]
  }
  enumeration_value {
    name  = "business"
    synonyms = ["business trip", "work", "conference"]
  }
}

