# Sample slot types for pizza ordering
resource "aws_lex_slot_type" "pizza_size" {
  name         = "PizzaSize"
  description  = "Pizza size options"
  value_selection_strategy = "RESTRICTED"

  enumeration_value {
    name  = "Small"
    synonyms = ["small", "s"]
  }

  enumeration_value {
    name  = "Medium"
    synonyms = ["medium", "m"]
  }

  enumeration_value {
    name  = "Large"
    synonyms = ["large", "l"]
  }

  enumeration_value {
    name  = "Extra Large"
    synonyms = ["extra large", "xl", "x-large"]
  }
}

resource "aws_lex_slot_type" "pizza_topping" {
  name         = "PizzaTopping"
  description  = "Pizza topping options"
  value_selection_strategy = "ALLOW_CUSTOM"

  enumeration_value {
    name  = "Pepperoni"
    synonyms = ["pepperoni", "pep"]
  }

  enumeration_value {
    name  = "Cheese"
    synonyms = ["cheese", "plain"]
  }

  enumeration_value {
    name  = "Mushroom"
    synonyms = ["mushroom", "mushrooms"]
  }

  enumeration_value {
    name  = "Sausage"
    synonyms = ["sausage", "italian sausage"]
  }
}

resource "aws_lex_slot_type" "pizza_quantity" {
  name         = "PizzaQuantity"
  description  = "Number of pizzas"
  value_selection_strategy = "VALIDATE"

  enumeration_value {
    name  = "1"
    synonyms = ["one", "single"]
  }

  enumeration_value {
    name  = "2"
    synonyms = ["two", "double"]
  }

  enumeration_value {
    name  = "3"
    synonyms = ["three"]
  }
}

# Intent 1: OrderPizza
resource "aws_lex_intent" "order_pizza" {
  name                               = "OrderPizza"
  description                        = "Order a pizza"
  confirmation_required              = true
  create_version                     = true
  fulfillment_activity {
    type = "ReturnIntent"
    voice_title = "OrderPizzaFulfillment"
  }

  sample_utterances {
    utterance = "I want to order a pizza"
  }

  sample_utterances {
    utterance = "Order pizza"
  }

  slot {
    name           = "Size"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_size.name
    priority       = 1
    message {
      content_type = "PlainText"
      content      = "What size pizza would you like?"
    }
    response_card {
      title       = "Pizza Size"
      content_type = "application/vnd.amazonaws.card.generic"
    }
  }

  slot {
    name           = "Topping"
    slot_constraint = "Required"
    slot_type      = aws_lex_slot_type.pizza_topping.name
    priority       = 2
    message {
      content_type = "PlainText"
      content      = "What toppings would you like?"
    }
  }

  slot {
    name           = "Quantity"
    slot_constraint = "Optional"
    slot_type      = aws_lex_slot_type.pizza_quantity.name
    priority       = 3
  }
}

# Intent 2: CancelOrder
resource "aws_lex_intent" "cancel_order" {
  name                               = "CancelOrder"
  description                        = "Cancel pizza order"
  confirmation_required              = false
  create_version                     = true
  fulfillment_activity {
    type = "ReturnIntent"
    voice_title = "CancelOrderFulfillment"
  }

