  description                        = "Check status of pizza order"
  confirmation_required              = false
  create_version                     = true
  fulfillment_activity {
    type = "ReturnIntent"
    voice_title = "CheckOrderStatusFulfillment"
  }

  sample_utterances {
    utterance = "where is my pizza"
  }

  sample_utterances {
    utterance = "order status"
  }
}

# Intent 4: ChangeOrder
resource "aws_lex_intent" "change_order" {
  name                               = "ChangeOrder"
  description                        = "Modify existing pizza order"
  confirmation_required              = true
  create_version                     = true
  fulfillment_activity {
    type = "ReturnIntent"
    voice_title = "ChangeOrderFulfillment"
  }

  sample_utterances {
    utterance = "change my pizza order"
  }

  sample_utterances {
    utterance = "make it large instead"
  }

  slot {
    name           = "Size"
    slot_constraint = "Optional"
    slot_type      = aws_lex_slot_type.pizza_size.name
  }
}

# Intent 5: MenuInfo
resource "aws_lex_intent" "menu_info" {
  name                               = "MenuInfo"
  description                        = "Get pizza menu information"
  confirmation_required              = false
  create_version                     = true
  fulfillment_activity {
    type = "ReturnIntent"
    voice_title = "MenuInfoFulfillment"
  }

  sample_utterances {
    utterance = "what do you have"
  }

  sample_utterances {
    utterance = "show me the menu"
  }
}

# Lex Bot
resource "aws_lex_bot" "pizza_order_bot" {
  name                        = "PizzaOrderBot"
  description                 = "Bot for ordering pizzas"
  locale                      = "en_US"
  voice_id                    = "Joanna"
  create_version              = true
  process_behavior            = "BUILD"
  idle_session_ttl_in_seconds = 300

  intent {
    intent_name    = aws_lex_intent.order_pizza.name
    intent_version = aws_lex_intent.order_pizza.version
  }

  intent {
    intent_name    = aws_lex_intent.cancel_order.name
    intent_version = aws_lex_intent.cancel_order.version
  }

  intent {
    intent_name    = aws_lex_intent.check_order_status.name
    intent_version = aws_lex_intent.check_order_status.version
  }

  intent {
    intent_name    = aws_lex_intent.change_order.name
    intent_version = aws_lex_intent.change_order.version
  }

  intent {
    intent_name    = aws_lex_intent.menu_info.name
    intent_version = aws_lex_intent.menu_info.version
  }

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Goodbye."
    }
  }

  depends_on = [
    aws_lex_intent.order_pizza,
    aws_lex_intent.cancel_order,
    aws_lex_intent.check_order_status,
    aws_lex_intent.change_order,
    aws_lex_intent.menu_info
  ]
}

