# Sample slot types for pizza ordering
resource "aws_lex_slot_type" "pizza_size" {
  name         = "PizzaSize"
  description  = "Pizza size options"
  value_selection_strategy = "RESTRICTED"

  enumeration_value {
    name  = "Small"
    synonyms = ["small", "s"]
  }

  enumeration_value {
    name  = "Medium"
    synonyms = ["medium", "m"]
  }

  enumeration_value {
    name  = "Large"
    synonyms = ["large", "l"]
  }

  enumeration_value {
    name  = "Extra Large"
    synonyms = ["extra large", "xl", "x-large"]
  }
}

resource "aws_lex_slot_type" "pizza_topping" {
  name         = "PizzaTopping"
  description  = "Pizza topping options"
  value_selection_strategy = "ALLOW_CUSTOM"

  enumeration_value {
    name  = "Pepperoni"
    synonyms = ["pepperoni", "pep"]
  }

  enumeration_value {
    name  = "Cheese"
    synonyms = ["cheese", "plain"]
  }

  enumeration_value {
