terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# Lex Bot for kids ordering pizzas
resource "aws_lex_bot" "pizza_order_kids" {
  name                               = "PizzaOrderKidsBot"
  description                        = "Fun pizza ordering bot for kids!"
  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Oops! Something went wrong. Let's try again! 🍕"
    }
  }
  create_version                     = true
  idle_session_ttl_in_seconds        = 300
  child_directed                     = true  # Important for kids' bot

  locale_configuration {
    locale                = "en_US"
    description           = "English (US) for kids"
    nlu_confidence_threshold = 0.75

    voice_settings {
      voice_id = "Joanna"  # Friendly voice
    }
  }

  # Sample intents for pizza ordering
  intent {
    name = "OrderPizza"
  }

  intent {
    name = "PizzaSize"
  }

  intent {
    name = "PizzaToppings"
  }

  intent {
    name = "ConfirmOrder"
  }

  intent {
    name = "CancelOrder"
  }
}

# Sample Lex Bot Version
resource "aws_lex_bot_version" "pizza_order_kids_version" {
  bot_name       = aws_lex_bot.pizza_order_kids.name
  bot_version    = "1"
  locale         = "en_US"

  depends_on = [aws_lex_bot.pizza_order_kids]
}

# Lex Bot Alias for production
resource "aws_lex_bot_alias" "pizza_order_kids_prod" {
  bot_name       = aws_lex_bot.pizza_order_kids.name
  bot_version    = aws_lex_bot_version.pizza_order_kids_version.bot_version
  name           = "Prod"
  description    = "Production alias for kids pizza bot"

  conversation_logs {
    log_settings {
      destination = "CLOUDWATCH_LOGS"
      resource_arn = aws_cloudwatch_log_group.lex_bot.arn
    }
  }
}

# CloudWatch Log Group for Lex conversation logs
resource "aws_cloudwatch_log_group" "lex_bot" {
  name              = "/aws/lex/pizza-order-kids"
  retention_in_days = 7
}

# IAM Role for Lex to write to CloudWatch
resource "aws_iam_role" "lex_cloudwatch_role" {
  name = "LexCloudWatchRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_cloudwatch_policy" {
  role = aws_iam_role.lex_cloudwatch_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = aws_cloudwatch_log_group.lex_bot.arn
      }
    ]
  })
}

