terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Lambda function
resource "aws_iam_role" "lambda_role" {
  name = "lex-pizza-bot-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Lambda execution
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# IAM policy for Lex Bot permissions
resource "aws_iam_role_policy" "lex_policy" {
  name = "lex-pizza-bot-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "lex:PutSession"
        ]
        Effect = "Allow"
        Resource = "*"
      }
    ]
  })
}

# Lambda function for pizza ordering fulfillment
resource "aws_lambda_function" "pizza_fulfillment" {
  filename         = "pizza_fulfillment.zip"
  function_name    = "pizza-order-fulfillment"
  role            = aws_iam_role.lambda_role.arn
  handler         = "pizza_fulfillment.lambda_handler"
  runtime         = "python3.9"
  source_code_hash = filebase64sha256("pizza_fulfillment.zip")

  environment {
    variables = {
      PIZZA_API_ENDPOINT = "https://api.pizza.example.com/order"
    }
  }
}

# Permission for Lex to invoke Lambda
resource "aws_lambda_permission" "lex_invoke" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_fulfillment.function_name
  principal     = "lex.amazonaws.com"
  source_arn    = aws_lex_bot.pizza_bot.arn
}

# Lex Bot - Pizza Ordering Bot
resource "aws_lex_bot" "pizza_bot" {
  name                               = "PizzaOrderBot"
  description                        = "Pizza ordering bot"
  idle_session_ttl_in_seconds        = 300
  child_directed                     = false
  detect_sentiment                   = false
  create_version                     = true

  voice_id = "Joanna"

  intent {
    name = "OrderPizzaIntent"
    fulfillment_activity {
      type = "LambdaFulfillment"
      code_hook {
        message_version = "1.0"
        lambda_function_arn = aws_lambda_function.pizza_fulfillment.arn
      }
    }
    sample_utterances = [
      "I want to order a pizza",
      "Can I get a pizza",
      "Order pizza",
      "I'd like a pizza please"
    ]

    slot {
      name           = "PizzaSize"
      slot_type      = aws_lex_slot_type.pizza_size.name
      slot_constraint = "Required"
      priority       = 1
      message {
        content_type = "PlainText"
        content      = "What size pizza would you like? Small, medium, or large?"
      }
    }

    slot {
      name           = "PizzaToppings"
      slot_type      = aws_lex_slot_type.pizza_toppings.name
      slot_constraint = "Optional"
      priority       = 2
    }

    slot {
      name           = "PizzaQuantity"
      slot_type      = "AMAZON.NUMBER"
      slot_constraint = "Required"
      priority       = 3
      message {
        content_type = "PlainText"
        content      = "How many pizzas would you like?"
      }
    }
  }

  intent {
    name = "CancelOrderIntent"
    fulfillment_activity {
      type = "ReturnParametersAndPrompt"
    }
    sample_utterances = [
      "cancel my order",
      "never mind",
      "cancel order",
      "I changed my mind"
    ]
  }

  intent {
    name = "HelpIntent"
    fulfillment_activity {
      type = "Default"
    }
    sample_utterances = [
      "help",
      "help me",
      "what can you do"
    ]
  }

  locale_configuration {
    locale           = "en_US"
    nlu_confidence_threshold = 0.75
  }
}

# Custom Slot Type - Pizza Sizes
resource "aws_lex_slot_type" "pizza_size" {
  name         = "PizzaSize"
  description  = "Pizza sizes"
  version      = "$LATEST"
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value = "small"
  }
  enumeration_value {
    value = "medium"
  }
  enumeration_value {
    value = "large"
  }
}

# Custom Slot Type - Pizza Toppings
resource "aws_lex_slot_type" "pizza_toppings" {
  name         = "PizzaToppings"
  description  = "Common pizza toppings"
  version      = "$LATEST"
  value_selection_strategy = "ORIGINAL_VALUE"

  enumeration_value {
    value = "pepperoni"
  }
  enumeration_value {
    value = "sausage"
  }
  enumeration_value {
    value = "mushrooms"
  }
  enumeration_value {
    value = "onions"
  }
  enumeration_value {
    value = "bell peppers"
  }
  enumeration_value {
    value = "extra cheese"
  }
}

# Lex Bot Alias
resource "aws_lex_bot_alias" "pizza_bot_alias" {
  name           = "PizzaOrderBotAlias"
  bot_name       = aws_lex_bot.pizza_bot.name
  bot_version    = aws_lex_bot.pizza_bot.version
  description    = "Production alias for pizza ordering bot"
}

