      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Lex bot
resource "aws_iam_role" "lex_bot_role" {
  name = "LexV2BotRoleForChildren"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "LexV2BotPolicyForChildren"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lex V2 Bot for children (simple educational bot)
resource "aws_lexv2models_bot" "children_bot" {
  bot_name               = "ChildrenLearningBot"
  role_arn               = aws_iam_role.lex_bot_role.arn
  data_privacy {
    child_directed = true
  }
  idle_session_ttl_in_seconds = 300
  bot_tags = {
    Environment = "production"
    Purpose     = "children-education"
  }
}

# Bot version
resource "aws_lexv2models_bot_version" "children_bot_version" {
  bot_id     = aws_lexv2models_bot.children_bot.id
  description = "Initial version for children learning bot"
}

# Bot alias (default production alias)
resource "aws_lexv2models_bot_alias" "children_bot_alias" {
  bot_alias_id           = "TstAlias"
  bot_version            = aws_lexv2models_bot_version.children_bot_version.bot_version
  bot_id                 = aws_lexv2models_bot.children_bot.id
  bot_alias_locale_settings {
    locale_id           = "en_US"
    bot_alias_locale_status = "BUILDING"
    bot_version         = aws_lexv2models_bot_version.children_bot_version.bot_version
  }
}

# Example Intent for children bot (colors learning)
resource "aws_lexv2models_intent" "learn_colors" {
  intent_name = "LearnColors"
  description = "Intent for children to learn colors"
  input_contexts {
    name = "ColorLearningContext"
  }
  sample_utterances {
    utterance = "what color is the sky"
  }
  sample_utterances {
    utterance = "teach me colors"
  }
  sample_utterances {
    utterance = "what color is apple"
  }
  dialog_code_hook {
    enabled = false
  }
  closing_response {
    message_groups {
      message = "Great job learning colors! The sky is blue and apples can be red or green! 🌈"
    }
  }
}

# Bot locale for English US with the intent
resource "aws_lexv2models_bot_locale" "en_us" {
  bot_id                      = aws_lexv2models_bot.children_bot.id
  bot_version                 = aws_lexv2models_bot_version.children_bot_version.bot_version
  locale_name                 = "en_US"
  description                 = "English locale for children bot"
  nlu_confidence_threshold    = 0.70
  voice_settings {
    voice_id = "Joanna"
  }

  intent {
    intent_id   = aws_lexv2models_intent.learn_colors.id
    priority    = 1
  }
}

