# Example AWS Connect Instance (prerequisite)
resource "aws_connect_instance" "example" {
  identity_management_type = "SAML"
  inbound_calls_enabled    = true
  instance_alias           = "example-instance"
}

# SAML Provider for AWS Connect (prerequisite for SAML integration)
resource "aws_iam_saml_provider" "example" {
  name                   = "example-saml-provider"
  saml_metadata_document = file("saml-metadata.xml") # Replace with your SAML metadata file path
}

