provider "aws" {
  region = "us-east-1"
}

# Kinesis Stream for input
resource "aws_kinesis_stream" "analytics_input_stream" {
  name             = "analytics-input-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes",
  ]

  tags = {
    Name = "AnalyticsInputStream"
  }
}

# IAM Role for Kinesis Analytics to read from the input stream
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for reading from Kinesis stream
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.analytics_input_stream.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_caller_identity.current.account_id}:log-group:/aws/kinesis-analytics/*"
      }
    ]
  })
}

# Data source for AWS caller identity (used in policy)
data "aws_caller_identity" "current" {}

# Kinesis Analytics Application
resource "aws_kinesisanalytics_application" "example" {
  name = "example-kinesis-analytics-app"

  inputs {
    name_prefix = "test_prefix"

    kinesis_firehose_input {
      resource_arn = aws_kinesis_stream.analytics_input_stream.arn
    }

    parallelism {
      count = 1
    }

    processing_configuration {
      zeppelin_application_configuration {
        # Basic SQL application - customize as needed
        monitoring_configuration {
          log_level = "INFO"
          metrics_level = "APPLICATION"
        }

        custom_artifacts_configuration {
          s3_content_location {
            bucket_arn = "arn:aws:s3:::your-bucket-name" # Replace with your S3 bucket
            file_key   = "path/to/your/application.zip"  # Replace with your application zip
          }
          artifact_type = "UDF"
        }

        # Example SQL query - customize for your use case
        sql_application_configuration {
          input_stream_descriptions {
            stream_arn = aws_kinesis_stream.analytics_input_stream.arn
            input_id   = "1.1"
          }

          # Simple output to a Kinesis stream (optional)
          output_stream_descriptions {
            stream_arn = aws_kinesis_stream.analytics_input_stream.arn
            output_id  = "1.1"
          }
        }
      }
    }
  }

  tags = {
    Name = "ExampleKinesisAnalyticsApp"
  }

  depends_on = [aws_iam_role_policy.kinesis_analytics_policy]
}
```

**Note:** This configuration includes a basic SQL Kinesis Analytics V1 application. You must replace the S3 bucket and file path in `custom_artifacts_configuration` with your actual application ZIP file containing the SQL code. For production use, customize the SQL application logic in `sql_application_configuration` and add appropriate output configurations.

