provider "aws" {
  region = "us-east-1"
}

# S3 bucket for Firehose delivery
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-firehose-delivery-bucket-unique"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_versioning" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  rule {
    id     = "firehose-expiration"
    status = "Enabled"

    expiration {
      days = 365
    }

    noncurrent_version_expiration {
      noncurrent_days = 30
    }
  }
}

# IAM role for Firehose to write to S3
resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream with Extended S3 Destination and Dynamic Partitioning
resource "aws_kinesis_firehose_delivery_stream" "extended_s3_stream" {
  name = "my-extended-s3-firehose-stream"

  server_side_encryption {
    type = "AwsKms"
  }

  extended_s3_configuration {
    role_arn                       = aws_iam_role.firehose_role.arn
    bucket_arn                     = aws_s3_bucket.firehose_bucket.arn
    buffering_size                 = 64
    buffering_interval             = 60
    compression_format             = "GZIP"

    # Dynamic Partitioning configuration
    dynamic_partitioning_configuration {
      enable_dynamic_partitioning = true
      retry_duration             = 300
    }

    # Prefix and error prefix with partitioning keys
    prefix = "year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    error_prefix = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"

    # CloudWatch logging
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesis/firehose/my-extended-s3-firehose-stream"
      log_stream_name = "S3Delivery"
    }
  }
}

# CloudWatch Log Group for Firehose logging
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesis/firehose/my-extended-s3-firehose-stream"
  retention_in_days = 14
}

# IAM role for CloudWatch logging
resource "aws_iam_role" "firehose_cloudwatch_role" {
  name = "firehose_cloudwatch_logging_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_cloudwatch_policy" {
  name = "firehose_cloudwatch_policy"
  role = aws_iam_role.firehose_cloudwatch_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Attach CloudWatch logging policy to Firehose role
resource "aws_iam_role_policy_attachment" "firehose_cloudwatch_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_role_policy.firehose_cloudwatch_policy.arn
}

