provider "aws" {
  region = "us-east-1"
}

# S3 bucket for Firehose buffering and failed deliveries
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "kinesis-firehose-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Random suffix for bucket name uniqueness
resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Elasticsearch domain (OpenSearch Service)
resource "aws_opensearch_domain" "firehose_es" {
  domain_name    = "firehose-es-domain-${random_string.bucket_suffix.result}"
  engine_version = "OpenSearch_1.3"

  cluster_config {
    instance_type = "t3.small.search"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp2"
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action = "es:*"
        Resource = "arn:aws:es:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:domain/firehose-es-domain-${random_string.bucket_suffix.result}/*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
        }
      }
    ]
  })
}

data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# IAM role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role-${random_string.bucket_suffix.result}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Firehose S3 access
resource "aws_iam_role_policy" "firehose_s3_policy" {
  name = "firehose-s3-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# IAM policy for Firehose OpenSearch access
resource "aws_iam_role_policy" "firehose_es_policy" {
  name = "firehose-es-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = ["es:ESHttpPut", "es:ESHttpPost"]
        Effect   = "Allow"
        Resource = aws_opensearch_domain.firehose_es.arn
      }
    ]
  })
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "elasticsearch_stream" {
  name        = "firehose-to-elasticsearch-${random_string.bucket_suffix.result}"
  destination = "elasticsearch"

  elasticsearch_configuration {
    domain_arn   = aws_opensearch_domain.firehose_es.arn
    role_arn     = aws_iam_role.firehose_role.arn
    index_name   = "firehose-index"
    type_name    = "_doc"
    retry_duration = 300
  }

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "data/"
    error_output_prefix = "errors/"
  }

  server_side_encryption {
    enabled = true
    key_arn = "arn:aws:kms:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:alias/aws/firehose"
  }

  tags = {
    Name = "Firehose to Elasticsearch"
  }

  depends_on = [
    aws_iam_role_policy.firehose_s3_policy,
    aws_iam_role_policy.firehose_es_policy
  ]
}

# Output the Firehose stream ARN and endpoint
output "firehose_stream_arn" {
  value = aws_kinesis_firehose_delivery_stream.elasticsearch_stream.arn
}

output "opensearch_domain_endpoint" {
  value = aws_opensearch_domain.firehose_es.endpoint
}

output "s3_bucket_name" {
  value = aws_s3_bucket.firehose_bucket.id
}
