terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (update region as needed)
provider "aws" {
  region = "us-east-1"
}

# IAM role for Firehose to publish logs to CloudWatch
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# CloudWatch Logs policy attachment
resource "aws_iam_role_policy" "firehose_cloudwatch_policy" {
  name = "firehose-cloudwatch-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# S3 bucket for failed deliveries and backup
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-splunk-backup-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_policy" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.firehose_backup.arn}/*"
      }
    ]
  })
}

# Random suffix for unique bucket name
resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Kinesis Firehose Delivery Stream with Splunk destination
resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  name = "splunk-delivery-stream"

  splunk_destination_configuration {
    splunk_endpoint {
      url = "https://http-inputs-MY_SPLUNK_HEC.splunkcloud.com:8088" # Replace with your Splunk HEC endpoint
    }

    hec_ack_enabled                  = false
    retry_options {
      duration_in_seconds = 300
    }
    s3_backup_mode                   = "FailedDataOnly"
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesis/firehose/splunk-stream"
      log_stream_name = "S3Delivery"
    }
  }

  server_side_encryption {
    key_arn = aws_kms_key.firehose_key.arn
  }

  tags = {
    Name = "SplunkDeliveryStream"
  }
}

# KMS Key for server-side encryption
resource "aws_kms_key" "firehose_key" {
  description             = "KMS key for Firehose encryption"
  deletion_window_in_days = 7
  enable_key_rotation     = true
}

resource "aws_kms_alias" "firehose_key" {
  name          = "alias/firehose-splunk-key"
  target_key_id = aws_kms_key.firehose_key.key_id
}

# IAM policy for Firehose to use KMS
resource "aws_iam_role_policy" "firehose_kms_policy" {
  name = "firehose-kms-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = [aws_kms_key.firehose_key.arn]
      }
    ]
  })
}

# S3 destination configuration for backup
resource "aws_kinesis_firehose_delivery_stream" "splunk_stream" {
  # ... (previous configuration remains the same)

  # Add this block for S3 backup configuration
  extended_s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    buffering_size     = 5
    buffering_interval = 300
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesis/firehose/splunk-stream"
      log_stream_name = "S3BackupDelivery"
    }
  }
}
```

**Important Notes:**
1. Replace `https://http-inputs-MY_SPLUNK_HEC.splunkcloud.com:8088` with your actual Splunk HEC endpoint URL
2. Update the AWS region in the provider block as needed
3. The S3 bucket name is auto-generated with a random suffix for uniqueness
4. Splunk HEC token is passed via environment variables or AWS Secrets Manager in production
5. Enable `hec_ack_enabled = true` if your Splunk instance supports HEC acknowledgements

