    Name = "kinesis-firehose-sg"
  }
}

resource "aws_security_group" "elasticsearch_sg" {
  name_prefix = "elasticsearch-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.kinesis_firehose_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "elasticsearch-sg"
  }
}

# IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "kinesis-firehose-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPost",
          "es:ESHttpPut"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup.arn,
          "${aws_s3_bucket.firehose_backup.arn}/*"
        ]
      }
    ]
  })
}

# S3 Backup Bucket for failed deliveries
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "kinesis-firehose-backup-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Elasticsearch Domain
resource "aws_elasticsearch_domain" "firehose_es" {
  domain_name           = "kinesis-firehose-es"
  elasticsearch_version = "7.10"

  vpc_options {
    subnet_ids         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.elasticsearch_sg.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
    volume_type = "gp3"
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  cluster_config {
    instance_type = "t3.small.elasticsearch"
  }

  tags = {
    Name = "kinesis-firehose-es"
  }

  depends_on = [aws_iam_service_linked_role.elasticsearch]
}

resource "aws_iam_service_linked_role" "elasticsearch" {
  aws_service_name = "es.amazonaws.com"
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "elasticsearch_stream" {
  name        = "kinesis-firehose-to-elasticsearch"
  destination = "elasticsearch"

  vpc_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    subnet_ids         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.kinesis_firehose_sg.id]
  }

  elasticsearch_configuration {
    domain_arn        = aws_elasticsearch_domain.firehose_es.arn
    role_arn          = aws_iam_role.firehose_role.arn
    index_name        = "firehose-index"
    type_name         = "_doc"
    retry_duration    = 300
    buffering_size    = 5
    buffering_interval = 300

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_log.name
      log_stream_name = aws_cloudwatch_log_stream.firehose_log.name
    }
  }

  server_side_encryption {
    key_arn = aws_kms_key.firehose.arn
  }

  backup_mode = "AllData"

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    prefix             = "firehose-backup/"
    buffer_size        = 5
    buffer_interval    = 300
    compression_format = "GZIP"
  }

  tags = {
    Name = "kinesis-firehose-to-elasticsearch"
  }
}

# KMS Key for encryption
resource "aws_kms_key" "firehose" {
  description             = "KMS key for Kinesis Firehose"
  deletion_window_in_days = 7
  enable_key_rotation     = true
}

# CloudWatch Logs for Firehose
