  name              = "/aws/kinesis/firehose/kinesis-firehose-to-elasticsearch"
  retention_in_days = 14
}

resource "aws_cloudwatch_log_stream" "firehose_log" {
  name           = "firehose-log-stream"
  log_group_name = aws_cloudwatch_log_group.firehose_log.name
}

