terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# IAM role for Firehose to assume
resource "aws_iam_role" "firehose_role" {
  name = "firehose-delivery-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Firehose (basic logging permissions - customize as needed)
resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-delivery-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# CloudWatch Log Group for Firehose monitoring
resource "aws_cloudwatch_log_group" "firehose_logs" {
  name              = "/aws/kinesisfirehose/newrelic-firehose"
  retention_in_days = 7
}

# CloudWatch Log Stream
resource "aws_cloudwatch_log_stream" "firehose_log_stream" {
  name           = "S3DeliveryErrors"
  log_group_name = aws_cloudwatch_log_group.firehose_logs.name
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "newrelic_firehose" {
  name = "newrelic-firehose-stream"

  http_endpoint_destination {
    endpoint_configuration {
      url = "https://aws-api.newrelic.com/firehose-v1?api_key=YOUR_NEW_RELIC_LICENSE_KEY&license_key=YOUR_NEW_RELIC_LICENSE_KEY"
      name = "New Relic HTTP Endpoint"
    }

    buffering_hints {
      interval_in_seconds = 60
      size_in_mbs         = 1
    }

    processing_configuration {
      enabled = false
    }

    retry_options {
      duration_in_seconds = 300
    }

    s3_backup_mode = "FailedDataOnly"
  }

  server_side_encryption {
    type = "AwsKms"
  }

  # S3 Backup bucket for failed deliveries
  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_backup.arn
    buffering_size     = 5
    buffering_interval = 300
    compression_format = "GZIP"
  }

  tags = {
    Name = "NewRelicFirehose"
  }
}

# S3 bucket for backup of failed deliveries
resource "aws_s3_bucket" "firehose_backup" {
  bucket = "firehose-newrelic-backup-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.bucket

  rule {
    apply_server_side_encryption_by_default {
      kms_master_key_id = aws_kms_key.firehose_backup.arn
      sse_algorithm     = "aws:kms"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_versioning" "firehose_backup" {
  bucket = aws_s3_bucket.firehose_backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

# KMS Key for S3 encryption
resource "aws_kms_key" "firehose_backup" {
  description             = "KMS key for Firehose backup bucket"
  deletion_window_in_days = 7
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Output the Firehose stream ARN
output "firehose_stream_arn" {
