terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# VPC Configuration
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "kinesis-firehose-vpc"
  }
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "kinesis-firehose-private-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "kinesis-firehose-private-2"
  }
}

# VPC Endpoints for Kinesis Firehose and OpenSearch
resource "aws_vpc_endpoint" "kinesis_firehose" {
  vpc_id            = aws_vpc.main.id
  service_name      = "com.amazonaws.us-east-1.kinesis-firehose"
  vpc_endpoint_type = "Gateway"
  route_table_ids   = [aws_vpc.main.main_route_table_id]
  tags = {
    Name = "kinesis-firehose-endpoint"
  }
}

resource "aws_vpc_endpoint" "es_opensearch" {
  vpc_id              = aws_vpc.main.id
  service_name        = "vpce-2c3ea4d1.us-east-1.es.amazonaws.com" # OpenSearch endpoint service
  vpc_endpoint_type   = "Interface"
  subnet_ids          = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
  security_group_ids  = [aws_security_group.opensearch_sg.id]
  private_dns_enabled = true
  tags = {
    Name = "opensearch-endpoint"
  }
}

# Security Groups
resource "aws_security_group" "firehose_sg" {
  name_prefix = "kinesis-firehose-sg"
  vpc_id      = aws_vpc.main.id

  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "kinesis-firehose-sg"
  }
}

resource "aws_security_group" "opensearch_sg" {
  name_prefix = "opensearch-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.firehose_sg.id]
  }

  tags = {
    Name = "opensearch-sg"
  }
}

# IAM Role for Kinesis Firehose
resource "aws_iam_role" "firehose_role" {
  name = "kinesis-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "kinesis-firehose-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains"
        ]
        Resource = aws_opensearch_domain.main.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# S3 Bucket for buffering and failed deliveries
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "kinesis-firehose-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# OpenSearch Domain
resource "aws_opensearch_domain" "main" {
  domain_name    = "kinesis-firehose-opensearch"
  engine_version = "OpenSearch_2.3"

  cluster_config {
    instance_type          = "t3.small.search"
    instance_count         = 2
    zone_awareness_enabled = true
  }

  vpc_options {
    subnet_ids         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.opensearch_sg.id]
  }

  ebs_options {
    ebs_enabled = true
    volume_type = "gp3"
    volume_size = 10
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  domain_endpoint_options {
    enforce_https       = true
    tls_security_policy = "Policy-Min-TLS-1-2-2019-07"
  }

  tags = {
    Name = "kinesis-firehose-opensearch"
  }
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "main" {
  name        = "kinesis-firehose-opensearch-stream"
  destination = "opensearch"

  vpc_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    subnet_ids         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.firehose_sg.id]
  }

  opensearch_configuration {
    domain_arn        = aws_opensearch_domain.main.arn
    role_arn          = aws_iam_role.firehose_role.arn
    index_name        = "firehose_index"
    type_name         = "_doc"
    buffering_size    = 5
    buffering_interval = 300
    retry_duration    = 300
    s3_backup_mode    = "FailedDataOnly"
  }

  s3_configuration {
    role_arn           = aws_iam_role.firehose_role.arn
    bucket_arn         = aws_s3_bucket.firehose_bucket.arn
    buffering_size     = 10
    buffering_interval = 400
    compression_format = "GZIP"
  }

  server_side_encryption {
    enabled  = true
    key_arn  = "arn:aws:kms:us-east-1:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab"
  }

  tags = {
    Name = "kinesis-firehose-opensearch-stream"
  }
}

# OpenSearch Domain Policy (for Firehose access)
resource "aws_opensearch_domain_policy" "main" {
  domain_name = aws_opensearch_domain.main.domain_name

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_role.arn
        }
        Action   = "es:ESHttp*"
        Resource  = "${aws_opensearch_domain.main.arn}/*"
      }
    ]
  })
}

