      enabled         = true
      log_group_name  = "/aws/kinesis/firehose/my-extended-s3-firehose-stream"
      log_stream_name = "S3Delivery"
    }

    # Processing configuration (optional data transformation)
    processing_configuration {
      enabled = true

      processors {
        type = "Lambda"

        parameters {
          parameter_name  = "LambdaArn"
          parameter_value = "arn:aws:lambda:us-east-1:111122223333:function:my-data-transform-function" # Replace with your Lambda ARN
        }

        parameters {
          parameter_name  = "BufferSize"
          parameter_value = "25"
        }

        parameters {
          parameter_name  = "BufferInterval"
          parameter_value = "900"
        }
      }
    }

    # S3 backup mode
    s3_backup_mode = "AllDocuments"

    # KMS encryption for extended destination
    kms_key_arn = "arn:aws:kms:us-east-1:111122223333:key/1234abcd-12ab-34cd-56ef-1234567890ab" # Replace with your KMS key ARN
  }

  tags = {
    Environment = "production"
    Purpose     = "data-streaming"
  }
}

# CloudWatch Log Group for Firehose logging
resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name              = "/aws/kinesis/firehose/my-extended-s3-firehose-stream"
  retention_in_days = 30
}

