terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration
provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Kinesis stream as input source
resource "aws_kinesis_stream" "analytics_input" {
  name             = "kinesis-analytics-input"
  shard_count      = 1
  retention_period = 24

  tags = {
    Name = "Kinesis Analytics Input Stream"
  }
}

# Kinesis stream as output destination
resource "aws_kinesis_stream" "analytics_output" {
  name             = "kinesis-analytics-output"
  shard_count      = 1
  retention_period = 24

  tags = {
    Name = "Kinesis Analytics Output Stream"
  }
}

# IAM role for Kinesis Analytics
resource "aws_iam_role" "kinesis_analytics_role" {
  name = "kinesis-analytics-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kinesisanalytics.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Kinesis Analytics to read from input and write to output
resource "aws_iam_role_policy" "kinesis_analytics_policy" {
  name = "kinesis-analytics-policy"
  role = aws_iam_role.kinesis_analytics_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kinesis:DescribeStreamSummary",
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:GetRecords",
          "kinesis:ListShards"
        ]
        Resource = aws_kinesis_stream.analytics_input.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kinesis:PutRecord",
          "kinesis:PutRecords",
          "kinesis:DescribeStreamSummary",
          "kinesis:DescribeStream"
        ]
        Resource = aws_kinesis_stream.analytics_output.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_caller_identity.current.account_id}:log-group:/aws/kinesis-analytics/*"
      }
    ]
  })
}

# Data source for current AWS account ID
data "aws_caller_identity" "current" {}

# Kinesis Analytics V2 Application (SQL-based)
resource "aws_kinesisanalyticsv2_application" "sql_app" {
  name                   = "kinesis-sql-analytics-app"
  runtime_environment    = "SQL-1_0"
  service_execution_role = aws_iam_role.kinesis_analytics_role.arn

  application_configuration {
    sql_application_configuration {
      inputs {
        name_prefix = "input-"

        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json {
                record_row_path = "$"
              }
            }
          }

          record_encoding = "UTF-8"
        }

        input_parallelism {
          count = 1
        }

        input_starting_position_configuration {
          input_starting_position = "NOW"
        }

        kinesis_streams_input {
          resource_arn = aws_kinesis_stream.analytics_input.arn
        }
      }

      outputs {
        name = "output"

        kinesis_streams_output {
          resource_arn = aws_kinesis_stream.analytics_output.arn
        }

        schema {
          record_format_type = "JSON"
        }
      }

      # Simple SQL query to pass through records (count records per window)
      application_code = <<EOF
      CREATE OR REPLACE STREAM "input-stream" (payload VARCHAR(1000));

      CREATE OR REPLACE PUMP "input-pump" AS 
      INSERT INTO "output" 
      SELECT STREAM "payload", ROWTIME FROM "input-stream";

      CREATE OR REPLACE STREAM "output" (payload VARCHAR(1000), roctime ROWTIME);
EOF
    }
  }

  tags = {
    Name = "Kinesis SQL Analytics Application"
  }
}

