    sql_application_configuration {
      inputs {
        name_prefix = "test-input"
        input_schema {
          record_format {
            record_format_type = "JSON"
            mapping_parameters {
              json {
                record_row_path = "$"
              }
            }
          }
          record_encoding = "UTF-8"
          record_columns {
            name   = "name"
            sql_type = "VARCHAR(8)"
            mapping = "$.name"
          }
          record_columns {
            name   = "id"
            sql_type = "INTEGER"
            mapping = "$.id"
          }
        }
