terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Assume an existing Kendra index
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  role_arn    = aws_iam_role.kendra_role.arn
  edition     = "DEVELOPER_EDITION"

  # Additional configurations can be added here
}

# IAM role for Kendra
resource "aws_iam_role" "kendra_role" {
  name = "kendra-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "kendra_basic" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKendraDeveloperEditionPolicy"
}

# S3 bucket for data source (example for S3 data source)
resource "aws_s3_bucket" "data_source" {
  bucket = "example-kendra-data-source-bucket"
}

resource "aws_s3_bucket_versioning" "data_source" {
  bucket = aws_s3_bucket.data_source.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Kendra S3 data source with proxy configuration
resource "aws_kendra_data_source" "example" {
  index_id       = aws_kendra_index.example.id
  name           = "example-s3-data-source"
  type           = "S3"
  role_arn       = aws_iam_role.kendra_data_source_role.arn

  s3_configuration {
    bucket_name = aws_s3_bucket.data_source.bucket
    inclusion_prefixes = ["documents/"]
  }

  configuration {
    proxy_configuration {
      credentials_secret_arn = aws_secretsmanager_secret.proxy_credentials.arn
      host                   = "proxy.example.com"
      port                   = 8080
    }
  }

  schedule {
    interval = 1440  # Daily sync
  }

  tags = {
    Environment = "production"
  }
}

# IAM role for data source
resource "aws_iam_role" "kendra_data_source_role" {
  name = "kendra-data-source-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_data_source_policy" {
  name = "kendra-data-source-policy"
  role = aws_iam_role.kendra_data_source_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.data_source.arn,
          "${aws_s3_bucket.data_source.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue"
        ]
        Resource = aws_secretsmanager_secret.proxy_credentials.arn
      }
    ]
  })
}

# Secrets Manager secret for proxy credentials
resource "aws_secretsmanager_secret" "proxy_credentials" {
  name = "kendra-proxy-credentials"
}

resource "aws_secretsmanager_secret_version" "proxy_credentials" {
  secret_id     = aws_secretsmanager_secret.proxy_credentials.id
  secret_string = jsonencode({
    username = "proxy-username"
    password = "proxy-password"
  })
}

