extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Assume an existing Kendra index
resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  role_arn    = aws_iam_role.kendra_role.arn
  edition     = "DEVELOPER"

  server_side_encryption_configuration {
    kms_key_id = "alias/aws/kendra"
  }
}

# IAM role for Kendra
resource "aws_iam_role" "kendra_role" {
  name = "kendra-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "kendra_basic" {
  role       = aws_iam_role.kendra_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonKendraServiceRolePolicy"
}

# Kendra Web Crawler Data Source with URL Inclusion and Exclusion Patterns
resource "aws_kendra_data_source" "web_crawler" {
  index_id       = aws_kendra_index.example.id
  name           = "example-web-crawler-datasource"
  type           = "WEBCRAWLER"
  role_arn       = aws_iam_role.kendra_role.arn

  configuration {
    web_crawler_configuration {
      urls {
        seed_url_configuration {
          seed_url_list = ["https://example.com"]
        }
      }

      inclusion_filters {
        filter = "example\.com/.*"
      }

      inclusion_filters {
        filter = "example\.com/blog/.*"
      }

      exclusion_filters {
        filter = "example\.com/admin/.*"
      }

      exclusion_filters {
        filter = "example\.com/login.*"
      }

      # Crawl up to 3 levels deep
      crawl_depth = 3

      url_expiry_date = "2025-12-31T23:59:59Z"
    }
  }

  schedule {
    expression = "cron(0 1 ? * MON *)"  # Run weekly on Monday at 1 AM UTC
  }

  tags = {
    Environment = "dev"
  }
}

