provider "aws" {
  region = "us-east-1"
}

# Hosted Zone named "primary"
resource "aws_route53_zone" "primary" {
  name = "primary.example.com"  # Replace with your domain
}

# US East Endpoint (e.g., Virginia)
resource "aws_route53_record" "us_endpoint" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "us.primary.example.com"
  type    = "A"
  ttl     = 300
  records = ["3.5.140.128"]  # Example IP for US East endpoint
}

# EU West Endpoint (e.g., Frankfurt)
resource "aws_route53_record" "eu_endpoint" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "eu.primary.example.com"
  type    = "A"
  ttl     = 300
  records = ["18.184.65.144"]  # Example IP for EU West endpoint
}

# Geolocation Routing Policy - Route to nearest endpoint based on continent
resource "aws_route53_record" "geolocation_routing" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "app.primary.example.com"  # Main application endpoint
  type    = "A"
  ttl     = 300
  set_identifier = "geolocation-us-eu"

  geolocation_routing_policy {
    continent_code = "NA"  # North America (includes US)
    geolocation_routing_policy {
      primary = true
      endpoint {
        dns_name = aws_route53_record.us_endpoint.fqdn
      }
    }
  }

  geolocation_routing_policy {
    continent_code = "EU"  # Europe
    geolocation_routing_policy {
      primary = true
      endpoint {
        dns_name = aws_route53_record.eu_endpoint.fqdn
      }
    }
  }

  # Default routing (fallback)
  geolocation_routing_policy {
    continent_code = "default"
    geolocation_routing_policy {
      primary = true
      endpoint {
        dns_name = aws_route53_record.us_endpoint.fqdn  # Default to US
      }
    }
  }
}

# Optional: Name servers output
output "name_servers" {
  value = aws_route53_zone.primary.name_servers
}

