variable "cluster_name" {
  description = "Name of the EKS cluster"
  type        = string
}

provider "aws" {
  region = "us-west-2"  # Change as needed
}

# IAM Role for EKS Cluster
resource "aws_iam_role" "eks_cluster_role" {
  name = "${var.cluster_name}-eks-cluster-role"

  assume_role_policy = jsonencode({
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "eks.amazonaws.com"
      }
    }]
    Version = "2012-10-17"
  })
}

# Attach AmazonEKSClusterPolicy
resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

# Attach AmazonEKSServicePolicy
resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

# VPC and Subnet IDs (replace with your actual subnet IDs)
variable "vpc_subnet_ids" {
  description = "List of VPC Subnet IDs for EKS cluster"
  type        = list(string)
  default     = ["subnet-12345678", "subnet-87654321"]  # Replace with actual subnet IDs
}

# EKS Cluster
resource "aws_eks_cluster" "main" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_cluster_role.arn
  version  = "1.28"  # Specify desired Kubernetes version

  vpc_config {
    subnet_ids              = var.vpc_subnet_ids
    security_group_ids      = []
    endpoint_private_access = true
    endpoint_public_access  = true
    public_access_cidrs     = ["0.0.0.0/0"]
  }

  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy,
  ]

  # Provisioner to configure kubectl on cluster creation
  provisioner "local-exec" {
    command = <<EOT
      aws eks update-kubeconfig --region ${data.aws_region.current.name} --name ${var.cluster_name}
    EOT
  }

  # Provisioner to clean up kubectl config on cluster destruction
  provisioner "local-exec" {
    when    = destroy
    command = "kubectl config delete-cluster ${var.cluster_name}"
  }
}

# Data source for current region
data "aws_region" "current" {}

# Output cluster endpoint
output "cluster_endpoint" {
  description = "Endpoint for EKS control plane"
  value       = aws_eks_cluster.main.endpoint
}

output "cluster_name" {
  description = "Kubernetes Cluster Name"
  value       = aws_eks_cluster.main.name
}

output "kubeconfig_command" {
  description = "Run this command to update kubeconfig"
  value       = "aws eks update-kubeconfig --name ${aws_eks_cluster.main.name} --region ${data.aws_region.current.name}"
}

