# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

# S3 bucket with preventive destruction measures
resource "aws_s3_bucket" "platform_infra" {
  bucket = "wellcomecollection-platform-infra"
}

# Prevent accidental destruction
resource "aws_s3_bucket_ownership_controls" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Bucket ACL set to private
resource "aws_s3_bucket_acl" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id
  acl    = "private"
}

# Enable versioning
resource "aws_s3_bucket_versioning" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Lifecycle policy for tmp/ prefix (30 days deletion)
resource "aws_s3_bucket_lifecycle_configuration" "platform_infra" {
  bucket = aws_s3_bucket.platform_infra.id

  rule {
    id     = "tmp-prefix-30days"
    status = "Enabled"

    filter {
      prefix = "tmp/"
    }

    expiration {
      days = 30
    }
  }

  rule {
    id     = "versioning-transition-delete"
    status = "Enabled"

    noncurrent_version_expiration {
      noncurrent_days = 90
    }

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "STANDARD_IA"
    }
  }
}

