terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

variable "bucket_suffix" {
  description = "Suffix for bucket names"
  type        = string
  default     = "test"
}

# CloudGoat data storage bucket
resource "aws_s3_bucket" "cloudgoat_data" {
  bucket = "cloudgoat-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "cloudgoat_data" {
  bucket = aws_s3_bucket.cloudgoat_data.id

  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "cloudgoat_data" {
  bucket = aws_s3_bucket.cloudgoat_data.id
  acl    = "private"

  depends_on = [aws_s3_bucket_ownership_controls.cloudgoat_data]
}

# Web data storage bucket
resource "aws_s3_bucket" "web_data" {
  bucket = "web-data-${var.bucket_suffix}"
}

resource "aws_s3_bucket_ownership_controls" "web_data" {
  bucket = aws_s3_bucket.web_data.id

  rule {
    object_ownership = "ObjectWriter"
  }
}

resource "aws_s3_bucket_acl" "web_data" {
  bucket = aws_s3_bucket.web_data.id
  acl    = "private"

  depends_on = [aws_s3_bucket_ownership_controls.web_data]
}

# Public access block for web data bucket
resource "aws_s3_bucket_public_access_block" "web_data" {
  bucket = aws_s3_bucket.web_data.id

  block_public_acls       = true
  block_public_policy     = false
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Upload object to web data bucket
resource "aws_s3_object" "order_data" {
  bucket = aws_s3_bucket.web_data.id
  key    = "order_data2.csv"
  source = "order_data2.csv"

  depends_on = [aws_s3_bucket_acl.web_data]
}

# Bucket policy allowing s3:PutObject for all principals on web data bucket objects
resource "aws_s3_bucket_policy" "web_data" {
  bucket = aws_s3_bucket.web_data.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowPutObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:PutObject"
        Resource  = "${aws_s3_bucket.web_data.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.web_data]
}

