        Sid       = "AllowGetObjectWithReferer"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.my_bucket.arn}/*"
        Condition = {
          StringLike = {
            "aws:Referer" = ["*"]  # Replace with specific referer domains like "https://example.com/*"
          }
        }
      }
    ]
  })
}

