provider "aws" {
  region = "us-east-1"
}

# Main bucket for which logging will be enabled
resource "aws_s3_bucket" "main_bucket" {
  bucket = "my-main-bucket-unique-12345"
}

# Logging bucket to receive logs
resource "aws_s3_bucket" "logging_bucket" {
  bucket = "my-logging-bucket-unique-12345"
}

# ACL for main bucket - private
resource "aws_s3_bucket_acl" "main_bucket_acl" {
  bucket = aws_s3_bucket.main_bucket.id
  acl    = "private"
}

# ACL for logging bucket - allows log delivery writes
resource "aws_s3_bucket_acl" "logging_bucket_acl" {
  bucket = aws_s3_bucket.logging_bucket.id
  acl    = "log-delivery-write"
}

# Enable server access logging for main bucket to logging bucket
resource "aws_s3_bucket_logging" "main_bucket_logging" {
  bucket = aws_s3_bucket.main_bucket.id

  target_bucket = aws_s3_bucket.logging_bucket.id
  target_prefix = "log/"
}

# Ensure logging bucket has versioning enabled (recommended for log buckets)
resource "aws_s3_bucket_versioning" "logging_bucket_versioning" {
  bucket = aws_s3_bucket.logging_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

