      instance_type     = "t3.large"
      weighted_capacity = "1"
    }

    override {
      instance_type     = "t3.small"
      weighted_capacity = "1"
    }
  }

  type = "maintain"

  tags = {
    Name = "ec2-fleet"
  }
}

