  lifecycle {
    ignore_changes = [engine_version]
  }
}

# Supporting VPC and subnet group
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example" {
  vpc_id     = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"
}

resource "aws_elasticache_subnet_group" "example" {
  name       = "example-subnet-group"
  subnet_ids = [aws_subnet.example.id]
}

resource "aws_security_group" "example" {
  vpc_id = aws_vpc.example.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# IAM role for ElastiCache access
resource "aws_iam_role" "elasticache_access" {
  name = "ElastiCacheAccessRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticache.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy allowing ElastiCache Redis access
resource "aws_iam_role_policy" "elasticache_policy" {
  name = "ElastiCacheRedisPolicy"
  role = aws_iam_role.elasticache_access.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:Connect",
          "elasticache:Describe*"
        ]
        Resource = aws_elasticache_replication_group.example.arn
      }
    ]
  })
}

# ElastiCache User with IAM authentication
resource "aws_elasticache_user" "iam_user" {
  user_id        = "iam-user"
  user_name      = "iamuser"
  engine         = "REDIS"
  access_string  = "on"

  iam_authentication_enabled = true

  depends_on = [aws_elasticache_replication_group.example]
}

# User Group for IAM user association
resource "aws_elasticache_user_group" "iam_group" {
  user_group_id = "iam-group"
  engine        = "REDIS"
  user_ids      = [aws_elasticache_user.iam_user.user_id]
}

# Associate user group with replication group (enables IAM auth)
resource "aws_elasticache_replication_group_user_group_association" "example" {
  replication_group_id = aws_elasticache_replication_group.example.id
  user_group_id        = aws_elasticache_user_group.iam_group.user_group_id

  depends_on = [aws_elasticache_user_group.iam_group]
}

