  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Example ElastiCache Redis cluster (required for user group attachment)
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "example-rep-group"
  description                = "Example replication group"
  node_type                  = "cache.t4g.micro"
  port                       = 6379
  engine                     = "redis"
  engine_version             = "7.1"
  num_cache_clusters         = 1
  parameter_group_name       = "default.redis7.1"
  security_group_ids         = [aws_security_group.example.id]
  subnet_group_name          = aws_elasticache_subnet_group.example.name

  lifecycle {
    ignore_changes = [engine_version]
  }
}

# Security group for ElastiCache
resource "aws_security_group" "example" {
  name_prefix = "elasticache-example-"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port       = 6379
    to_port         = 6379
    protocol        = "tcp"
    security_groups = [aws_security_group.ec2_example.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Example VPC
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "elasticache-example"
  }
}

# Subnet group for ElastiCache
resource "aws_elasticache_subnet_group" "example" {
  name       = "example-subnet-group"
  subnet_ids = [aws_subnet.example.id]
}

resource "aws_subnet" "example" {
  vpc_id     = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"
}

# Security group for EC2 (for ingress rule)
resource "aws_security_group" "ec2_example" {
  name_prefix = "ec2-example-"
  vpc_id      = aws_vpc.example.id
}

# ElastiCache User Group
resource "aws_elasticache_user_group" "example" {
  user_group_id = "example-user-group"
  engine        = "REDIS"

  user_ids = [
    aws_elasticache_user.example.user_id
  ]

  # Attach to replication group
  replication_groups = [aws_elasticache_replication_group.example.id]
}

# ElastiCache User (required for user group)
resource "aws_elasticache_user" "example" {
  user_id                            = "example-user"
  user_group_ids                     = [aws_elasticache_user_group.example.user_group_id]
  engine                             = "REDIS"
  access_string                      = "on~allcommands~name:example-pattern*~channels:*~%"
  passwords                           = ["complex-password123!"]
  minimum_engine_version             = "7.1"
}

