```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (adjust region as needed)
provider "aws" {
  region = "us-east-1"
}

# Associate existing ElastiCache user with existing user group
resource "aws_elasticache_user_group_association" "example" {
  user_group_id = "your-existing-user-group-id"  # e.g., "ug-0123456789abcdef0"
  user_id       = "your-existing-user-id"        # e.g., "default"
}
```

**Note:** Replace `your-existing-user-group-id` and `your-existing-user-id` with the actual IDs of your pre-existing ElastiCache user group and user. These resources must exist prior to running `terraform apply`. Use `aws elasticache list-user-groups` and `aws elasticache list-users` to find the IDs.

