terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

# Subnet for Redshift
resource "aws_subnet" "redshift_subnet" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "redshift-subnet"
  }
}

# Subnet group for Redshift
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet.id]

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift cluster (single node)
resource "aws_redshift_cluster" "single_node_cluster" {
  cluster_identifier     = "single-node-redshift-cluster"
  database_name          = "dev"
  master_username        = "admin"
  master_password        = "SuperSecurePassword123!"  # Use secrets manager in production
  node_type              = "dc2.large"
  cluster_type           = "single-node"
  engine_version         = "1.0"

  subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name

  skip_final_snapshot = true  # Set to false in production

  tags = {
    Name = "single-node-redshift"
  }
}

# Output cluster endpoint
output "redshift_endpoint" {
  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.single_node_cluster.endpoint
}

