extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "redshift-vpc"
  }
}

# Subnet 1
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "redshift-subnet-1"
  }
}

# Subnet 2
resource "aws_subnet" "redshift_subnet_2" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "redshift-subnet-2"
  }
}

# Subnet group for Redshift
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Cluster (2 nodes)
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier      = "redshift-cluster-2node"
  database_name           = "dev"
  master_username         = "admin"
  master_password         = "SuperSecurePassword123!"  # Use secrets manager in production
  node_type               = "dc2.large"
  number_of_nodes         = 2
  cluster_type            = "multi-node"

  # Concurrency scaling configuration - 60 minutes max duration
  concurrency_scaling_mode             = "auto"
  concurrency_scaling_usage_limit_min  = 1
  concurrency_scaling_usage_limit_max  = 60

  cluster_subnet_group_name   = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids      = [aws_security_group.redshift_sg.id]
  availability_zone           = "us-west-2a"

  # Enable logging
  logging {
    enable = true
    s3_bucket_name = aws_s3_bucket.redshift_logs.bucket
    s3_key_prefix  = "logs"
  }

  skip_final_snapshot = true

  tags = {
    Name = "redshift-2node-cluster"
  }
}

# S3 bucket for Redshift logs
resource "aws_s3_bucket" "redshift_logs" {
  bucket = "redshift-logs-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_public_access_block" "redshift_logs" {
  bucket = aws_s3_bucket.redshift_logs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# IAM role for Redshift to access S3 logs
resource "aws_iam_role" "redshift_s3_role" {
  name = "redshift-s3-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "redshift_s3_policy" {
  name = "redshift-s3-policy"
  role = aws_iam_role.redshift_s3_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:PutObject",
          "s3:DeleteObject"
        ]
        Resource = "${aws_s3_bucket.redshift_logs.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = aws_s3_bucket.redshift_logs.arn
      }
    ]
  })
}

