}

provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# VPC for Redshift
resource "aws_vpc" "redshift_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "redshift-vpc"
  }
}

# Subnet 1
resource "aws_subnet" "redshift_subnet_1" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.1.0/24"
