provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

resource "aws_redshift_cluster" "single_node" {
  cluster_identifier      = "single-node-redshift-cluster"
  node_type               = "dc2.large"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "SecurePassword123!"  # Use secrets manager in production
  cluster_type            = "single-node"

  # Automatic snapshot every 12 hours
  automated_snapshot_retention_period = 7  # days to retain
  snapshot_cluster_identifier_prefix  = "redshift-snapshot-"

  # Preferred maintenance window for snapshots (12 hour interval example)
  preferred_maintenance_window = "sun:01:00-sun:03:00"

  # Apply immediately for testing
  apply_immediately = true

  # Security group
  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  # Subnet group
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name

  tags = {
    Name = "single-node-redshift"
  }
}

resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust to your VPC CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "redshift-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "redshift-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "redshift-subnet-b"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
