  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "redshift-subnet-a"
  }
}

resource "aws_subnet" "redshift_subnet_b" {
  vpc_id            = aws_vpc.redshift_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "redshift-subnet-b"
  }
}

# Subnet group for Redshift
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.redshift_subnet_a.id, aws_subnet.redshift_subnet_b.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Security Group for Redshift
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.redshift_vpc.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Parameter Group
resource "aws_redshift_parameter_group" "redshift_param_group" {
  name   = "redshift-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "true"
  }
}

# Redshift Cluster (Highly Available - Multi-AZ)
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier              = "redshift-ha-cluster"
  database_name                   = "redshiftdb"
  master_username                 = "admin"
  master_password                 = "RedshiftAdmin123!" # Change in production
  node_type                       = "dc2.large"
  cluster_type                    = "multi-node"
  number_of_nodes                 = 2
  cluster_subnet_group_name       = aws_redshift_subnet_group.redshift_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.redshift_sg.id]
  cluster_parameter_group_name    = aws_redshift_parameter_group.redshift_param_group.name
  availability_zone               = "us-east-1a" # Leader in 1a, replicas across AZs
  preferred_maintenance_window    = "sun:23:00-sun:03:00"
  maintenance_track_name          = "current"
  automated_snapshot_retention_period = 7
  publicly_accessible             = false
  encrypted                       = true

  tags = {
    Name = "redshift-ha-cluster"
  }
}

# Output cluster endpoint
output "redshift_endpoint" {
  description = "Redshift cluster endpoint"
  value       = aws_redshift_cluster.redshift_cluster.endpoint
}

output "redshift_port" {
  description = "Redshift cluster port"
  value       = aws_redshift_cluster.redshift_cluster.port
}

