terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (replace with your region)
provider "aws" {
  region = "us-west-2"
}

# IAM Role for Redshift Cluster
resource "aws_iam_role" "redshift_role" {
  name = "redshift-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# IAM Role Policy Attachment - AmazonRedshiftAllCommandsFullAccess (example policy)
resource "aws_iam_role_policy_attachment" "redshift_policy" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy:AmazonRedshiftAllCommandsFullAccess"
}

# Additional custom policy for S3 access (common for Redshift)
resource "aws_iam_role_policy" "redshift_s3_access" {
  name = "redshift-s3-access"
  role = aws_iam_role.redshift_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:DeleteObject",
          "s3:PutObject"
        ]
        Resource = "arn:aws:s3:::your-redshift-bucket/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = "arn:aws:s3:::your-redshift-bucket"
      }
    ]
  })
}

# Redshift Subnet Group
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = ["subnet-0123456789abcdef0", "subnet-0123456789abcdef1"] # Replace with your subnet IDs
}

# Redshift Security Group
resource "aws_security_group" "redshift_sg" {
