terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Example Lambda function (required for event source mapping)
resource "aws_lambda_function" "example" {
  filename         = "lambda.zip"  # Replace with your Lambda deployment package
  function_name    = "example-function"
  role            = aws_iam_role.lambda_exec.arn
  handler         = "index.handler"  # Adjust based on your code
  runtime         = "nodejs18.x"     # Adjust based on your runtime
  source_code_hash = filebase64sha256("lambda.zip")
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy attachment for Lambda execution
resource "aws_iam_role_policy_attachment" "lambda_policy" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# DynamoDB table
resource "aws_dynamodb_table" "example" {
  name           = "example-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  stream_enabled   = true
  stream_view_type = "NEW_AND_OLD_IMAGES"
}

# Lambda event source mapping from DynamoDB stream
resource "aws_lambda_event_source_mapping" "dynamodb" {
  event_source_arn = aws_dynamodb_table.example.stream_arn
  function_name    = aws_lambda_function.example.arn
  starting_position = "LATEST"

  # Optional: Batch configuration
  maximum_batching_window_in_seconds = 20
  maximum_retry_attempts             = 1000
  parallelization_factor             = 1
  bisect_batch_on_function_error     = true

  # Required for DynamoDB streams
  destination_config {
    on_failure {
      destination_arn = aws_sqs_queue.dlq.arn
    }
  }
}

# Dead Letter Queue (optional but recommended)
resource "aws_sqs_queue" "dlq" {
  name = "lambda-dynamodb-dlq"
}

