resource "aws_cloudwatch_event_rule" "every_fifteen_minutes" {
  name                = "every-fifteen-minutes"
  schedule_expression = "rate(15 minutes)"
}

# CloudWatch Event Target to invoke Lambda
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.every_fifteen_minutes.name
  target_id = "lambda-target"
  arn       = aws_lambda_function.example.arn
}

# Lambda permission to allow CloudWatch Events to invoke
resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.example.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_fifteen_minutes.arn
}
```

**Note:** Create a `lambda.zip` file in the same directory with a simple `index.js` like this:

```javascript
exports.handler = async (event) => {
  console.log('Triggered every 15 minutes!', event);
  return { statusCode: 200, body: 'Hello from Lambda!' };
};
```

Then run `zip -r lambda.zip index.js` before `terraform apply`.

