    }
  }
}

# Configure the AWS Provider
provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

# VPC for the DAX subnet group
resource "aws_vpc" "dax_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "dax-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "dax_igw" {
  vpc_id = aws_vpc.dax_vpc.id

  tags = {
    Name = "dax-igw"
  }
}

# Public Subnet 1 (us-east-1a)
resource "aws_subnet" "dax_subnet_a" {
  vpc_id                  = aws_vpc.dax_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "dax-subnet-a"
  }
}

# Public Subnet 2 (us-east-1b)
resource "aws_subnet" "dax_subnet_b" {
  vpc_id                  = aws_vpc.dax_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "dax-subnet-b"
  }
}

# Route Table
resource "aws_route_table" "dax_rt" {
  vpc_id = aws_vpc.dax_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.dax_igw.id
  }

  tags = {
    Name = "dax-rt"
  }
}

# Route Table Association for subnet A
resource "aws_route_table_association" "dax_rta_a" {
  subnet_id      = aws_subnet.dax_subnet_a.id
  route_table_id = aws_route_table.dax_rt.id
}

# Route Table Association for subnet B
resource "aws_route_table_association" "dax_rta_b" {
  subnet_id      = aws_subnet.dax_subnet_b.id
  route_table_id = aws_route_table.dax_rt.id
}

# Custom DAX Subnet Group
resource "aws_dax_subnet_group" "custom_dax_subnet_group" {
  name       = "custom-dax-subnet-group"
  vpc_id     = aws_vpc.dax_vpc.id
  subnet_ids = [aws_subnet.dax_subnet_a.id, aws_subnet.dax_subnet_b.id]

  tags = {
    Name = "custom-dax-subnet-group"
  }
}

# Output the DAX subnet group name and subnets
output "dax_subnet_group_name" {
  value = aws_dax_subnet_group.custom_dax_subnet_group.name
}

output "dax_subnet_group_subnets" {
  value = aws_dax_subnet_group.custom_dax_subnet_group.subnet_ids
}
```

