provider "aws" {
  region = "us-west-2"
}

# VPC and subnets (required for SageMaker Domain)
resource "aws_vpc" "sagemaker_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "sagemaker-vpc"
  }
}

resource "aws_subnet" "sagemaker_subnet_a" {
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "sagemaker-subnet-a"
  }
}

resource "aws_subnet" "sagemaker_subnet_b" {
  vpc_id            = aws_vpc.sagemaker_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "sagemaker-subnet-b"
  }
}

# Security Group for SageMaker Domain
resource "aws_security_group" "sagemaker_sg" {
  vpc_id = aws_vpc.sagemaker_vpc.id
  name   = "sagemaker-domain-sg"

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "sagemaker-security-group"
  }
}

# IAM Role for SageMaker Domain (Execution Role)
resource "aws_iam_role" "sagemaker_domain_execution_role" {
  name = "SageMakerDomainExecutionRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "sagemaker_domain_execution_policy" {
  role       = aws_iam_role.sagemaker_domain_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Domain
resource "aws_sagemaker_domain" "example" {
  domain_name = "my-sagemaker-domain"

  auth_mode = "SSO"
  vpc_id    = aws_vpc.sagemaker_vpc.id
  subnet_ids = [
    aws_subnet.sagemaker_subnet_a.id,
    aws_subnet.sagemaker_subnet_b.id
  ]

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_domain_execution_role.arn

    security_groups = [aws_security_group.sagemaker_sg.id]

    sharing_settings {
      notebook_output_option = "Disabled"
      s3_output_path         = "s3://my-sagemaker-bucket"
    }
  }

  tags = {
    Name = "my-sagemaker-domain"
  }

  depends_on = [
    aws_iam_role_policy_attachment.sagemaker_domain_execution_policy
  ]
}

# S3 bucket for notebook storage
resource "aws_s3_bucket" "sagemaker_bucket" {
  bucket = "my-sagemaker-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_public_access_block" "sagemaker_bucket" {
  bucket = aws_s3_bucket.sagemaker_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

