}

# Provider configuration (update region as needed)
provider "aws" {
  region = "us-west-2"
}

# IAM role for SageMaker domain (required for app)
resource "aws_iam_role" "sagemaker_domain_role" {
  name = "sagemaker-domain-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach SageMaker execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_domain_policy" {
  role       = aws_iam_role.sagemaker_domain_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Domain (required for apps)
resource "aws_sagemaker_domain" "example" {
  domain_name             = "example-domain"
  auth_mode              = "IAM"
  vpc_id                 = "vpc-12345678"  # Replace with your VPC ID
  subnet_ids             = ["subnet-12345678"]  # Replace with your subnet ID
  app_security_group_management = "Service"

  default_user_settings {
    execution_role = aws_iam_role.sagemaker_domain_role.arn
  }

  tags = {
    Name = "example-domain"
  }

  depends_on = [aws_iam_role_policy_attachment.sagemaker_domain_policy]
}

# SageMaker App - JupyterServer
resource "aws_sagemaker_app" "jupyter_server" {
  domain_name      = aws_sagemaker_domain.example.domain_name
  app_name         = "jupyter-server-app"
  app_type         = "JupyterServer"
  space_name       = "default-space"  # Default space
  user_profile_name = "default-user-profile"

  space_sharing_configuration {
    share_type = "Shared"
  }

  tags = {
    Name = "jupyter-server-app"
  }

  depends_on = [aws_sagemaker_domain.example]
}
```

**Note:** Before applying, update `vpc_id` and `subnet_ids` with your actual VPC and subnet IDs. Ensure the subnets are in the same region and have internet access for SageMaker. The IAM role uses `AmazonSageMakerFullAccess` for simplicity - consider least-privilege policies for production.

