    ]
  })
}

# Attach SageMaker execution policy
resource "aws_iam_role_policy_attachment" "sagemaker_execution" {
  role       = aws_iam_role.sagemaker_notebook_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# SageMaker Notebook Instance
resource "aws_sagemaker_notebook_instance" "example" {
  name             = "example-notebook-instance"
  role_arn         = aws_iam_role.sagemaker_notebook_role.arn
  instance_type    = "ml.t3.medium"
  subnet_id        = "subnet-xxxxxxxx"  # Replace with your subnet ID
  security_groups  = ["sg-xxxxxxxx"]    # Replace with your security group ID

  # Optional: Direct internet access
  direct_internet_access = "Enabled"

  # Optional: Root access
  root_access = "Enabled"

  tags = {
    Name = "example-notebook"
  }
}
```

**Note:** Before applying, replace `subnet-xxxxxxxx` and `sg-xxxxxxxx` with actual subnet ID and security group ID from your VPC. Ensure the security group allows inbound SSH (port 22) and Jupyter (port 8888) access.

