    status = "Enabled"
  }
}

# SageMaker Pipeline definition
resource "aws_sagemaker_pipeline" "example_pipeline" {
  name     = "example-pipeline"
  role_arn = aws_iam_role.sagemaker_pipeline_role.arn

  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Parameters = [
      {
        Name = "input_data"
        Type = "String"
        DefaultValue = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/input/data.csv"
      }
    ]
    Steps = [
      {
        Name = "Processing"
        Type = "Processing"
        Arguments = {
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount = 1
              InstanceType = "ml.m5.large"
              VolumeSizeInGB = 30
            }
          }
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py36-ubuntu18.04"
            ContainerArguments = ["/opt/ml/processing/input", "/opt/ml/processing/output"]
            ContainerEntrypoint = ["python3", "/opt/ml/processing/entrypoint.py"]
          }
          ProcessingInputs = [
            {
              InputName = "input_data"
              AppManaged = false
              S3Input = {
                S3Uri = "$${input_data}"
                LocalPath = "/opt/ml/processing/input"
                S3DataType = "S3Prefix"
                S3InputMode = "File"
                S3DataDistributionType = "FullyReplicated"
              }
            }
          ]
          ProcessingOutputConfig = {
            Outputs = [
              {
                OutputName = "train_data"
                AppManaged = false
                S3Output = {
                  S3Uri = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/output/train"
                  LocalPath = "/opt/ml/processing/output/train"
                  S3UploadMode = "EndOfJob"
                }
              },
              {
                OutputName = "test_data"
                AppManaged = false
                S3Output = {
                  S3Uri = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/output/test"
                  LocalPath = "/opt/ml/processing/output/test"
                  S3UploadMode = "EndOfJob"
                }
              }
            ]
          }
        }
      },
      {
        Name = "Training"
        Type = "Training"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage = "683313688378.dkr.ecr.us-east-1.amazonaws.com/sagemaker-xgboost:1.5-1-cpu-py3"
            TrainingInputMode = "File"
          }
          InputDataConfig = [
            {
              ChannelName = "train"
              DataSource = {
                S3DataSource = {
                  S3DataType = "S3Prefix"
                  S3Uri = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/output/train"
                  S3DataDistributionType = "FullyReplicated"
                }
              }
              ContentType = "text/csv"
            }
          ]
          OutputDataConfig = {
            S3OutputPath = "s3://${aws_s3_bucket.sagemaker_pipeline_bucket.bucket}/output/model"
          }
          ResourceConfig = {
            InstanceCount = 1
            InstanceType = "ml.m5.large"
            VolumeSizeInGB = 30
          }
          EnableManagedSpotTraining = false
          RoleArn = aws_iam_role.sagemaker_pipeline_role.arn
          StoppingCondition = {
            MaxRuntimeInSeconds = 3600
          }
        }
        Dependencies = ["Processing"]
      }
    ]
  })
}

