resource "aws_iam_role" "sagemaker_execution_role" {
  name = "sagemaker-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "sagemaker.amazonaws.com"
        }
      }
    ]
  })
}

# Attach SageMaker full access policy
resource "aws_iam_role_policy_attachment" "sagemaker_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSageMakerFullAccess"
}

# Attach S3 full access policy
resource "aws_iam_role_policy_attachment" "s3_full_access" {
  role       = aws_iam_role.sagemaker_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

# SageMaker Model
resource "aws_sagemaker_model" "ml_model" {
  name = "my-model"

  execution_role_arn = aws_iam_role.sagemaker_execution_role.arn

  primary_container {
    image = "246618370639.dkr.ecr.us-west-2.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"  # Example image
    # model_data_url = "s3://${aws_s3_bucket.model_bucket.bucket}/model.tar.gz"  # Uncomment and upload your model
  }
}

# SageMaker Endpoint Configuration
resource "aws_sagemaker_endpoint_configuration" "endpoint_config" {
  name = "my-endpoint-config"

  production_variants {
    variant_name           = "AllTraffic"
    model_name             = aws_sagemaker_model.ml_model.name
    initial_instance_count = 1
    instance_type          = "ml.m5.large"
  }
}

# SageMaker Endpoint
resource "aws_sagemaker_endpoint" "endpoint" {
  name                 = "my-endpoint"
  endpoint_config_name = aws_sagemaker_endpoint_configuration.endpoint_config.name

  depends_on = [aws_sagemaker_endpoint_configuration.endpoint_config]
}

# Output the endpoint name and invoke URL
output "endpoint_name" {
  value = aws_sagemaker_endpoint.endpoint.name
}

output "endpoint_arn" {
  value = aws_sagemaker_endpoint.endpoint.arn
}
```

**Notes:**
1. Update `model_data_url` in the `aws_sagemaker_model` resource with your S3 path to model artifacts (`s3://your-bucket/model.tar.gz`)
2. Replace the container `image` with your model's container image
3. Adjust `instance_type` and `initial_instance_count` as needed
4. Upload your trained model to the S3 bucket before applying
5. The endpoint will be ready for inference after ~5-10 minutes

