  name = "ElastiCacheAuthRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "elasticache.amazonaws.com"
        }
      }
    ]
  })
}

# ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name       = "elasticache-subnet-group"
  subnet_ids = ["subnet-0123456789abcdef0", "subnet-0abcdef1234567890"]  # Replace with your subnet IDs
}

# ElastiCache Redis User for Authentication
resource "aws_elasticache_user" "redis_auth_user" {
  user_id        = "redis-admin"
  user_name      = "redisadmin"
  engine         = "REDIS"
  access_string  = "on ~* &* +@all"
  passwords      = ["SecureRedisPassword123!"]
}

# ElastiCache Redis Parameter Group with Authentication Enabled
resource "aws_elasticache_parameter_group" "redis_auth" {
  family = "redis7"
  name   = "redis-auth-params"

  parameter {
    name  = "auth-token"
    value = "SecureRedisPassword123!"  # Must match user password
  }

  parameter {
    name  = "requirepass"
    value = "true"
  }
}

# ElastiCache Redis Cluster with User Authentication
resource "aws_elasticache_replication_group" "redis_authenticated" {
  replication_group_id       = "redis-auth-cluster"
  description                = "Redis cluster with authentication"
  node_type                  = "cache.t4g.micro"
