  # Enable at-rest encryption (recommended)
  at_rest_encryption_enabled = true

  # Enable transit encryption (recommended for auth)
  transit_encryption_enabled = true

  auth_token                   = "SecureRedisPassword123!"
  auth_token_update_strategy   = "SET"
}

# ElastiCache User Group
resource "aws_elasticache_user_group" "redis_auth_group" {
  user_group_id = "redis-auth-group"
