# Example VPC and subnets (required for ElastiCache)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "elasticache-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-b"
  }
}

# ElastiCache Subnet Group
resource "aws_elasticache_subnet_group" "main" {
  name       = "elasticache-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]
}

# ElastiCache Redis Cluster with Authentication Enabled
resource "aws_elasticache_replication_group" "main" {
  replication_group_id       = "redis-iam-auth-cluster"
  description                = "Redis cluster with IAM authentication"
  engine                     = "redis"
  engine_version             = "7.1"
  node_type                  = "cache.t4g.micro"
  port                       = 6379
  num_cache_clusters         = 1
  parameter_group_name       = aws_elasticache_parameter_group.iam_auth.name
  subnet_group_name          = aws_elasticache_subnet_group.main.name
  security_group_ids         = [aws_security_group.elasticache.id]
  transit_encryption_enabled = true
  at_rest_encryption_enabled = true
  auth_token                 = "temp-password" # Required when IAM auth is enabled

  # Enable IAM database authentication
  auth_token_update_strategy = "SET_AUTH_TOKEN"

  tags = {
    Name = "redis-iam-auth"
  }
}

# Parameter group to enable IAM authentication
resource "aws_elasticache_parameter_group" "iam_auth" {
  family = "redis7.1"
  name   = "redis-iam-auth-params"

  parameter {
    name  = "auth-token-update-strategy"
    value = "rotate"
  }
}

# Security Group for ElastiCache
resource "aws_security_group" "elasticache" {
  name_prefix = "elasticache-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 6379
    to_port         = 6379
    protocol        = "tcp"
    self            = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "elasticache-sg"
  }
}

# IAM User for ElastiCache authentication
resource "aws_iam_user" "elasticache_user" {
  name = "elasticache-iam-user"
}

# IAM Policy for ElastiCache IAM authentication
resource "aws_iam_policy" "elasticache_iam_auth" {
  name        = "ElastiCacheIAMAuthPolicy"
  description = "Policy for IAM authentication to ElastiCache"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:Connect",
          "elasticache-db:Connect"
        ]
        Resource = aws_elasticache_replication_group.main.arn
      }
    ]
  })
}

# Attach policy to IAM user
resource "aws_iam_user_policy_attachment" "elasticache_user_policy" {
  user       = aws_iam_user.elasticache_user.name
  policy_arn = aws_iam_policy.elasticache_iam_auth.arn
}

# Output the IAM user ARN and ElastiCache endpoint for reference
output "elasticache_endpoint" {
  value = aws_elasticache_replication_group.main.primary_endpoint_address
}

output "iam_user_arn" {
  value = aws_iam_user.elasticache_user.arn
}

output "iam_user_name" {
  value = aws_iam_user.elasticache_user.name
}

