# Example: ElastiCache Redis cluster with authentication enabled
resource "aws_elasticache_subnet_group" "main" {
  name       = "elasticache-subnet-group"
  subnet_ids = var.subnet_ids  # Provide your subnet IDs
}

resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "example-redis-cluster"
  description                = "Redis cluster with authentication"
  node_type                  = "cache.t4g.micro"
  port                       = 6379
  num_cache_clusters         = 1
  engine                     = "redis"
  engine_version             = "7.1"
  parameter_group_name       = aws_elasticache_parameter_group.example.name
  subnet_group_name          = aws_elasticache_subnet_group.main.name
  security_group_ids         = [aws_security_group.elasticache.id]

  # Enable authentication
  auth_token                  = random_password.auth_token.result
  transit_encryption_enabled  = true
  at_rest_encryption_enabled  = true

  # Auto-failover and multi-AZ
  automatic_failover_enabled = true
  multi_az_enabled           = true

  # Maintenance window
  maintenance_window = "sun:23:00-sun:01:00"
}

# Parameter group to enable authentication
resource "aws_elasticache_parameter_group" "example" {
  family = "redis7.1"
  name   = "example-params"

  parameter {
    name  = "auth-token-update-enabled"
    value = "1"
  }
}

# Security group for ElastiCache
resource "aws_security_group" "elasticache" {
  name_prefix = "elasticache-"
  vpc_id      = var.vpc_id  # Provide your VPC ID

