  auth_token                  = random_password.auth_token.result
  transit_encryption_enabled  = true
  at_rest_encryption_enabled  = true

  # Auto-failover and multi-AZ
  automatic_failover_enabled = true
  multi_az_enabled           = true

  # Maintenance window
  maintenance_window = "sun:23:00-sun:01:00"
}

# Parameter group to enable authentication
resource "aws_elasticache_parameter_group" "example" {
  family = "redis7.1"
  name   = "example-params"

  parameter {
    name  = "auth-token-update-enabled"
    value = "1"
  }
}

# Security group for ElastiCache
resource "aws_security_group" "elasticache" {
  name_prefix = "elasticache-"
  vpc_id      = var.vpc_id  # Provide your VPC ID

  ingress {
    from_port       = 6379
    to_port         = 6379
    protocol        = "tcp"
    security_groups = [var.client_security_group_id]  # Your application SG
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Random password for authentication token
resource "random_password" "auth_token" {
  length  = 32
  special = false
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Output the authentication token (store securely in production)
output "elasticache_auth_token" {
  description = "ElastiCache Authentication Token"
  value       = random_password.auth_token.result
  sensitive   = true
}

output "elasticache_endpoint" {
  description = "ElastiCache Primary Endpoint"
  value       = aws_elasticache_replication_group.example.primary_endpoint_address
}

# Variables
variable "vpc_id" {
  description = "VPC ID"
  type        = string
}

variable "subnet_ids" {
  description = "List of subnet IDs"
  type        = list(string)
}

variable "client_security_group_id" {
  description = "Security group ID of the client/application"
  type        = string
}
```

**Usage Notes:**
1. Set the required variables (`vpc_id`, `subnet_ids`, `client_security_group_id`)
2. Connect to Redis using: `redis-cli -h <endpoint> -p 6379 -a <auth_token>`
3. The `auth_token` is the password for authenticating users/connections
4. Store the auth token securely (use Secrets Manager in production)
5. Update security groups to allow access from your application only

