}

# VPC for MSK
resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

# Subnets (3 subnets across different AZs)
resource "aws_subnet" "msk_subnet" {
  count = 3

  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.${count.index + 1}.0/24"
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "msk-subnet-${count.index + 1}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    description = "MSK from anywhere"
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "MSK TLS from anywhere"
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# MSK Cluster
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 1000    # 1TB per broker

    client_subnets = aws_subnet.msk_subnet[*].id
    security_groups = [aws_security_group.msk_sg.id]

    vpc_config {
      subnet_ids         = aws_subnet.msk_subnet[*].id
      security_group_ids = [aws_security_group.msk_sg.id]
    }
  }

  tags = {
    Name = "msk-cluster"
  }
}

# Output cluster details
output "msk_bootstrap_brokers" {
  description = "Bootstrap brokers"
  value       = aws_msk_cluster.msk_cluster.bootstrap_broker_string
}

output "msk_arn" {
  description = "MSK Cluster ARN"
  value       = aws_msk_cluster.msk_cluster.arn
}

