}

provider "aws" {
  region = "us-east-1"
}

# VPC for MSK cluster
resource "aws_vpc" "msk_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "msk-vpc"
  }
}

# Public subnet 1
resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "msk-public-subnet-1"
  }
}

# Public subnet 2
resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "msk-public-subnet-2"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "msk_igw" {
  vpc_id = aws_vpc.msk_vpc.id

  tags = {
    Name = "msk-igw"
  }
}

# Public Route Table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.msk_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.msk_igw.id
  }

  tags = {
    Name = "msk-public-rt"
  }
}

# Route Table Associations
resource "aws_route_table_association" "public_1" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_2" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# Private subnet 1 for MSK
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "msk-private-subnet-1"
  }
}

# Private subnet 2 for MSK
resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.4.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "msk-private-subnet-2"
  }
}

# KMS Key for encryption at rest
resource "aws_kms_key" "msk_encryption" {
  description             = "KMS key for MSK encryption at rest"
  enable_key_rotation     = true
  deletion_window_in_days = 30

  tags = {
    Name = "msk-encryption-key"
  }
}

# KMS Key Alias
resource "aws_kms_alias" "msk_key_alias" {
  name          = "alias/msk-encryption-key"
  target_key_id = aws_kms_key.msk_encryption.key_id
}

# MSK Security Group
resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    description = "MSK from anywhere"
    from_port   = 9092
    to_port     = 9098
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "MSK TLS from anywhere"
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# MSK Cluster with encryption at rest
resource "aws_msk_cluster" "main" {
  cluster_name           = "msk-encrypted-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 1000    # 1TB per broker
    client_subnets = [
      aws_subnet.private_subnet_1.id,
      aws_subnet.private_subnet_2.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    vpc_id          = aws_vpc.msk_vpc.id
  }

  encryption_info {
    encryption_at_rest {
      data_volume_kms_key_id = aws_kms_key.msk_encryption.arn
    }
  }

  monitoring_info {
    cloudwatch_log_group = "/aws/msk/my-cluster"
  }

  tags = {
    Name = "msk-encrypted-cluster"
  }

  depends_on = [aws_kms_key.msk_encryption]
}

# CloudWatch Log Group for MSK monitoring
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/my-cluster"
  retention_in_days = 14

  tags = {
    Name = "msk-cluster-logs"
  }
}
```

This Terraform configuration creates a fully managed Amazon MSK cluster with:

- VPC with public and private subnets across 2 AZs
- Custom KMS key for encryption at rest
- 3 broker nodes (kafka.m5.large) with 1TB EBS storage each
- Security group allowing Kafka traffic (ports 9092-9098)
- CloudWatch logging enabled
- Encryption at rest using the custom KMS key

**Note**: Update the AWS region and AZs as needed for your environment. The cluster will take 15-30 minutes to provision.

