# MSK Cluster with JMX Exporter and Node Exporter enabled
resource "aws_msk_cluster" "msk_cluster" {
  cluster_name           = "managed-msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
    client_subnets = [
      aws_subnet.msk_subnet_a.id,
      aws_subnet.msk_subnet_b.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    vpc_security_group_ids = [aws_security_group.msk_sg.id]
  }

  monitoring_info {
    cloudwatch_log_group = aws_cloudwatch_log_group.msk_log.id
  }

  # Enable JMX Exporter and Node Exporter
  open_monitoring {
