  }
}

# CloudWatch Log Group for MSK
resource "aws_cloudwatch_log_group" "msk_log" {
  name              = "/aws/msk/managed-msk-cluster"
  retention_in_days = 7
}

# IAM role for MSK to write logs to CloudWatch
resource "aws_iam_role" "msk_log_role" {
  name = "msk-cloudwatch-logs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafka.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_log_policy" {
  role = aws_iam_role.msk_log_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect   = "Allow"
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Attach logging policy to MSK cluster
resource "aws_msk_cluster" "msk_cluster" {
  # ... previous configuration ...

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled = true
        log_group = aws_cloudwatch_log_group.msk_log.name
      }
    }
  }

  depends_on = [aws_iam_role_policy.msk_log_policy]
}
```

**Note:** This configuration creates a fully managed MSK cluster with both JMX Exporter and Node Exporter enabled via the `open_monitoring.prometheus` block. The cluster is accessible on ports 9092 (Kafka) and 9094 (Prometheus metrics). Ensure your AWS account has the necessary permissions for MSK and CloudWatch Logs. The `depends_on` ensures proper IAM role creation before cluster deployment.

