  tags = {
    Name = "msk-public-1a"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.msk_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "msk-public-1b"
  }
}

# Private subnets for MSK
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.64.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "msk-private-1a"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = "10.0.65.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "msk-private-1b"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "msk_igw" {
  vpc_id = aws_vpc.msk_vpc.id
  tags = {
    Name = "msk-igw"
  }
}

# Public route table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.msk_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.msk_igw.id
  }
  tags = {
    Name = "msk-public-rt"
  }
}

resource "aws_route_table_association" "public_1a" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_1b" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# Security Group for MSK
resource "aws_security_group" "msk_sg" {
  name_prefix = "msk-cluster-"
  vpc_id      = aws_vpc.msk_vpc.id

  ingress {
    description = "MSK from anywhere"
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "MSK TLS from anywhere"
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-sg"
  }
}

# Serverless MSK Cluster with 3 broker nodes capacity
resource "aws_msk_cluster" "serverless_msk" {
  cluster_name           = "serverless-msk-cluster"
  kafka_version          = "3.7.1"
  number_of_broker_nodes = 3

  vpc_config {
    subnet_ids         = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.msk_sg.id]
  }

  # Serverless configuration
  serverless {
    client_authentication {
      sasl {
        iam {
          enabled = true
        }
      }
    }
  }

  tags = {
    Name = "serverless-msk-cluster"
  }
}

# Output cluster details
output "msk_bootstrap_brokers" {
  description = "Bootstrap brokers"
  value       = aws_msk_cluster.serverless_msk.bootstrap_brokers_sasl_iam
}

output "msk_arn" {
  description = "MSK Cluster ARN"
  value       = aws_msk_cluster.serverless_msk.arn
}

