  }
}

# MSK Cluster
resource "aws_msk_cluster" "main" {
  cluster_name           = "debezium-msk-cluster"
  kafka_version          = "3.7.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
    client_subnets = [
      aws_subnet.msk_subnet_a.id,
      aws_subnet.msk_subnet_b.id,
      aws_subnet.msk_subnet_c.id
    ]
    security_groups = [aws_security_group.msk_sg.id]
    vpc_subnet_group_name = "msk-subnet-group"
  }

  client_authentication {
    saslauth = {
      plain_text = true
    }
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = "arn:aws:kms:us-east-1:111122223333:key/example-key-id"
    encryption_in_transit {
      in_cluster = true
    }
  }

  monitoring_info {
    cloudwatch_log_group = "/aws/msk/main"
  }

  tags = {
    Name = "debezium-msk"
  }

  depends_on = [aws_cloudwatch_log_group.msk_log_group]
}

resource "aws_cloudwatch_log_group" "msk_log_group" {
  name              = "/aws/msk/main"
  retention_in_days = 7
}

# S3 bucket for custom plugin
resource "aws_s3_bucket" "plugin_bucket" {
  bucket = "debezium-plugin-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_versioning" "plugin_bucket_versioning" {
  bucket = aws_s3_bucket.plugin_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

# Upload Debezium plugin to S3 (assumes local file exists)
resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.plugin_bucket.id
  key    = "debezium.zip"
  source = "debezium.zip"  # Local path to debezium.zip file
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name       = "debezium-custom-plugin"
  content_type = "ZIPFILE"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.plugin_bucket.arn
      file_path  = aws_s3_object.debezium_plugin.key
    }
  }

  description = "Debezium custom plugin"
}

# MSK Connect Worker Configuration
resource "aws_mskconnect_worker_configuration" "main" {
  name = "debezium-worker-config"

  properties = {
    "client.producer.max.request.size" = "2097152"
    "client.producer.buffer.memory"    = "5242880"
    "connect.plugin.path"              = "."
  }
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  connector_name = "debezium-connector"
  capacity {
    auto_scaling {
      mcu_count       = 1
      min_worker_count = 1
      max_worker_count = 4
      scale_in_policy {
        cpu_utilization_percentage = 20
      }
      scale_out_policy {
        cpu_utilization_percentage = 80
      }
    }
  }
  connector_configuration = {
    "connector.class"           = "io.debezium.connector.PostgresqlConnector"  # Example Debezium connector
    "database.hostname"         = "your-postgres-host.example.com"
    "database.port"             = "5432"
    "database.user"             = "debezium"
    "database.password"         = "password"
    "database.dbname"           = "inventory"
    "database.server.name"      = "dbserver1"
    "table.include.list"        = "inventory.customers"
    "key.converter"             = "org.apache.kafka.connect.json.JsonConverter"
    "value.converter"           = "org.apache.kafka.connect.json.JsonConverter"
    "key.converter.schemas.enable" = "false"
    "value.converter.schemas.enable" = "false"
    "topics"                    = "dbserver1.inventory.customers"
  }
  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = [aws_security_group.msk_sg.id]
        subnets         = [
          aws_subnet.msk_subnet_a.id,
          aws_subnet.msk_subnet_b.id,
          aws_subnet.msk_subnet_c.id
        ]
      }
      apache_kafka_cluster_arn = aws_msk_cluster.main.arn
    }
  }
  kafka_connect_version = "3.1.1"
  plugin {
    custom_plugin {
      arn = aws_mskconnect_custom_plugin.debezium_plugin.arn
    }
  }
  service_execution_role_arn = aws_iam_role.mskconnect_role.arn
  worker_configuration {
    arn = aws_mskconnect_worker_configuration.main.arn
  }

  log_delivery {
    cloudwatch_logs {
      enabled = true
      log_group = aws_cloudwatch_log_group.connector_log_group.name
    }
  }

  depends_on = [
    aws_iam_role_policy_attachment.mskconnect_policy
  ]
}

# IAM Role for MSK Connect
resource "aws_iam_role" "mskconnect_role" {
  name = "mskconnect-role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "mskconnect_policy" {
  role       = aws_iam_role.mskconnect_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonMSKConnectServiceRolePolicy"
}

resource "aws_cloudwatch_log_group" "connector_log_group" {
  name              = "/aws/mskconnect/debezium-connector"
  retention_in_days = 7
}

