```hcl
provider "aws" {
  region = "us-east-1"
}

# CloudWatch Log Group for MSK
resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/my-cluster"
  retention_in_days = 14
}

# S3 Bucket for Firehose
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "my-msk-firehose-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_server_side_encryption_configuration" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "firehose_bucket" {
  bucket = aws_s3_bucket.firehose_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Kinesis Firehose Delivery Stream
resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose-stream"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose/"
  }
}

# IAM Role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      }
    ]
  })
}

# MSK Cluster
resource "aws_msk_cluster" "main" {
  cluster_name           = "my-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type  = "kafka.m5.large"
    ebs_volume_size = 100
    client_subnets = [aws_subnet.private_a.id, aws_subnet.private_b.id]
    security_groups = [aws_security_group.msk.id]
    vpc_config {
      subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]
      security_group_ids = [aws_security_group.msk.id]
    }
  }

  encryption_info {
    encryption_at_rest {
      data_volume_kms_key_id = "aws/kafka"
    }
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        tls {
          enabled = true
        }
      }
      node_exporter {
        tls {
          enabled = true
        }
      }
    }
  }

  logging_info {
    cloudwatch_log_group = aws_cloudwatch_log_group.msk_logs.name
    firehose {
      delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
    }
  }

  tags = {
    Environment = "production"
  }
}

# VPC and Networking
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-b"
  }
}

resource "aws_security_group" "msk" {
  name_prefix = "msk-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# MSK Connect Custom Plugin
resource "aws_s3_bucket" "msk_connect_plugins" {
  bucket = "msk-connect-plugins-${random_id.connect_suffix.hex}"
}

resource "random_id" "connect_suffix" {
  byte_length = 8
}

resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msk_connect_plugins.id
  key    = "debezium.zip"
  source = "debezium.zip"  # Local file path
}

resource "aws_mskconnect_custom_plugin" "debezium" {
  name       = "debezium-plugin"
  content_type = "ZIPFILE"
  location {
    s3 {
      bucket_arn = aws_s3_bucket.msk_connect_plugins.arn
      file_key   = aws_s3_object.debezium_plugin.key
    }
  }

  depends_on = [aws_s3_object.debezium_plugin]
}

# IAM Role for MSK Connect
resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "kafkaconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  name = "msk-connect-policy"
  role = aws_iam_role.msk_connect_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "kafka-cluster:Connect",
          "kafka-cluster:AlterCluster",
          "kafka-cluster:DescribeCluster"
        ]
        Resource = aws_msk_cluster.main.arn
      },
      {
        Effect = "Allow"
        Action = [
          "kafka:Create*",
          "kafka:Describe*",
          "kafka:Delete*",
          "kafka:Alter*",
          "kafka:List*"
        ]
        Resource = "*"
      }
    ]
  })
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  connector_name = "debezium-connector"
  kafka_cluster {
    apache_kafka_cluster {
      vpc {
        security_groups = [aws_security_group.msk.id]
        subnets         = [aws_subnet.private_a.id, aws_subnet.private_b.id]
      }
      kafka_cluster_arn = aws_msk_cluster.main.arn
    }
  }
  kafka_connect_version = "3.5"
  service_role_arn      = aws_iam_role.msk_connect_role.arn
  capacity {
    provisioned_capacity {
      mku_count = 1
    }
  }
  plugin {
    custom_plugin_arn = aws_mskconnect_custom_plugin.debezium.arn
  }
  connector_configuration = {
    "connector.class" = "io.debezium.connector.PostgresqlConnector"
    "database.hostname" = "your-db-host"
    "database.port" = "5432"
    "database.user" = "dbuser"
    "database.password" = "dbpassword"
    "database.dbname" = "yourdb"
    "database.server.name" = "server1"
    "key.converter" = "org.apache.kafka.connect.json.JsonConverter"
    "value.converter" = "io.debezium.converters.JsonConverter"
    "value.converter.type" = "io.debezium.converters.JsonConverter"
    "value.converter.version" = "1.8.1.Final"
    "value.converter.schemas.enable" = "false"
    "value.converter.transforms" = "unwrap"
    "value.converter.transforms.unwrap.type" = "io.debezium.transforms.ExtractNewRecordState"
    "value.converter.transforms.unwrap.drop.tombstones" = "false"
  }

  depends_on = [aws_msk_cluster.main]
}
```

**Note:** Update the Debezium connector configuration with your actual source database details (PostgreSQL/MySQL/etc.). Place the `debezium.zip` file in your Terraform working directory before running `terraform apply`. The VPC/subnet setup is minimal - adjust CIDR blocks and AZs as needed for your environment.

