provider "aws" {
  region = "us-east-1"
}

module "mysql_cluster" {
  source  = "terraform-aws-modules/rds/aws"
  version = "~> 6.0"

  # Identifier
  identifier           = "mysql-cluster"
  engine               = "mysql"
  engine_version       = "8.0"
  family               = "mysql8.0"
  major_engine_version = "8.0"

  # Primary instance configuration
  instance_class   = "db.m5.large"
  allocated_storage = 100
  storage_type     = "gp3"
  storage_encrypted = true

  # Multi-AZ cluster with 3 instances
  create_cluster      = true
  cluster_identifier  = "mysql-cluster"
  db_cluster_instance_class = "db.m5.large"
  instances = {
    "a" = {
      identifier         = "mysql-cluster-a"
      instance_class     = "db.m5.large"
      publicly_accessible = false
      performance_insights_enabled = true
      db_subnet_group_name   = module.mysql_cluster.db_subnet_group_name
      vpc_security_group_ids = [module.mysql_cluster.vpc_security_group_ids]
    }
    "b" = {
      identifier         = "mysql-cluster-b"
      instance_class     = "db.m5.large"
      publicly_accessible = false
      performance_insights_enabled = true
      db_subnet_group_name   = module.mysql_cluster.db_subnet_group_name
      vpc_security_group_ids = [module.mysql_cluster.vpc_security_group_ids]
    }
    "c" = {
      identifier         = "mysql-cluster-c"
      instance_class     = "db.m5.large"
      publicly_accessible = false
      performance_insights_enabled = true
      db_subnet_group_name   = module.mysql_cluster.db_subnet_group_name
      vpc_security_group_ids = [module.mysql_cluster.vpc_security_group_ids]
    }
  }

  # All instances have 100 GB storage
  storage_type      = "gp3"
  allocated_storage = 100
  max_allocated_storage = 1000

  db_name  = "mydatabase"
  username = "admin"
  password = "SuperSecurePassword123!"
  port     = 3306

  vpc_security_group_ids = [aws_security_group.rds.id]

  # DB subnet group across us-east-1a, us-east-1b, us-east-1c
  create_db_subnet_group = true
  db_subnet_group_name   = "mysql-cluster-subnet-group"
  subnet_ids = [
    aws_subnet.private_a.id,
    aws_subnet.private_b.id,
    aws_subnet.private_c.id
  ]

  # Backup configuration
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"

  # Deletion protection
  deletion_protection = true

  # Parameter group
  db_cluster_parameter_group_name = aws_db_parameter_group.mysql.name
  db_parameter_group_name         = aws_db_parameter_group.mysql.name

  # Monitoring
  monitoring_interval = 60
  monitoring_role_arn = aws_iam_role.rds_monitoring.arn
  enabled_cloudwatch_logs_exports = ["error", "general", "slowquery"]

  tags = {
    Name = "mysql-cluster"
  }
}

# VPC and subnets for us-east-1a, us-east-1b, us-east-1c
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "mysql-vpc"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-a"
    Type = "private"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-b"
    Type = "private"
  }
}

resource "aws_subnet" "private_c" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "private-c"
    Type = "private"
  }
}

# Security group for RDS
resource "aws_security_group" "rds" {
  name_prefix = "mysql-cluster-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "mysql-cluster-sg"
  }
}

# RDS monitoring role
resource "aws_iam_role" "rds_monitoring" {
  name = "rds-monitoring-role-mysql"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "monitoring.rds.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_monitoring" {
  role       = aws_iam_role.rds_monitoring.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"
}

# Parameter groups
resource "aws_db_parameter_group" "mysql" {
  name   = "mysql-cluster-params"
  family = "mysql8.0"

  parameter {
    name  = "character_set_server"
    value = "utf8mb4"
  }

  parameter {
    name  = "collation_server"
    value = "utf8mb4_unicode_ci"
  }

  tags = {
    Name = "mysql-cluster-params"
  }
}

resource "aws_rds_cluster_parameter_group" "mysql" {
  name   = "mysql-cluster-cluster-params"
  family = "mysql8.0"

  parameter {
    name  = "binlog_format"
    value = "ROW"
  }

  tags = {
    Name = "mysql-cluster-cluster-params"
  }
}

