terraform {
  required_version = ">= 1.0"
  required_providers {
    google = {
      source  = "hashicorp/google"
      version = "~> 5.0"
    }
  }
}

provider "google" {
  project = var.project_id
  region  = var.region
}

variable "project_id" {
  description = "The GCP project ID"
  type        = string
  default     = "your-project-id"
}

variable "region" {
  description = "The GCP region"
  type        = string
  default     = "us-central1"
}

# VPC and Subnet for the PostgreSQL instance
resource "google_compute_network" "postgres_vpc" {
  name                    = "postgres-vpc"
  auto_create_subnetworks = false
}

resource "google_compute_subnetwork" "postgres_subnet" {
  name                     = "postgres-subnet"
  ip_cidr_range            = "10.0.0.0/24"
  network                  = google_compute_network.postgres_vpc.id
  region                   = var.region
  private_ip_google_access = true
}

# Private Service Access for Cloud SQL
resource "google_compute_global_address" "private_ip_allocator" {
  name          = "postgres-private-ip-allocator"
  purpose       = "VPC_PEERING"
  address_type  = "INTERNAL"
  prefix_length = 16
  network       = google_compute_network.postgres_vpc.id
}

resource "google_service_networking_connection" "postgres_vpc_connection" {
  network                 = google_compute_network.postgres_vpc.id
  service                 = "servicenetworking.googleapis.com"
  reserved_peering_ranges = [google_compute_global_address.private_ip_allocator.name]
}

# Cloud SQL PostgreSQL Instance
resource "google_sql_database_instance" "postgres" {
  name             = "postgres-instance"
  database_version = "POSTGRES_15"
  region           = var.region
  deletion_protection = false

  settings {
    tier = "db-f1-micro"  # Use db-f1-micro for testing, upgrade for production

    ip_configuration {
      ipv4_enabled    = false
      private_network = google_compute_network.postgres_vpc.id
    }

    availability_type = "ZONAL"
    disk_autoresize   = true
    disk_size         = "10"
    disk_type         = "PD_SSD"

    maintenance_window {
      day  = 7
      hour = 3
    }

    backup_configuration {
      enabled                        = true
      location                       = var.region
      point_in_time_recovery_enabled = true
      start_time                     = "02:00"
    }
  }

  depends_on = [google_service_networking_connection.postgres_vpc_connection]
}

# Database within the instance
resource "google_sql_database" "postgres_db" {
  name     = "mydb"
  instance = google_sql_database_instance.postgres.name
}

# PostgreSQL user
resource "google_sql_user" "postgres_user" {
  name     = "postgresuser"
  instance = google_sql_database_instance.postgres.name
  password = "secure_password_123!"  # Change in production, use secrets manager
}

# Output the instance connection name
output "postgres_instance_connection_name" {
  value = google_sql_database_instance.postgres.connection_name
}

output "postgres_private_ip" {
  value = google_sql_database_instance.postgres.private_ip_address
}

