terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"
}

# VPC and subnets for DAX
resource "aws_vpc" "dax_vpc" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "dax-vpc"
  }
}

resource "aws_subnet" "dax_subnet_a" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "dax-subnet-a"
  }
}

resource "aws_subnet" "dax_subnet_b" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "dax-subnet-b"
  }
}

resource "aws_subnet" "dax_subnet_c" {
  vpc_id            = aws_vpc.dax_vpc.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-west-2c"
  tags = {
    Name = "dax-subnet-c"
  }
}

# Subnet group for DAX
resource "aws_dax_subnet_group" "dax_subnet_group" {
  name       = "dax-subnet-group"
  vpc_id     = aws_vpc.dax_vpc.id
  subnet_ids = [
    aws_subnet.dax_subnet_a.id,
    aws_subnet.dax_subnet_b.id,
    aws_subnet.dax_subnet_c.id
  ]
}

# Security group for DAX
resource "aws_security_group" "dax_sg" {
  name_prefix = "dax-sg-"
  vpc_id      = aws_vpc.dax_vpc.id

  ingress {
    from_port   = 8111
    to_port     = 8111
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "dax-security-group"
  }
}

# Parameter group for DAX
resource "aws_dax_parameter_group" "dax_param_group" {
  name = "dax-param-group"
  parameters {
    name  = "cluster-endpoint"
    value = "true"
  }
}

# DAX Cluster
resource "aws_dax_cluster" "dax_cluster" {
  cluster_name       = "my-dax-cluster"
  iam_role_arn       = aws_iam_role.dax_role.arn
  subnet_group_name  = aws_dax_subnet_group.dax_subnet_group.name
  security_group_ids = [aws_security_group.dax_sg.id]
  parameter_group_name = aws_dax_parameter_group.dax_param_group.name

  server_side_encryption {
    enabled = true
  }

  node_type     = "dax.t3.small"
  ram_size_gb   = 1.36
  nodes         = 3
}

# IAM Role for DAX
resource "aws_iam_role" "dax_role" {
  name = "dax-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dax.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dax_policy" {
  role       = aws_iam_role.dax_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDAXFullAccess"
}

# Output
output "dax_cluster_endpoint" {
  value = aws_dax_cluster.dax_cluster.cluster_endpoint
}

