}

resource "aws_dynamodb_table" "example" {
  name           = "example-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  ttl {
    attribute_name = "expirationTime"
    enabled        = true
  }

  tags = {
    Name = "example-table-with-ttl"
  }
}

# Usage example: To set TTL on an item, set 'expirationTime' to a Unix timestamp (seconds since epoch)
# e.g., current time + 30 days: 1735689600 (example value)
```

**Note:** Items with an `expirationTime` attribute containing a future Unix timestamp will be automatically deleted by DynamoDB after that time passes. Populate this attribute on your items to enable automatic expiration.

