terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC 1
resource "aws_vpc" "vpc1" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "vpc1"
  }
}

# VPC 2
resource "aws_vpc" "vpc2" {
  cidr_block           = "10.1.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "vpc2"
  }
}

# VPC Peering Connection
resource "aws_vpc_peering_connection" "vpc1_to_vpc2" {
  vpc_id        = aws_vpc.vpc1.id
  peer_vpc_id   = aws_vpc.vpc2.id
  auto_accept   = true

  tags = {
    Name = "vpc1-to-vpc2"
  }
}

# Route table for VPC1
resource "aws_route_table" "vpc1_rt" {
  vpc_id = aws_vpc.vpc1.id

  route {
    cidr_block                = "10.1.0.0/16"
    vpc_peering_connection_id = aws_vpc_peering_connection.vpc1_to_vpc2.id
  }

  tags = {
    Name = "vpc1-route-table"
  }
}

# Route table for VPC2
resource "aws_route_table" "vpc2_rt" {
  vpc_id = aws_vpc.vpc2.id

  route {
    cidr_block                = "10.0.0.0/16"
    vpc_peering_connection_id = aws_vpc_peering_connection.vpc1_to_vpc2.id
  }

  tags = {
    Name = "vpc2-route-table"
  }
}

# Default route table associations (assuming no subnets created, associating with main route tables)
resource "aws_main_route_table_association" "vpc1" {
  vpc_id         = aws_vpc.vpc1.id
  route_table_id = aws_route_table.vpc1_rt.id
}

resource "aws_main_route_table_association" "vpc2" {
  vpc_id         = aws_vpc.vpc2.id
  route_table_id = aws_route_table.vpc2_rt.id
}

