terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC for Neptune cluster
resource "aws_vpc" "neptune" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "neptune-vpc"
  }
}

# Subnets for Neptune cluster (must be in different AZs)
resource "aws_subnet" "neptune_a" {
  vpc_id            = aws_vpc.neptune.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-a"
  }
}

resource "aws_subnet" "neptune_b" {
  vpc_id            = aws_vpc.neptune.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-b"
  }
}

resource "aws_subnet" "neptune_c" {
  vpc_id            = aws_vpc.neptune.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"

  tags = {
    Name = "neptune-subnet-c"
  }
}

# Subnet group for Neptune
resource "aws_neptune_subnet_group" "neptune" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.neptune_a.id, aws_subnet.neptune_b.id, aws_subnet.neptune_c.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Custom parameter group for Neptune
resource "aws_neptune_parameter_group" "custom" {
  family = "neptune1"

  parameter {
    name  = "neptune_query_timeout"
    value = "60000"
  }

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = {
    Name = "custom-neptune-params"
  }
}

# Neptune cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier      = "neptune-cluster-basic"
  engine                  = "neptune"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  iam_database_authentication_enabled = true

  neptune_subnet_group_name   = aws_neptune_subnet_group.neptune.name
  neptune_parameter_group_name = aws_neptune_parameter_group.custom.name

  # Apply immediately for demo purposes
  apply_immediately = true

  tags = {
    Name = "neptune-cluster-basic"
  }
}

# Neptune cluster instance
resource "aws_neptune_cluster_instance" "cluster_instances" {
  count              = 2
  identifier         = "neptune-cluster-instance-${count.index}"
  cluster_identifier = aws_neptune_cluster.main.id
  instance_class     = "db.r6g.large"
  engine             = "neptune"

  tags = {
    Name = "neptune-instance-${count.index}"
  }
}

# Security group for Neptune
resource "aws_security_group" "neptune" {
  name_prefix = "neptune-sg-"
  vpc_id      = aws_vpc.neptune.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# Attach security group to cluster
resource "aws_neptune_cluster" "main_with_sg" {
  # Reference the existing cluster and override security group
  cluster_identifier                 = aws_neptune_cluster.main.cluster_identifier
  vpc_security_group_ids             = [aws_security_group.neptune.id]
  iam_database_authentication_enabled = true

  lifecycle {
    create_before_destroy = true
  }
}

output "neptune_cluster_endpoint" {
  description = "Neptune cluster endpoint"
  value       = aws_neptune_cluster.main.endpoint
}

output "neptune_reader_endpoint" {
  description = "Neptune reader endpoint"
  value       = aws_neptune_cluster.main.reader_endpoint
}

