  cidr_block = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.azs.names[1]
}
resource "aws_neptune_subnet_group" "default" {
  name       = "main"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
}

