```hcl
provider "aws" {
  region = "us-east-1"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "neptune-vpc"
  }
}

# Subnets
resource "aws_subnet" "example" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "example-subnet"
  }
}

# Subnet Group for Neptune
resource "aws_neptune_subnet_group" "main" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.example.id]
  tags = {
    Name = "neptune-subnet-group"
  }
}

# Custom Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "custom" {
  family = "neptune1"
  name   = "neptune-cluster-custom-pg"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = {
    Name = "neptune-cluster-custom-pg"
  }
}

# Custom Instance Parameter Group
resource "aws_neptune_parameter_group" "custom" {
  family = "neptune1"
  name   = "neptune-instance-custom-pg"

  parameter {
    name  = "neptune_query_timeout"
    value = "60000"
  }

  tags = {
    Name = "neptune-instance-custom-pg"
  }
}

# Security Group - only allows connections from the example subnet
resource "aws_security_group" "neptune_sg" {
  name_prefix = "neptune-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port       = 8182
    to_port         = 8182
    protocol        = "tcp"
    cidr_blocks     = [aws_subnet.example.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# Neptune Cluster
resource "aws_neptune_cluster" "main" {
  cluster_identifier      = "neptune-cluster"
  engine                  = "neptune"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  iam_database_authentication_enabled = true

  neptune_subnet_group_name   = aws_neptune_subnet_group.main.name
  vpc_security_group_ids      = [aws_security_group.neptune_sg.id]
  neptune_cluster_parameter_group_name = aws_neptune_cluster_parameter_group.custom.name

  tags = {
    Name = "neptune-cluster"
  }
}

# Neptune Cluster Instance
resource "aws_neptune_cluster_instance" "main" {
  count              = 1
  identifier         = "neptune-instance"
  cluster_identifier = aws_neptune_cluster.main.id
  instance_class     = "db.r5.large"
  engine             = "neptune"
  preferred_maintenance_window = "Sun:23:00-Sun:23:30"

  neptune_parameter_group_name = aws_neptune_parameter_group.custom.name

  tags = {
    Name = "neptune-instance"
  }
}

# Output the cluster endpoint
output "neptune_cluster_endpoint" {
  description = "Neptune cluster endpoint"
  value       = aws_neptune_cluster.main.endpoint
}

output "neptune_reader_endpoint" {
  description = "Neptune reader endpoint"
  value       = aws_neptune_cluster.main.reader_endpoint
}
```

