resource "aws_kinesis_stream" "chime_media_stream" {
  name             = "chime-media-stream"
  shard_count      = 1
  retention_period = 24

  shard_level_metrics = [
    "IncomingBytes",
    "OutgoingBytes",
  ]

  tags = {
    Name = "ChimeVoiceConnectorMediaStream"
  }
}

# Create AWS Chime Voice Connector
resource "aws_chime_voice_connector" "main" {
  name               = "my-voice-connector"
  require_encryption = true

  tags = {
    Name = "MyVoiceConnector"
  }
}

# Create Voice Connector streaming configuration for media streaming to Kinesis
resource "aws_chime_voice_connector_streaming" "media_streaming" {
  voice_connector_id = aws_chime_voice_connector.main.id

  streaming_notification_targets {
    sns_topic = aws_sns_topic.chime_streaming_events.arn
  }

  media_streaming_configuration {
    disabled = false
    kinesis_video_stream_configuration {
      data_retention_in_hours = 24
    }
  }

  depends_on = [aws_kinesis_stream.chime_media_stream]
}

# SNS topic for streaming notification events
resource "aws_sns_topic" "chime_streaming_events" {
  name = "chime-voice-connector-streaming-events"
}

# Optional: Subscribe to SNS topic for notifications (e.g., Lambda or email)
resource "aws_sns_topic_subscription" "events_subscription" {
  topic_arn = aws_sns_topic.chime_streaming_events.arn
  protocol  = "email"
  endpoint  = "your-email@example.com"
}

