resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id]
  tags = {
    Name = "redshift-subnet-group"
  }
}

# Redshift Security Group allowing access from the subnets
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # VPC CIDR - adjust as needed
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Parameter Group (optional, using defaults)
resource "aws_redshift_parameter_group" "redshift_pg" {
  name   = "redshift-param-group"
  family = "redshift-1.0"

  parameter {
    name  = "require_ssl"
    value = "true"
  }
}

# Redshift Cluster with endpoint access from the two subnets
resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier      = "redshift-cluster"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "SuperSecurePassword123!"  # Use secrets manager in production
  node_type               = "dc2.large"
