provider "aws" {
  region = "us-west-2"
}

# SNS Topic for Redshift event notifications
resource "aws_sns_topic" "redshift_events" {
  name = "redshift-events-topic"
}

# Subscribe an email endpoint to the SNS topic (replace with your email)
resource "aws_sns_topic_subscription" "redshift_events_email" {
  topic_arn = aws_sns_topic.redshift_events.arn
  protocol  = "email"
  endpoint  = "your-email@example.com"
}

# IAM role for Redshift to publish to SNS
resource "aws_iam_role" "redshift_sns_role" {
  name = "redshift-sns-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy to allow Redshift to publish to SNS
resource "aws_iam_role_policy" "redshift_sns_policy" {
  name = "redshift-sns-policy"
  role = aws_iam_role.redshift_sns_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "sns:Publish"
        ]
        Resource = aws_sns_topic.redshift_events.arn
      }
    ]
  })
}

# Redshift Security Group
resource "aws_security_group" "redshift_sg" {
  name_prefix = "redshift-"
  vpc_id      = "vpc-12345678"  # Replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Replace with your CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redshift-sg"
  }
}

# Redshift Subnet Group (replace subnet IDs with your own)
resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "redshift-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"]  # Replace with your subnet IDs

  tags = {
    Name = "redshift-subnet-group"
  }
}

# Redshift Cluster with event notifications
resource "aws_redshift_cluster" "main" {
  cluster_identifier     = "redshift-cluster-1"
  database_name          = "mydb"
  master_username        = "admin"
  master_password        = "SuperSecurePassword123!"
  node_type              = "dc2.large"
  cluster_type           = "single-node"
  cluster_subnet_group_name = aws_redshift_subnet_group.redshift_subnet_group.name

  vpc_security_group_ids = [aws_security_group.redshift_sg.id]

  # Event notifications
  event_subscriptions {
    name               = "redshift-events-subscription"
    sns_topic_arn      = aws_sns_topic.redshift_events.arn
    source_type        = "cluster"
    source_ids         = [self.id]
    event_categories   = ["availability", "deletion", "low_storage", "maintenance", "restoration"]
    enabled            = true
  }

  # IAM role attachment for SNS
  iam_roles = [aws_iam_role.redshift_sns_role.arn]

  skip_final_snapshot = true

  tags = {
    Name = "redshift-cluster"
  }
}

# Confirm SNS subscription (optional, for email subscriptions)
resource "null_resource" "confirm_sns_subscription" {
  provisioner "local-exec" {
    command = "aws sns confirm-subscription --topic-arn ${aws_sns_topic.redshift_events.arn} --token ${data.aws_sns_topic_subscription.redshift_events_email.confirmation_token} --authenticate-on-minimize"
  }

  depends_on = [aws_sns_topic_subscription.redshift_events_email]
}

data "aws_sns_topic_subscription" "redshift_events_email" {
  topic_arn = aws_sns_topic.redshift_events.arn
  subscription_arn = aws_sns_topic_subscription.redshift_events_email.arn
}

