provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# S3 bucket for storing images
resource "aws_s3_bucket" "website_images" {
  bucket = "my-website-images-bucket-unique"  # Must be globally unique - replace with your own name
}

# Enable versioning
resource "aws_s3_bucket_versioning" "website_images" {
  bucket = aws_s3_bucket.website_images.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Bucket policy for public read access (required for website display)
resource "aws_s3_bucket_policy" "website_images_public" {
  bucket = aws_s3_bucket.website_images.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.website_images.arn}/*"
      },
    ]
  })
}

# Enable static website hosting (optional but recommended for direct access)
resource "aws_s3_bucket_website_configuration" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# Output the bucket endpoint for website access
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.website_images.website_endpoint
}

# Output the bucket name
output "bucket_name" {
  value = aws_s3_bucket.website_images.bucket
}

response:
```hcl
provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# S3 bucket for storing images
resource "aws_s3_bucket" "website_images" {
  bucket = "my-website-images-bucket-unique"  # Must be globally unique - replace with your own name
}

# Enable versioning
resource "aws_s3_bucket_versioning" "website_images" {
  bucket = aws_s3_bucket.website_images.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Bucket policy for public read access (required for website display)
resource "aws_s3_bucket_policy" "website_images_public" {
  bucket = aws_s3_bucket.website_images.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.website_images.arn}/*"
      },
    ]
  })
}

# Enable static website hosting (optional but recommended for direct access)
resource "aws_s3_bucket_website_configuration" "website_images" {
  bucket = aws_s3_bucket.website_images.id

  index_document {
    suffix = "index.html"
  }

  error_document {
    key = "error.html"
  }
}

# Output the bucket endpoint for website access
output "website_endpoint" {
  value = aws_s3_bucket_website_configuration.website_images.website_endpoint
}

# Output the bucket name
output "bucket_name" {
  value = aws_s3_bucket.website_images.bucket
}
```

**Note:** Replace `my-website-images-bucket-unique` with a globally unique bucket name. Upload your images to this bucket and they'll be publicly accessible via the website endpoint for display on your site.

