    data_aggregate_storage_class {
      storage_class {
        id = "STANDARD"
      }
    }
  }
}

resource "aws_s3_bucket" "results_bucket" {
  bucket = "mybucket-results"
}

resource "aws_s3_bucket_analytics_configuration" "example" {
  bucket                = aws_s3_bucket.analytics_bucket.id
  name                  = "entire-bucket"
  storage_class_analysis {
    data_aggregate_storage_class {
      storage_class {
        id = "STANDARD"
      }
    }
  }

  storage_class_analysis_data_export {
    destination {
      s3_bucket {
        bucket_account_id = data.aws_caller_identity.current.account_id
        bucket            = aws_s3_bucket.results_bucket.id
        prefix            = "analytics"
        format {
          csv = true
        }
      }
    }
  }

  depends_on = [aws_s3_bucket_public_access_block.results_bucket]
}

data "aws_caller_identity" "current" {}

resource "aws_s3_bucket_public_access_block" "results_bucket" {
  bucket = aws_s3_bucket.results_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_ownership_controls" "results_bucket" {
  bucket = aws_s3_bucket.results_bucket.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}
