terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
}

resource "aws_s3_bucket_inventory" "daily_inventory" {
  bucket = aws_s3_bucket.mybucket.id
  name   = "daily-inventory"

  inventory_configuration {
    id             = "daily-inventory"
    destination {
      bucket {
        name = aws_s3_bucket.mybucket.id  # Inventory reports stored in same bucket
        account_id = data.aws_caller_identity.current.account_id
      }
      format = "CSV"
    }
    is_enabled = true
    schedule {
      frequency = "Daily"
    }
    included_object_versions = "All"
  }

  depends_on = [aws_s3_bucket.mybucket]
}

# Bucket policy to allow inventory delivery
resource "aws_s3_bucket_policy" "inventory_policy" {
  bucket = aws_s3_bucket.mybucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "InventoryDelivery"
        Effect    = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "s3:PutObject"
        Resource  = "${aws_s3_bucket.mybucket.arn}/inventory/*"
        Condition = {
          StringEquals = {
            "s3:x-amz-acl" = "bucket-owner-full-control"
          }
        }
      }
    ]
  })
}

# Data source for current account ID
data "aws_caller_identity" "current" {}

