  bucket = aws_s3_bucket.main_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Inventory destination bucket
resource "aws_s3_bucket" "inventory_bucket" {
  bucket = "my-inventory-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_versioning" "inventory_bucket_versioning" {
  bucket = aws_s3_bucket.inventory_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Bucket policy for inventory bucket to allow main bucket to write inventory
resource "aws_s3_bucket_policy" "inventory_bucket_policy" {
  bucket = aws_s3_bucket.inventory_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowMainBucketToWriteInventory"
        Effect    = "Allow"
        Principal = {
          AWS = aws_iam_role.inventory_role.arn
        }
        Action   = "s3:PutObject"
        Resource = "${aws_s3_bucket.inventory_bucket.arn}/inventory/main-bucket/*"
      }
    ]
  })
}

# IAM role for S3 inventory
resource "aws_iam_role" "inventory_role" {
  name = "s3-inventory-role-${random_string.bucket_suffix.result}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for inventory role
