terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Object Lock requires US East (N. Virginia) or another supported region
}

# Create S3 bucket with object lock enabled
resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
}

# Enable object lock on the bucket
resource "aws_s3_bucket_object_lock_configuration" "mybucket" {
  bucket = aws_s3_bucket.mybucket.id

  rule {
    default_retention {
      mode  = "GOVERNANCE"
      days  = 365
    }
  }
}

# Bucket versioning must be enabled for object lock
resource "aws_s3_bucket_versioning" "mybucket" {
  bucket = aws_s3_bucket.mybucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

