provider "aws" {
  region = "us-east-1"
}

# S3 bucket for CodeBuild artifacts (autograder results)
resource "aws_s3_bucket" "autograder_results" {
  bucket = "cs-autograder-results-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "cs-autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# IAM policy for CodeBuild (S3 access, CloudWatch logs, GitHub access)
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = "${aws_s3_bucket.autograder_results.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      }
    ]
  })
}

# CodeBuild project for autograder
resource "aws_codebuild_project" "cs_autograder" {
  name          = "cs-autograder"
  description   = "Autograder for CS class - runs student GitHub code"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    name = "autograder-artifacts"
    location = aws_s3_bucket.autograder_results.bucket
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false

    environment_variable {
      name  = "GITHUB_REPO"
      value = "https://github.com/your-org/student-submissions" # Replace with actual student repo
    }

    environment_variable {
      name  = "TEST_RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/student-submissions.git" # Replace with actual repo
    buildspec = "buildspec.yml"
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograder"
      stream_name = "autograder-logs"
    }
  }

  depends_on = [aws_iam_role_policy.codebuild_policy]
}

# Data source for current account ID
data "aws_caller_identity" "current" {}

# Optional: CloudWatch Events rule to trigger autograder on GitHub push
resource "aws_cloudwatch_event_rule" "github_push_trigger" {
  name        = "cs-autograder-github-trigger"
  description = "Trigger autograder on student code push"

  event_pattern = jsonencode({
    source      = ["aws.codecommit"] # Note: Use CodeCommit webhook or GitHub App webhook for production
    detail-type = ["CodeCommit Repository State Change"]
    detail = {
      referenceName = ["refs/heads/main"]
      repositoryName = ["student-submissions"]
    }
  })
}

resource "aws_cloudwatch_event_target" "autograder_target" {
  rule      = aws_cloudwatch_event_rule.github_push_trigger.name
  target_id = "cs-autograder-target"
  arn       = aws_codebuild_project.cs_autograder.arn

  role_arn = aws_iam_role.codebuild_role.arn
}

# Sample buildspec.yml content (this would be in your GitHub repo)
# Note: Upload this buildspec.yml to your GitHub repository root
/*
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
    commands:
      - pip install pytest coverage

  pre_build:
    commands:
      - echo Cloning student submissions...
      - git clone $GITHUB_REPO ./student-code
      - cd student-code

  build:
    commands:
      - echo Running autograder tests...
      - pytest tests/ --junitxml=test-results.xml --cov=src
      - coverage xml -o coverage.xml

  post_build:
    commands:
      - echo Uploading results...
      - aws s3 cp test-results.xml s3://$TEST_RESULTS_BUCKET/$(date +%Y%m%d-%H%M%S)-results.xml
      - aws s3 cp coverage.xml s3://$TEST_RESULTS_BUCKET/$(date +%Y%m%d-%H%M%S)-coverage.xml
*/

# Output important values
output "autograder_results_bucket" {
  value = aws_s3_bucket.autograder_results.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.cs_autograder.name
}

output "codebuild_project_arn" {
  value = aws_codebuild_project.cs_autograder.arn
}

