**Required `buildspec.yml` file** (create this file in your Terraform directory):

```yaml
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
      nodejs: 18
    commands:
      - echo "Installing dependencies..."
      - pip install pytest coverage flake8

  pre_build:
    commands:
      - echo "Preparing student submission..."
      - STUDENT_ID=${STUDENT_ID:-"test_student"}
      - ASSIGNMENT_ID=${ASSIGNMENT_ID:-"hw1"}
      - SUBMISSION_KEY="submissions/${STUDENT_ID}/${ASSIGNMENT_ID}.zip"
      - RESULTS_KEY="results/${STUDENT_ID}/${ASSIGNMENT_ID}.json"
      - |
        if [ -f "$SUBMISSION_KEY" ]; then
          echo "Found submission, unzipping..."
          unzip -q $SUBMISSION_KEY -d ./student_code/
        else
          echo "No submission found, creating test file"
          mkdir -p student_code
          echo "print('Test passed')" > student_code/test.py
        fi

  build:
    commands:
      - echo "Running autograder tests..."
      - cd student_code
      - pytest tests/ --junitxml=results.xml --verbose || true
      - coverage run --source=. -m pytest || true
      - coverage xml -o coverage.xml
      - flake8 . --format=json --output-file=flake8.json || true

      - |
        cat > ../results.json << EOF
        {
          "student_id": "$STUDENT_ID",
          "assignment_id": "$ASSIGNMENT_ID",
          "pytest_passed": $(pytest tests/ -q --collect-only | grep -c "collected 0 items" || echo "false"),
          "coverage_percent": $(coverage report | tail -1 | awk '{print $NF}' | sed 's/%//'),
          "flake8_issues": $([ -f flake8.json ] && jq '. | length' flake8.json || echo 0),
          "timestamp": "$(date -u +%Y-%m-%dT%H:%M:%SZ)"
        }
        EOF

  post_build:
    commands:
      - echo "Uploading results to S3..."
      - aws s3 cp results.json s3://$S3_BUCKET/$RESULTS_KEY
      - aws s3 cp results.xml s3://$S3_BUCKET/results/${STUDENT_ID}/${ASSIGNMENT_ID}_pytest.xml
      - aws s3 cp coverage.xml s3://$S3_BUCKET/results/${STUDENT_ID}/${ASSIGNMENT_ID}_coverage.xml 2>/dev/null || true
      - echo "Autograding complete!"
```

**Usage:**
1. Apply Terraform: `terraform init && terraform apply`
2. Upload student submissions as ZIP files to `s3://<bucket>/submissions/{student_id}/{assignment_id}.zip`
3. Start CodeBuild manually or via API/Lambda with env vars `STUDENT_ID` and `ASSIGNMENT_ID`
4. Results stored in `s3://<bucket>/results/{student_id}/{assignment_id}.json`

