```hcl
provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for storing autograder results and artifacts
resource "aws_s3_bucket" "autograder_results" {
  bucket = "cs-autograder-results-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_ownership_controls" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "autograder_results" {
  depends_on = [aws_s3_bucket_ownership_controls.autograder_results]

  bucket = aws_s3_bucket.autograder_results.id
  acl    = "private"
}

resource "aws_s3_bucket_versioning" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_results" {
  bucket = aws_s3_bucket.autograder_results.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for CodeBuild access to S3 and CloudWatch Logs
resource "aws_iam_role_policy" "codebuild_policy" {
  name = "autograder-codebuild-policy"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:GetObjectVersion",
          "s3:GetBucketVersioning",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.autograder_results.arn,
          "${aws_s3_bucket.autograder_results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

data "aws_region" "current" {}

# CodeBuild Service Role attachment
resource "aws_iam_role_policy_attachment" "codebuild_service_role" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/CodeBuildServiceRolePolicy"
}

# CodeBuild Project for autograder
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder for CS class - runs student GitHub code and stores results"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 30

  artifacts {
    type = "CODEPIPELINE"  # Can be changed to S3 if not using CodePipeline
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "S3_RESULTS_BUCKET"
      value = aws_s3_bucket.autograder_results.bucket
    }

    environment_variable {
      name  = "STUDENT_REPO"
      value = "https://github.com/student-org/student-repo.git"  # Replace with actual student repo
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/cs-class-autograder.git"  # Main autograder repo
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograder"
      stream_name = "autograder-builds"
    }
  }

  depends_on = [aws_iam_role_policy_attachment.codebuild_service_role]
}

# Optional: S3 bucket policy to allow CodeBuild access (already covered in IAM)
resource "aws_s3_bucket_policy" "autograder_results_policy" {
  bucket = aws_s3_bucket.autograder_results.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "CodeBuildAccess"
        Effect    = "Allow"
        Principal = {
          AWS = aws_iam_role.codebuild_role.arn
        }
        Action   = ["s3:PutObject", "s3:GetObject"]
        Resource = "${aws_s3_bucket.autograder_results.arn}/*"
      }
    ]
  })
}

# Output important values
output "s3_bucket_name" {
  value       = aws_s3_bucket.autograder_results.bucket
  description = "Name of the S3 bucket for autograder results"
}

output "codebuild_project_name" {
  value       = aws_codebuild_project.autograder.name
  description = "Name of the CodeBuild project"
}

output "codebuild_role_arn" {
  value       = aws_iam_role.codebuild_role.arn
  description = "ARN of the CodeBuild service role"
}
```

This configuration creates:

1. **Secure S3 bucket** with versioning, encryption, and proper access controls for storing autograder results
2. **IAM role and policies** for CodeBuild with permissions for S3, CloudWatch Logs, and GitHub source
3. **CodeBuild project** configured to:
   - Pull autograder code from GitHub
   - Run in a Linux container with student repo URL as environment variable
   - Store results in the S3 bucket
   - Log to CloudWatch

**To use:**
1. Replace GitHub URLs with your actual repositories
2. Customize `buildspec.yml` in your GitHub repo to:
   - Clone student repo
   - Run tests/grading logic
   - Upload results to S3 using `S3_RESULTS_BUCKET` env var
3. Trigger builds manually via AWS Console/CLI or set up GitHub webhook/CodePipeline

