  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false  # No Docker privileges for security

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder_bucket.bucket
    }
  }

  source {
    type = "GITHUB"
    # Configure GitHub source with OAuth token via environment variable or separate source credential
