}

# Public subnet for NAT
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.autograder_vpc.id
  cidr_block              = "10.0.0.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true

  tags = {
    Name = "autograder-public-subnet"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-igw"
  }
}

# Public route table
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }

  tags = {
    Name = "autograder-public-rt"
  }
}

resource "aws_route_table_association" "public_rta" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# Private route table with NAT
resource "aws_route_table" "private_rt" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat_gateway.id
  }

  tags = {
    Name = "autograder-private-rt"
  }
}

resource "aws_route_table_association" "private_rta" {
  subnet_id      = aws_subnet.private_subnet.id
  route_table_id = aws_route_table.private_rt.id
}

# Security Group for CodeBuild - outbound only to GitHub and AWS services
resource "aws_security_group" "codebuild_sg" {
  name_prefix = "autograder-codebuild-"
  vpc_id      = aws_vpc.autograder_vpc.id

  # No inbound traffic
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }

  # Outbound to GitHub (HTTPS), AWS S3, CodeBuild service
  egress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "HTTPS outbound"
  }

  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
    description = "HTTP outbound"
  }

  tags = {
    Name = "autograder-codebuild-sg"
  }
}

# S3 Bucket for source code and results (private)
resource "aws_s3_bucket" "autograder_bucket" {
  bucket = "cs-autograder-${random_string.bucket_suffix.result}"

  tags = {
    Name = "autograder-bucket"
  }
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_versioning" "autograder_versioning" {
  bucket = aws_s3_bucket.autograder_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "autograder_encryption" {
  bucket = aws_s3_bucket.autograder_bucket.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_public_access_block" "autograder_block_public_access" {
  bucket = aws_s3_bucket.autograder_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy" "codebuild_s3_policy" {
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetObjectVersion"
        ]
        Resource = "${aws_s3_bucket.autograder_bucket.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = aws_s3_bucket.autograder_bucket.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:us-east-1:*:log-group:/aws/codebuild/*"
      }
    ]
  })
}

# CodeBuild Project
resource "aws_codebuild_project" "autograder" {
  name          = "cs-autograder"
  description   = "Autograder for CS class - runs student GitHub code in isolated environment"
  service_role  = aws_iam_role.codebuild_role.arn
  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/standard:7.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = false  # No Docker privileges for security

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.autograder_bucket.bucket
    }
  }

  source {
    type = "GITHUB"
    # Configure GitHub source with OAuth token via environment variable or separate source credential
    git_clone_depth = 1
  }

  artifacts {
    type = "S3"
    name = "autograder-artifacts"
    location = aws_s3_bucket.autograder_bucket.bucket
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnet_ids         = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  # Sample buildspec - customize per class needs
  buildspec = <<EOF
version: 0.2

phases:
  install:
    runtime-versions:
      python: 3.9
      java: corretto17
      nodejs: 18
  pre_build:
    commands:
      - echo "Setting up isolated test environment"
      - echo "No network access beyond AWS services allowed"
  build:
    commands:
      - echo "Downloading student submission from GitHub"
      - echo "Running tests in isolated environment"
      - python -m pytest tests/ -v --junitxml=results.xml || true
      - echo "Test results:"
      - cat results.xml
  post_build:
    commands:
      - echo "Uploading results to S3"
      - aws s3 cp results.xml s3://$S3_BUCKET/$(date +%Y%m%d_%H%M%S)_results.xml
      - aws s3 cp test-results/ s3://$S3_BUCKET/results/$(date +%Y%m%d_%H%M%S)/ --recursive
artifacts:
  files:
    - results.xml
    - '**/*'
EOF
}

# Output important values
output "s3_bucket_name" {
  value = aws_s3_bucket.autograder_bucket.bucket
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  value = aws_vpc.autograder_vpc.id
}
```

This configuration creates a completely isolated autograder environment:

**Key Security Features:**
- Private subnet with no inbound internet access
- NAT gateway allows **only** outbound GitHub/S3 access (no student code can reach internet)
- Restrictive security group (HTTPS outbound only)
- No Docker privileged mode
- Encrypted/private S3 bucket
- VPC isolation from public internet

**Workflow:**
1. Trigger CodeBuild with GitHub student submission URL
2. CodeBuild fetches code via GitHub (only outbound HTTPS)
3. Runs tests in isolated VPC environment
4. Stores results in private S3 bucket
5. **Student code cannot access internet** due to VPC/SG restrictions

**To use:**
1. `terraform apply`
2. Configure GitHub source credentials in CodeBuild
3. Trigger builds with student GitHub repo URLs
4. Results stored in S3 bucket

