provider "aws" {
  region = "us-east-1"
}

# S3 bucket for storing cat pictures
resource "aws_s3_bucket" "cat_pics" {
  bucket = "my-cat-pics-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_ownership_controls" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_pics" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_pics]

  bucket = aws_s3_bucket.cat_pics.id
  acl    = "private"
}

# Enable versioning
resource "aws_s3_bucket_versioning" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CORS configuration for API Gateway
resource "aws_s3_bucket_cors_configuration" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET", "PUT", "POST"]
    allowed_origins = ["*"]
    expose_headers  = ["ETag"]
    max_age_seconds = 3000
  }
}

# IAM role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "catpics-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Lambda to access S3
resource "aws_iam_role_policy" "lambda_s3_policy" {
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_pics.arn,
          "${aws_s3_bucket.cat_pics.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lambda function for handling requests
resource "aws_lambda_function" "catpics_handler" {
  filename         = "catpics_handler.zip"
  function_name    = "catpics-handler"
  role            = aws_iam_role.lambda_role.arn
  handler         = "catpics_handler.lambda_handler"
  runtime         = "python3.9"
  source_code_hash = filebase64sha256("catpics_handler.zip")

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pics.bucket
    }
  }
}

