# API Gateway REST API
resource "aws_api_gateway_rest_api" "catpics_api" {
  name        = "CatPicsAPI"
  description = "API for uploading and getting random cat pictures"
}

# /upload resource
resource "aws_api_gateway_resource" "upload" {
  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
  parent_id   = aws_api_gateway_rest_api.catpics_api.root_resource_id
  path_part   = "upload"
}

# /random resource
resource "aws_api_gateway_resource" "random" {
  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
  parent_id   = aws_api_gateway_rest_api.catpics_api.root_resource_id
  path_part   = "random"
}

# POST method for /upload
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.catpics_api.id
  resource_id   = aws_api_gateway_resource.upload.id
  http_method   = "POST"
  authorization = "NONE"
}

# GET method for /random
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.catpics_api.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "GET"
  authorization = "NONE"
}

# OPTIONS method for CORS - upload
resource "aws_api_gateway_method" "upload_options" {
  rest_api_id   = aws_api_gateway_rest_api.catpics_api.id
  resource_id   = aws_api_gateway_resource.upload.id
  http_method   = "OPTIONS"
  authorization = "NONE"
}

# OPTIONS method for CORS - random
resource "aws_api_gateway_method" "random_options" {
  rest_api_id   = aws_api_gateway_rest_api.catpics_api.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "OPTIONS"
  authorization = "NONE"
}

# Lambda integration for POST /upload
resource "aws_api_gateway_integration" "upload_post_integration" {
  rest_api_id             = aws_api_gateway_rest_api.catpics_api.id
  resource_id             = aws_api_gateway_resource.upload.id
  http_method             = aws_api_gateway_method.upload_post.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.catpics_handler.invoke_arn
}

# Lambda integration for GET /random
resource "aws_api_gateway_integration" "random_get_integration" {
  rest_api_id             = aws_api_gateway_rest_api.catpics_api.id
  resource_id             = aws_api_gateway_resource.random.id
  http_method             = aws_api_gateway_method.random_get.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.catpics_handler.invoke_arn
}

# CORS OPTIONS integration for upload
resource "aws_api_gateway_integration" "upload_options_integration" {
  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
  resource_id = aws_api_gateway_resource.upload.id
  http_method = aws_api_gateway_method.upload_options.http_method

  type = "MOCK"

  request_templates = {
    "application/json" = "{"statusCode": 200}"
  }
}

# CORS OPTIONS integration for random
resource "aws_api_gateway_integration" "random_options_integration" {
  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_options.http_method

  type = "MOCK"

  request_templates = {
    "application/json" = "{"statusCode": 200}"
  }
}

# Lambda permission for API Gateway
resource "aws_lambda_permission" "api_gateway" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.catpics_handler.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.catpics_api.execution_arn}/*/*"
}

# API Gateway deployment
resource "aws_api_gateway_deployment" "catpics_deployment" {
  depends_on = [
    aws_api_gateway_integration.upload_post_integration,
    aws_api_gateway_integration.random_get_integration,
    aws_api_gateway_integration.upload_options_integration,
    aws_api_gateway_integration.random_options_integration,
  ]

  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
  stage_name  = "prod"
}

# CORS headers
resource "aws_api_gateway_method_response" "upload_post_200" {
  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
  resource_id = aws_api_gateway_resource.upload.id
  http_method = aws_api_gateway_method.upload_post.http_method
  status_code = "200"
  response_parameters = {
    "method.response.header.Access-Control-Allow-Headers" = true
    "method.response.header.Access-Control-Allow-Methods" = true
    "method.response.header.Access-Control-Allow-Origin"  = true
  }
}

resource "aws_api_gateway_method_response" "random_get_200" {
  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method
  status_code = "200"
  response_parameters = {
    "method.response.header.Access-Control-Allow-Headers" = true
    "method.response.header.Access-Control-Allow-Methods" = true
    "method.response.header.Access-Control-Allow-Origin"  = true
  }
}

resource "aws_api_gateway_method_response" "upload_options_200" {
  rest_api_id = aws_api_gateway_rest_api.catpics_api.id
