provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for storing cat pictures
resource "aws_s3_bucket" "cat_pics" {
  bucket = "cat-pics-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_ownership_controls" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_pics" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_pics]

  bucket = aws_s3_bucket.cat_pics.id
  acl    = "private"
}

resource "aws_s3_bucket_public_access_block" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# IAM Role for Lambda
resource "aws_iam_role" "lambda_role" {
  name = "cat-service-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy_attachment" "lambda_s3" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

# Lambda for uploading cat pictures
resource "aws_lambda_function" "upload_cat" {
  filename         = "upload_cat.zip"
  function_name    = "upload-cat"
  role             = aws_iam_role.lambda_role.arn
  handler          = "upload_cat.lambda_handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("upload_cat.zip")

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pics.bucket
    }
  }
}

# Lambda for getting random cat picture
resource "aws_lambda_function" "get_random_cat" {
  filename         = "get_random_cat.zip"
  function_name    = "get-random-cat"
  role             = aws_iam_role.lambda_role.arn
  handler          = "get_random_cat.lambda_handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("get_random_cat.zip")

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_pics.bucket
    }
  }
}

# API Gateway
resource "aws_apigatewayv2_api" "cat_api" {
  name          = "cat-api"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_stage" "default" {
  api_id      = aws_apigatewayv2_api.cat_api.id
  name        = "$default"
  auto_deploy = true

  access_log_settings {
    destination_arn = aws_cloudwatch_log_group.api_logs.arn

    format = jsonencode({
      requestId               = "$context.requestId"
      sourceIp                = "$context.identity.sourceIp"
      requestTime             = "$context.requestTime"
      protocol                = "$context.protocol"
      httpMethod              = "$context.httpMethod"
      resourcePath            = "$context.resourcePath"
      routeKey                = "$context.routeKey"
      status                  = "$context.status"
      responseLength          = "$context.responseLength"
      integrationErrorMessage = "$context.integrationErrorMessage"
    })
  }
}

resource "aws_cloudwatch_log_group" "api_logs" {
  name = "/aws/apigateway/${aws_apigatewayv2_api.cat_api.name}/default"
}

# API Gateway Integration for upload
resource "aws_apigatewayv2_integration" "upload_integration" {
  api_id             = aws_apigatewayv2_api.cat_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.upload_cat.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_route" "upload_route" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "POST /upload"
  target    = "integrations/${aws_apigatewayv2_integration.upload_integration.id}"
}

# API Gateway Integration for random cat
resource "aws_apigatewayv2_integration" "random_integration" {
  api_id             = aws_apigatewayv2_api.cat_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.get_random_cat.invoke_arn
  integration_method = "GET"
}

resource "aws_apigatewayv2_route" "random_route" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "GET /random"
  target    = "integrations/${aws_apigatewayv2_integration.random_integration.id}"
}

# Lambda Permissions
resource "aws_lambda_permission" "upload_api" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_api.execution_arn}/*/*"
}

resource "aws_lambda_permission" "random_api" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_random_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.cat_api.execution_arn}/*/*"
}

# CORS for API Gateway
resource "aws_apigatewayv2_route" "options_upload" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "OPTIONS /upload"
  target    = "integrations/${aws_apigatewayv2_integration.cors_integration.id}"
}

resource "aws_apigatewayv2_route" "options_random" {
  api_id    = aws_apigatewayv2_api.cat_api.id
  route_key = "OPTIONS /random"
  target    = "integrations/${aws_apigatewayv2_integration.cors_integration.id}"
}

resource "aws_apigatewayv2_integration" "cors_integration" {
