**Note:** This configuration assumes you will create the Lambda deployment packages (`upload_cat.zip` and `get_random_cat.zip`) separately. Here are the sample Python Lambda functions needed:

**upload_cat.py:**
```python
import json
import boto3
import uuid
from urllib.parse import parse_qs

s3 = boto3.client('s3')

def lambda_handler(event, context):
    try:
        body = json.loads(event['body'])
        file_content = body['file_content'].encode()
        filename = f"cat_{uuid.uuid4().hex}.jpg"

        bucket = event['BUCKET_NAME']
        s3.put_object(Bucket=bucket, Key=filename, Body=file_content, ContentType='image/jpeg')

        return {
            'statusCode': 200,
            'headers': {
                'Access-Control-Allow-Origin': '*',
                'Access-Control-Allow-Headers': 'Content-Type'
            },
            'body': json.dumps({'message': 'Cat picture uploaded successfully', 'filename': filename})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': str(e)})
        }
```

**get_random_cat.py:**
```python
import json
import boto3
import random
import urllib.parse

s3 = boto3.client('s3')

def lambda_handler(event, context):
    try:
        bucket = event['BUCKET_NAME']
        objects = s3.list_objects_v2(Bucket=bucket)

        if 'Contents' not in objects or not objects['Contents']:
            return {
                'statusCode': 404,
                'headers': {
                    'Access-Control-Allow-Origin': '*'
                },
                'body': json.dumps({'error': 'No cat pictures found'})
            }

        random_obj = random.choice(objects['Contents'])
        url = s3.generate_presigned_url(
            'get_object',
            Params={'Bucket': bucket, 'Key': random_obj['Key']},
            ExpiresIn=3600
        )

        return {
            'statusCode': 200,
            'headers': {
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'url': url, 'filename': random_obj['Key']})
        }
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({'error': str(e)})
        }
```

