provider "aws" {
  region = "us-east-1"
}

# S3 Bucket for storing cat pictures
resource "aws_s3_bucket" "cat_pics" {
  bucket = "cat-pics-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket_ownership_controls" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "cat_pics" {
  depends_on = [aws_s3_bucket_ownership_controls.cat_pics]
  bucket     = aws_s3_bucket.cat_pics.id
  acl        = "private"
}

resource "aws_s3_bucket_public_access_block" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_cors_configuration" "cat_pics" {
  bucket = aws_s3_bucket.cat_pics.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET", "PUT", "POST"]
    allowed_origins = ["*"]
    expose_headers  = ["ETag"]
    max_age_seconds = 3000
  }
}

# DynamoDB Table to track uploads (optional metadata)
resource "aws_dynamodb_table" "cat_uploads" {
  name           = "CatUploads-${random_string.bucket_suffix.result}"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "id"

  attribute {
    name = "id"
    type = "S"
  }

  tags = {
    Name = "CatUploads"
  }
}

# Lambda execution role
resource "aws_iam_role" "lambda_exec" {
  name = "cat_service_lambda_exec-${random_string.bucket_suffix.result}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
