# Lambda function code (inline for simplicity)
data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "/tmp/lambda_function.zip"

  source {
    content = <<-EOT
      import json
      import boto3
      import urllib.parse
      import os
      import uuid
      import random

      s3 = boto3.client('s3')
      dynamodb = boto3.resource('dynamodb')
      BUCKET_NAME = '${aws_s3_bucket.cat_pics.bucket}'
      TABLE_NAME = '${aws_dynamodb_table.cat_uploads.name}'

      def lambda_handler(event, context):
          http_method = event['httpMethod']
          resource_path = event['resourcePath']

          if http_method == 'POST' and resource_path == '/upload':
              return handle_upload(event)
          elif http_method == 'GET' and resource_path == '/random':
              return handle_random()
          else:
              return {
                  'statusCode': 404,
                  'body': json.dumps({'error': 'Not Found'})
              }

      def handle_upload(event):
          try:
              body = base64.b64decode(event['body'])
              key = f"cat_{uuid.uuid4().hex}.jpg"
              s3.put_object(Bucket=BUCKET_NAME, Key=key, Body=body, ContentType='image/jpeg')

              table = dynamodb.Table(TABLE_NAME)
              table.put_item(Item={'id': key})

              return {
                  'statusCode': 200,
                  'headers': {'Access-Control-Allow-Origin': '*'},
                  'body': json.dumps({'message': 'Upload successful', 'key': key})
              }
          except Exception as e:
              return {
                  'statusCode': 500,
                  'body': json.dumps({'error': str(e)})
              }

      def handle_random():
          try:
              table = dynamodb.Table(TABLE_NAME)
              response = table.scan(Limit=1000)
              items = response['Items']
              if items:
                  random_key = random.choice(items)['id']
                  url = f"https://{BUCKET_NAME}.s3.amazonaws.com/{random_key}"
                  return {
                      'statusCode': 200,
                      'headers': {'Access-Control-Allow-Origin': '*'},
                      'body': json.dumps({'url': url})
                  }
              else:
                  return {
                      'statusCode': 404,
                      'body': json.dumps({'error': 'No cat pictures available'})
                  }
          except Exception as e:
              return {
                  'statusCode': 500,
                  'body': json.dumps({'error': str(e)})
              }
    EOT
    filename = "lambda_function.py"
  }
}

