terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket for cat pictures
resource "aws_s3_bucket" "cat_pictures" {
  bucket = "caas-cat-pictures-bucket"
}

resource "aws_s3_bucket_public_access_block" "cat_pictures" {
  bucket = aws_s3_bucket.cat_pictures.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# DynamoDB table for cats
resource "aws_dynamodb_table" "cats" {
  name         = "Cats"
  billing_mode = "PAY_PER_REQUEST"
  hash_key     = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

# Lambda for GET method
resource "aws_lambda_function" "caas_get" {
  filename         = "get_handler.zip"
  function_name    = "caas_get"
  role            = aws_iam_role.lambda_get.arn
  handler         = "get_handler.lambda_handler"
  runtime         = "python3.9"
  source_code_hash = filebase64sha256("get_handler.zip")

  environment {
    variables = {
      DYNAMODB_TABLE = aws_dynamodb_table.cats.name
      S3_BUCKET      = aws_s3_bucket.cat_pictures.bucket
    }
  }
}

# Lambda for PUT method
resource "aws_lambda_function" "caas_put" {
  filename         = "put_handler.zip"
  function_name    = "caas_put"
  role            = aws_iam_role.lambda_put.arn
  handler         = "put_handler.lambda_handler"
  runtime         = "python3.9"
  source_code_hash = filebase64sha256("put_handler.zip")

  environment {
    variables = {
      DYNAMODB_TABLE = aws_dynamodb_table.cats.name
      S3_BUCKET      = aws_s3_bucket.cat_pictures.bucket
    }
  }
}

# IAM roles for Lambdas
resource "aws_iam_role" "lambda_get" {
  name = "caas_get_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role" "lambda_put" {
  name = "caas_put_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "lambda.amazonaws.com"
      }
    }]
  })
}

# IAM policy for Lambda access to DynamoDB and S3
resource "aws_iam_role_policy_attachment" "lambda_get_policy" {
  role       = aws_iam_role.lambda_get.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy_attachment" "lambda_put_policy" {
  role       = aws_iam_role.lambda_put.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_policy" "lambda_dynamodb_s3" {
  name = "caas_lambda_dynamodb_s3"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:GetItem",
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:Scan",
          "dynamodb:Query"
        ]
        Resource = aws_dynamodb_table.cats.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.cat_pictures.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_get_dynamodb_s3" {
  role       = aws_iam_role.lambda_get.name
  policy_arn = aws_iam_policy.lambda_dynamodb_s3.arn
}

resource "aws_iam_role_policy_attachment" "lambda_put_dynamodb_s3" {
  role       = aws_iam_role.lambda_put.name
  policy_arn = aws_iam_policy.lambda_dynamodb_s3.arn
}

# API Gateway
resource "aws_apigatewayv2_api" "caas" {
  name          = "caas"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_stage" "default" {
  api_id      = aws_apigatewayv2_api.caas.id
  name        = "$default"
  auto_deploy = true
}

# Resource /cat
resource "aws_apigatewayv2_route" "caas_cat_get" {
  api_id    = aws_apigatewayv2_api.caas.id
  route_key = "GET /cat"
  target    = "integrations/${aws_apigatewayv2_integration.caas_get.id}"
}

resource "aws_apigatewayv2_route" "caas_cat_put" {
  api_id    = aws_apigatewayv2_api.caas.id
  route_key = "PUT /cat"
  target    = "integrations/${aws_apigatewayv2_integration.caas_put.id}"
}

# Integrations
resource "aws_apigatewayv2_integration" "caas_get" {
  api_id             = aws_apigatewayv2_api.caas.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.caas_get.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_integration" "caas_put" {
  api_id             = aws_apigatewayv2_api.caas.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.caas_put.invoke_arn
  integration_method = "POST"
}

# Lambda permissions for API Gateway
resource "aws_lambda_permission" "api_gateway_get" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_get.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.caas.execution_arn}/*"
}

resource "aws_lambda_permission" "api_gateway_put" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_put.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.caas.execution_arn}/*"
}

# Output API endpoint
output "api_endpoint" {
  value = "${aws_apigatewayv2_stage.default.domain_name}${aws_apigatewayv2_stage.default.invoke_url}/cat"
}
```

**Note:** You'll need to create placeholder `get_handler.zip` and `put_handler.zip` files with your Lambda handler code for deployment. The configuration creates all requested resources with proper IAM permissions for API Gateway to invoke Lambdas and Lambdas to access S3/DynamoDB.

