terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"
}

# VPC and networking
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "backup-demo-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "public-subnet"
  }
}

resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "backup-demo-igw"
  }
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

# Security group
resource "aws_security_group" "ec2_sg" {
  vpc_id = aws_vpc.main.id
  name   = "ec2-backup-sg"

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "ec2-backup-sg"
  }
}

# EC2 instance
resource "aws_instance" "backup_demo" {
  ami           = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-west-2
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.public.id
  vpc_security_group_ids = [aws_security_group.ec2_sg.id]

  tags = {
    Name = "backup-demo-instance"
  }

  # Resource tag required for AWS Backup
  tags_with_resource_tag = {
    Backup = "true"
  }
}

# IAM role for AWS Backup service
resource "aws_iam_role" "backup_role" {
  name = "AWSBackupDefaultServiceRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_default_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

resource "aws_iam_role_policy_attachment" "backup_encryption_policy" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForEncryptionKey"
}

# Backup vault
resource "aws_backup_vault" "daily_vault" {
  name = "daily-backup-vault"

  encryption_configuration {
    kms_key_arn = aws_kms_key.backup_key.arn
  }

  tags = {
    Name = "daily-backup-vault"
  }
}

# KMS key for backup encryption
resource "aws_kms_key" "backup_key" {
  description             = "KMS key for AWS Backup"
  deletion_window_in_days = 7
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Default"
        Effect = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow use of the key"
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.backup_role.arn
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

# Backup plan - daily at midnight (UTC)
resource "aws_backup_plan" "daily_plan" {
  name = "daily-backup-plan"

  rule {
    rule_name         = "daily-midnight"
    target_vault_name = aws_backup_vault.daily_vault.name
    schedule          = "cron(0 0 * * ? *)" # Midnight UTC daily

    lifecycle {
      delete_after = 30
    }
  }

  tags = {
    Name = "daily-backup-plan"
  }
}

# Backup selection for EC2 instances tagged with Backup=true
resource "aws_backup_selection" "ec2_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-backup-selection"
  plan_id      = aws_backup_plan.daily_plan.id

  resources = [
    aws_instance.backup_demo.id
  ]

  tags {
    key     = "Backup"
    value   = "true"
  }
}

# Output the instance ID and backup vault name
output "ec2_instance_id" {
  value = aws_instance.backup_demo.id
}

output "backup_vault_name" {
  value = aws_backup_vault.daily_vault.name
}

