  schedule_expression = "cron(0 7 * * ? *)"
}

# Target: AWS Systems Manager Automation (example target)
# Replace with your desired target resource (e.g., Lambda ARN)
resource "aws_cloudwatch_event_target" "ssm_automation" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "run-daily-task"
