```hcl
provider "aws" {
  region = "us-east-1"
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_exec_role" {
  name = "lambda-eventbridge-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy attachment for basic Lambda execution
resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Lambda function
resource "aws_lambda_function" "daily_task" {
  filename         = "lambda_function.zip"  # Upload your code as lambda_function.zip
  function_name    = "daily-task-function"
  role            = aws_iam_role.lambda_exec_role.arn
  handler         = "index.handler"         # Adjust based on your code
  runtime         = "nodejs18.x"            # Adjust runtime as needed
  source_code_hash = filebase64sha256("lambda_function.zip")

  # Example inline code (uncomment and remove filename if preferred)
  /*
  source_code_hash = data.aws_lambda_function.default_source_code_hash
  code {
    zip_file = "lambda_function.zip"
  }
  */
}

# EventBridge Rule - Daily at 7 UTC
resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-7utc-rule"
  schedule_expression = "cron(0 7 * * ? *)"  # 7:00 UTC daily
  description         = "Run daily at 7 UTC"
}

# EventBridge Target - Lambda function
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "daily-lambda-target"
  arn       = aws_lambda_function.daily_task.arn
}

# Lambda Permission for EventBridge
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_schedule.arn
}
```

**Note:** Create a `lambda_function.zip` file with your code (e.g., `index.js` with `exports.handler = async () => { console.log('Daily task executed at 7 UTC'); return { statusCode: 200 }; };`) and place it in the same directory before running `terraform apply`. Adjust runtime, handler, and region as needed.

