  custom_error_response {
    error_code            = 404
    response_code         = 200
    response_page_path    = "/index.html"
    error_caching_min_ttl = 300
  }

  depends_on = [aws_s3_bucket.video_content]
}

# S3 bucket policy to allow CloudFront OAI access
resource "aws_s3_bucket_policy" "video_content_policy" {
  depends_on = [aws_cloudfront_origin_access_identity.oai, aws_s3_bucket_public_access_block.video_content]
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowCloudFrontServicePrincipal"
        Effect    = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action   = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.video_streaming.arn
          }
        }
      }
    ]
  })
}

# Route53 hosted zone
data "aws_route53_zone" "public" {
  name         = "video-streaming-site.com."
  private_zone = false
}

# Route53 A record alias to CloudFront
resource "aws_route53_record" "video_streaming" {
  zone_id = data.aws_route53_zone.public.zone_id
  name    = "streaming.video-streaming-site.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_streaming.domain_name
    zone_id                = aws_cloudfront_distribution.video_streaming.hosted_zone_id
    evaluate_target_health = false
  }
}

# IAM policy for uploading videos to S3
resource "aws_iam_policy" "video_upload_policy" {
  name        = "VideoUploadPolicy"
  description = "Policy for uploading videos to S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:GetObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.video_content.arn,
          "${aws_s3_bucket.video_content.arn}/*"
        ]
      }
    ]
  })
}

# Output values
output "cloudfront_domain_name" {
  description = "CloudFront distribution domain name"
  value       = aws_cloudfront_distribution.video_streaming.domain_name
}

output "s3_bucket_name" {
  description = "S3 bucket name for video content"
  value       = aws_s3_bucket.video_content.bucket
}

output "route53_record_name" {
  description = "Route53 record name"
  value       = aws_route53_record.video_streaming.fqdn
}

output "iam_policy_arn" {
  description = "IAM policy ARN for video uploads"
  value       = aws_iam_policy.video_upload_policy.arn
}
```

**Note:** Update the `data "aws_route53_zone" "public"` block with your actual domain name. The configuration provides:

- Secure S3 bucket with versioning and encryption
- CloudFront CDN with global distribution (PriceClass_100)
- Route53 DNS routing
- Origin Access Identity for secure S3-CloudFront access
- IAM policy for video uploads
- HTTPS enforcement and proper caching for video streaming

