```hcl
terraform {
  required_version = ">= 1.0"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC Module (using community module)
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway = true
  enable_vpn_gateway = false

  tags = {
    Name = "video-streaming-vpc"
  }
}

# Security Group for EC2 instances
resource "aws_security_group" "ec2_sg" {
  name_prefix = "video-streaming-ec2-"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "HTTP from ALB"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    security_groups = [aws_security_group.alb_sg.id]
  }

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "video-streaming-ec2-sg"
  }
}

# Security Group for ALB
resource "aws_security_group" "alb_sg" {
  name_prefix = "video-streaming-alb-"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "HTTP from anywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "video-streaming-alb-sg"
  }
}

# ALB Target Group
resource "aws_lb_target_group" "video_tg" {
  name_prefix       = "video-tg-"
  port              = 80
  protocol          = "HTTP"
  vpc_id            = module.vpc.vpc_id
  target_type       = "instance"
  deregistration_delay = 30

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    unhealthy_threshold = 2
  }

  tags = {
    Name = "video-streaming-tg"
  }
}

# Application Load Balancer
resource "aws_lb" "video_alb" {
  name               = "video-streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "video-streaming-alb"
  }
}

# ALB Listener
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.video_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_tg.arn
  }
}

# EC2 Instances (2 servers for load balancing)
resource "aws_instance" "video_server" {
  count                       = 2
  ami                         = "ami-0c02fb55956c7d316" # Amazon Linux 2 AMI (update for your region)
  instance_type               = "t3.medium"
  subnet_id                   = element(module.vpc.private_subnets, count.index)
  vpc_security_group_ids      = [aws_security_group.ec2_sg.id]
  associate_public_ip_address = false
  user_data                   = base64encode(templatefile("${path.module}/userdata.sh", {
    target_group_arn = aws_lb_target_group.video_tg.arn
  }))

  tags = {
    Name = "video-server-${count.index + 1}"
  }
}

# Attach EC2 instances to target group
resource "aws_lb_target_group_attachment" "video_tg_attachment" {
  count            = 2
  target_group_arn = aws_lb_target_group.video_tg.arn
  target_id        = aws_instance.video_server[count.index].id
  port             = 80
}

# Route53 Hosted Zone
resource "aws_route53_zone" "video_zone" {
  name = "videostreaming.example.com"
}

# Route53 Record pointing to ALB
resource "aws_route53_record" "alb_record" {
  zone_id = aws_route53_zone.video_zone.zone_id
  name    = "www.videostreaming.example.com"
  type    = "A"

  aliases {
    name                   = aws_lb.video_alb.dns_name
    zone_id                = aws_lb.video_alb.zone_id
    evaluate_target_health = true
  }
}

# Output important values
output "alb_dns_name" {
  description = "DNS name of the ALB"
  value       = aws_lb.video_alb.dns_name
}

output "route53_zone_id" {
  description = "Route53 Hosted Zone ID"
  value       = aws_route53_zone.video_zone.zone_id
}

output "route53_name_servers" {
  description = "Route53 Name Servers"
  value       = aws_route53_zone.video_zone.name_servers
}
```

**Note:** Create a `userdata.sh` file with the following content for the EC2 instances:

```bash
#!/bin/bash
yum update -y
yum install -y httpd
systemctl start httpd
systemctl enable httpd
echo "<h1>Video Streaming Server $(hostname)</h1>" > /var/www/html/index.html

# Install AWS CLI and configure target group health checks
yum install -y awscli
aws configure set default.region us-east-1
curl -o /usr/local/bin/deregister && chmod +x /usr/local/bin/deregister
cat > /usr/local/bin/deregister << 'EOF'
#!/bin/bash
INSTANCE_ID=$(curl -s http://169.254.169.254/latest/meta-data/instance-id)
aws elbv2 deregister-targets --target-group-arn ${target_group_arn} --targets Id=$INSTANCE_ID,Port=80
EOF
```

This configuration creates:
- VPC with public/private subnets and NAT gateway
- 2 EC2 instances in private subnets running a web server
- Application Load Balancer with target group
- Security groups for ALB and EC2
- Route53 hosted zone and A record alias to ALB

