# Provider configuration
provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Variables for VPC and subnets (replace with your existing VPC/subnet IDs)
variable "vpc_id" {
  description = "ID of the existing VPC"
  type        = string
  default     = "vpc-12345678"  # Replace with your VPC ID
}

variable "private_subnet_ids" {
  description = "List of private subnet IDs in different AZs"
  type        = list(string)
  default     = ["subnet-12345678", "subnet-87654321"]  # Replace with your subnet IDs
}

# KMS Key for encryption
resource "aws_kms_key" "rds_key" {
  description             = "KMS key for RDS encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "Enable IAM User Permissions"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"
        }
        Action   = "kms:*"
        Resource = "*"
      },
      {
        Sid    = "Allow RDS to use key"
        Effect = "Allow"
        Principal = {
          AWS = "arn:aws:rds:${var.aws_region}:${data.aws_caller_identity.current.account_id}:dbuser:*/*"
        }
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

# Custom Parameter Group for PostgreSQL 15
resource "aws_db_parameter_group" "postgres_params" {
  name   = "postgres15-custom-params"
  family = "postgres15"

  parameter {
    name  = "log_destination"
    value = "stderr"
  }

  parameter {
    name  = "logging_collector"
    value = "on"
  }

  parameter {
    name  = "log_statement"
    value = "all"
  }

  tags = {
    Name = "postgres15-custom-params"
  }
}

# RDS Subnet Group
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "RDS Subnet Group"
  }
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name_prefix = "rds-postgres-sg-"
  vpc_id      = var.vpc_id

  # Allow inbound PostgreSQL traffic from specific CIDR (adjust as needed)
  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Replace with your allowed CIDR
  }

  # Allow all outbound
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-sg"
  }
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgres" {
  identifier              = "postgres15-secure"
  engine                  = "postgres"
  engine_version          = "15.5"  # Latest PostgreSQL 15 version
  instance_class          = "db.t3.medium"  # Adjust size as needed
  allocated_storage       = 50
  max_allocated_storage   = 100
  storage_type            = "gp3"
  storage_encrypted       = true
  kms_key_id              = aws_kms_key.rds_key.arn

  # Multi-AZ deployment for high availability
  multi_az                = true

  # Database name and credentials
  db_name                 = "mydatabase"
  username                = "postgresadmin"
  password                = "SecurePassword123!"  # Use secrets manager in production
  port                    = 5432

  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.rds_subnet_group.name
  parameter_group_name    = aws_db_parameter_group.postgres_params.name

  # Backup and maintenance
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "Sun:04:00-Sun:05:00"

  # Deletion protection and monitoring
  deletion_protection     = true
  monitoring_interval     = 60
  monitoring_role_arn     = aws_iam_role.rds_monitoring.arn
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]

  skip_final_snapshot = false
  final_snapshot_identifier = "postgres15-final-snapshot"

  tags = {
    Name        = "Secure PostgreSQL 15"
    Environment = "production"
  }
}

# IAM Role for Enhanced Monitoring
resource "aws_iam_role" "rds_monitoring" {
  name = "rds-monitoring-role-postgres"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "monitoring.rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_monitoring" {
  role       = aws_iam_role.rds_monitoring.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSEnhancedMonitoringRole"
}

# Outputs
output "rds_endpoint" {
  description = "RDS PostgreSQL endpoint"
  value       = aws_db_instance.postgres.endpoint
}

output "rds_port" {
  description = "RDS PostgreSQL port"
  value       = aws_db_instance.postgres.port
}

output "kms_key_arn" {
  description = "KMS key ARN used for encryption"
  value       = aws_kms_key.rds_key.arn
}

output "security_group_id" {
  description = "RDS Security Group ID"
  value       = aws_security_group.rds_sg.id
}

