  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]  # Adjust to your VPC CIDR or specific sources
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-sg"
  }
}

# RDS PostgreSQL instance
resource "aws_db_instance" "postgres" {
  identifier              = "postgres-instance"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  max_allocated_storage   = 100
  storage_type            = "gp3"
  storage_encrypted       = true
  kms_key_id              = var.kms_key_id
  engine                  = "postgres"
  engine_version          = "15.4"
  db_name                 = "mydb"
  username                = "admin"
  password                = "SecurePassword123!"  # Use secrets manager in production
  parameter_group_name    = aws_db_parameter_group.postgres.name
  db_subnet_group_name    = aws_db_subnet_group.postgres.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  multi_az                = true
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"
  deletion_protection     = false
  skip_final_snapshot     = true

  tags = {
    Name = "postgres-instance"
  }
}

# Outputs
output "db_endpoint" {
  description = "The endpoint of the PostgreSQL instance"
  value       = aws_db_instance.postgres.endpoint
}

output "db_port" {
  description = "The port of the PostgreSQL instance"
  value       = aws_db_instance.postgres.port
}
