terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "airbyte-test-vpc"
  }
}

# Public subnets (specific subnets for RDS accessibility)
resource "aws_subnet" "public_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-1"
    Type = "public"
  }
}

resource "aws_subnet" "public_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-2"
    Type = "public"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "igw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "airbyte-test-igw"
  }
}

# Public Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.igw.id
  }
  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_1" {
  subnet_id      = aws_subnet.public_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_2" {
  subnet_id      = aws_subnet.public_2.id
  route_table_id = aws_route_table.public.id
}

# Security Group for RDS (allows PostgreSQL access from anywhere for testing)
resource "aws_security_group" "rds_sg" {
  name_prefix = "airbyte-rds-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # For testing; restrict in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-rds-sg"
  }
}

# RDS Subnet Group (using public subnets as requested)
resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "airbyte-rds-subnet-group"
  subnet_ids = [aws_subnet.public_1.id, aws_subnet.public_2.id]

  tags = {
    Name = "airbyte-rds-subnet-group"
  }
}

# PostgreSQL 15 RDS Instance (managed, low maintenance)
resource "aws_db_instance" "airbyte_postgres" {
  identifier              = "airbyte-test-postgres"
  engine                  = "postgres"
  engine_version          = "15.5"  # PostgreSQL 15.x
  instance_class          = "db.t4g.micro"  # Cost-effective for testing
  allocated_storage       = 20
  max_allocated_storage   = 100  # Auto-scaling
  storage_type            = "gp3"
  storage_encrypted       = true

  # Managed settings for low maintenance
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"
  auto_minor_version_upgrade = true
  deletion_protection     = false  # Set to true for production

  # Networking
  vpc_security_group_ids    = [aws_security_group.rds_sg.id]
  db_subnet_group_name      = aws_db_subnet_group.rds_subnet_group.name
  publicly_accessible       = true  # Public access for Airbyte testing

  # Credentials (change these in production)
  username = "airbyte"
  password = "AirbyteTest123!"  # Use secrets manager in production
  port     = 5432

  # Monitoring (basic managed)
  monitoring_interval = 0  # Enhanced monitoring disabled for simplicity
  monitoring_role_arn = null

  # Parameters for Airbyte compatibility
  parameter_group_name = aws_db_parameter_group.airbyte.name

  skip_final_snapshot = true  # For testing
  tags = {
    Name     = "airbyte-test-postgres"
    Purpose  = "airbyte-connector-tests"
  }
}

# Custom parameter group for PostgreSQL 15 optimized for Airbyte
resource "aws_db_parameter_group" "airbyte" {
  name   = "airbyte-postgres15-params"
  family = "postgres15"

  parameter {
    name  = "log_destination"
    value = "stderr"
  }

  parameter {
    name  = "logging_collector"
    value = "on"
  }

  parameter {
    name  = "max_connections"
    value = "200"
  }

  tags = {
    Name = "airbyte-postgres15-params"
  }
}

# Output the RDS endpoint for Airbyte connection
output "rds_endpoint" {
  description = "PostgreSQL RDS endpoint for Airbyte"
  value       = aws_db_instance.airbyte_postgres.endpoint
}

output "rds_port" {
  value = aws_db_instance.airbyte_postgres.port
}

output "rds_username" {
  value     = aws_db_instance.airbyte_postgres.username
  sensitive = true
}

output "vpc_id" {
  value = aws_vpc.main.id
}

