```hcl
provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Assume these public subnets already exist in your VPC
# Replace with your actual subnet IDs
data "aws_subnets" "public" {
  filter {
    name   = "vpc-id"
    values = ["vpc-12345678"]  # Replace with your VPC ID
  }

  filter {
    name   = "tag:Name"
    values = ["public-subnet-*"]  # Replace with your public subnet naming pattern
  }
}

# Security group for RDS allowing inbound PostgreSQL traffic from anywhere (restrict for production)
resource "aws_security_group" "rds_sg" {
  name_prefix = "rds-postgres-airbyte-"
  vpc_id      = "vpc-12345678"  # Replace with your VPC ID

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Restrict to specific IPs for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-postgres-airbyte-sg"
  }
}

# RDS PostgreSQL 15 instance
resource "aws_db_instance" "airbyte_postgres" {
  identifier              = "airbyte-postgres-test"
  engine                  = "postgres"
  engine_version          = "15.5"  # PostgreSQL 15 latest patch
  instance_class          = "db.t4g.micro"  # Low-cost managed instance
  allocated_storage       = 20
  storage_type            = "gp3"
  storage_encrypted       = true
  db_name                 = "airbyte"
  username                = "airbyte"
  password                = "AirbyteTest123!"  # Use secrets manager in production
  port                    = 5432
  publicly_accessible     = true
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  db_subnet_group_name    = aws_db_subnet_group.public.name
  skip_final_snapshot     = true
  deletion_protection     = false
  apply_immediately       = true
  backup_retention_period = 1
  multi_az                = false
  auto_minor_version_upgrade = true

  # Managed settings for low maintenance
  monitoring_interval          = 0
  monitoring_role_arn         = null
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  performance_insights_enabled = false

  tags = {
    Name        = "airbyte-postgres-test"
    Environment = "test"
    Purpose     = "airbyte-connector-tests"
  }
}

# DB Subnet Group for public subnets
resource "aws_db_subnet_group" "public" {
  name       = "airbyte-public-subnets"
  subnet_ids = data.aws_subnets.public.ids

  tags = {
    Name = "airbyte-public-subnet-group"
  }
}

# Output connection details
output "rds_endpoint" {
  description = "RDS PostgreSQL endpoint"
  value       = aws_db_instance.airbyte_postgres.endpoint
}

output "rds_port" {
  description = "RDS PostgreSQL port"
  value       = aws_db_instance.airbyte_postgres.port
}

output "rds_username" {
  description = "RDS PostgreSQL username"
  value       = aws_db_instance.airbyte_postgres.username
}

output "rds_connection_string" {
  description = "Full connection string"
  value       = "postgresql://${aws_db_instance.airbyte_postgres.username}:${aws_db_instance.airbyte_postgres.password}@${aws_db_instance.airbyte_postgres.endpoint}:5432/airbyte"
  sensitive   = true
}
```

**Important Notes:**
1. Replace `vpc-12345678` with your actual VPC ID
2. Update the `data.aws_subnets.public` filter to match your public subnet naming
3. Restrict the security group `cidr_blocks` to specific IPs for production use
4. Use AWS Secrets Manager for the database password in production
5. The instance uses `db.t4g.micro` for cost efficiency suitable for testing

