  password = random_password.db_password.result

  tags = {
    Name = "postgres-db"
  }
}

# Random password for DB
resource "random_password" "db_password" {
  length  = 16
  special = true
}

# Outputs
output "database_endpoint" {
  description = "The endpoint for the PostgreSQL RDS instance"
  value       = aws_db_instance.postgres.endpoint
}

output "database_port" {
  description = "The port for the PostgreSQL RDS instance"
  value       = aws_db_instance.postgres.port
}

output "database_username" {
  description = "The username for the PostgreSQL RDS instance"
  value       = "postgres"
}

output "database_password" {
  description = "The password for the PostgreSQL RDS instance"
  value       = random_password.db_password.result
  sensitive   = true
}

