resource "aws_db_option_group" "pike" {
  name                     = "option-group-pike"
  option_group_description = "Option group for SQL Server EE 11"
  engine_name              = "sqlserver-ee"
  major_engine_version     = "11"

  option {
    option_name = "SQLSERVER_AUDIT"

    option_settings {
      name  = "AUDIT_BUCKET_NAME"
      value = aws_s3_bucket.audit.arn
    }

    option_settings {
      name  = "AUDIT_IAM_ROLE_ARN"
      value = aws_iam_role.audit.arn
    }
  }

  option {
    option_name = "TDE"
  }
}

# Supporting resources (required for the option settings)
resource "aws_s3_bucket" "audit" {
  bucket = "pike-sqlserver-audit-bucket"
}

resource "aws_iam_role" "audit" {
  name = "pike-sqlserver-audit-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Basic policy for the audit role (adjust permissions as needed)
resource "aws_iam_role_policy" "audit" {
  name = "pike-sqlserver-audit-policy"
  role = aws_iam_role.audit.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.audit.arn,
          "${aws_s3_bucket.audit.arn}/*"
        ]
      }
    ]
  })
}

