  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "aurora-private-b"
  }
}

# Subnet group
resource "aws_db_subnet_group" "aurora" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security Groups
resource "aws_security_group" "aurora_cluster" {
  name_prefix = "aurora-cluster-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    self        = true
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-cluster-sg"
  }
}

resource "aws_security_group" "aurora_proxy" {
  name_prefix = "aurora-proxy-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.aurora_cluster.id]
  }

  tags = {
    Name = "aurora-proxy-sg"
  }
}

# Secrets Manager
resource "aws_secretsmanager_secret" "aurora_creds" {
  name = "aurora-master-creds"
}

resource "aws_secretsmanager_secret_version" "aurora_creds_version" {
  secret_id     = aws_secretsmanager_secret.aurora_creds.id
  secret_string = jsonencode({
    username = "admin"
    password = "SecurePassword123!"
  })
}

# IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [{
      Action = "sts:AssumeRole"
      Effect = "Allow"
      Principal = {
        Service = "rds.amazonaws.com"
      }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_secrets" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSSecretsManagerRolePolicy"
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora" {
  cluster_identifier      = "aurora-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  availability_zones      = ["us-east-1a", "us-east-1b"]
  database_name           = "mydb"
  master_username         = jsondecode(data.aws_secretsmanager_secret_version.creds.secret_string)["username"]
  manage_master_user_password = true
  master_user_secret {
    secret_arn = aws_secretsmanager_secret.aurora_creds.arn
  }
  db_subnet_group_name   = aws_db_subnet_group.aurora.name
  vpc_security_group_ids = [aws_security_group.aurora_cluster.id]
  storage_encrypted      = true
  skip_final_snapshot    = true

  tags = {
    Name = "aurora-cluster"
  }
}

# Aurora Cluster Instance
resource "aws_rds_cluster_instance" "aurora_instances" {
  count              = 2
  identifier         = "aurora-instance-${count.index}"
  cluster_identifier = aws_rds_cluster.aurora.id
  instance_class     = "db.r6g.large"
  engine             = aws_rds_cluster.aurora.engine
  engine_version     = aws_rds_cluster.aurora.engine_version

  tags = {
    Name = "aurora-instance-${count.index}"
  }
}

# RDS Proxy
resource "aws_db_proxy" "aurora_proxy" {
  name                   = "aurora-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_security_group_ids = [aws_security_group.aurora_proxy.id]
  vpc_subnet_ids         = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  auth {
    auth_scheme = "SECRETS"
    description = "aurora-proxy-auth"
    secret_arn  = aws_secretsmanager_secret.aurora_creds.arn
    iam_auth    = "DISABLED"
  }

  tags = {
    Name = "aurora-proxy"
  }
}

# RDS Proxy Target
resource "aws_db_proxy_target" "aurora_target" {
  db_proxy_name = aws_db_proxy.aurora_proxy.name
  target_type   = "rds"
  db_cluster_identifier = aws_rds_cluster.aurora.id
}

# Data source for secret (used in cluster)
data "aws_secretsmanager_secret_version" "creds" {
  secret_id = aws_secretsmanager_secret.aurora_creds.id
}

output "proxy_endpoint" {
  value = aws_db_proxy.aurora_proxy.endpoint
}

output "cluster_endpoint" {
  value = aws_rds_cluster.aurora.endpoint
}
