  region = "us-east-1"  # Change to your preferred region
}

# Amazon Lightsail instance
resource "aws_lightsail_instance" "basic" {
  name              = "basic-lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"  # Amazon Linux 2 blueprint
  bundle_id         = "nano_2_0"        # Nano bundle (smallest/cheapest)

  # Optional: Add SSH key
  key_pair_name = aws_lightsail_key_pair.main.name
}

# Lightsail SSH key pair (optional, for SSH access)
resource "aws_lightsail_key_pair" "main" {
  name = "lightsail-key-pair"
}

# Static IP address (optional, persists if instance is stopped)
resource "aws_lightsail_static_ip" "main" {
  name = "lightsail-static-ip"
}

# Attach static IP to instance
resource "aws_lightsail_static_ip_attachment" "main" {
  static_ip_name = aws_lightsail_static_ip.main.id
  instance_name  = aws_lightsail_instance.basic.id
}

# Output important information
output "instance_ip" {
  description = "Public IP of the Lightsail instance"
  value       = aws_lightsail_static_ip.main.ip_address
}

output "instance_id" {
  description = "ID of the Lightsail instance"
  value       = aws_lightsail_instance.basic.id
}

output "ssh_key_private_key" {
  description = "Private key for SSH access (save this securely!)"
  value       = tls_private_key.lightsail_ssh_key.private_key_pem
  sensitive   = true
}

# Generate SSH key pair for Lightsail
resource "tls_private_key" "lightsail_ssh_key" {
  algorithm = "RSA"
  rsa_bits  = 2048
}

# Save private key to file (optional)
resource "local_file" "private_key" {
  content  = tls_private_key.lightsail_ssh_key.private_key_pem
  filename = "${path.module}/lightsail-key.pem"
}

# Save public key to file (optional)
resource "local_file" "public_key" {
  content  = tls_private_key.lightsail_ssh_key.public_key_openssh
  filename = "${path.module}/lightsail-key.pub"
}

