  name              = "web-server"
  availability_zone = "us-west-2a"
  blueprint_id      = "amazon_linux_2"  # Use 'ubuntu_20_04' or others as needed
  bundle_id         = "nano_2_0"        # nano bundle for smallest size
  key_pair_name     = aws_lightsail_key_pair.main.name

  tags = {
    Name = "web-server"
  }
}

# SSH key pair for Lightsail
