  name = "lightsail-key"
}

# Enable automatic snapshots for the instance
resource "aws_lightsail_instance_snapshot" "auto_snapshot" {
  name                      = "daily-snapshot"
  instance_name             = aws_lightsail_instance.web_server.name
  # Note: Lightsail automatic snapshots are typically managed via console or API
  # This creates an on-demand snapshot; for true auto-snapshots, use Lightsail console scheduling
}

# Static IP for the instance (persistent)
resource "aws_lightsail_static_ip" "static_ip" {
  name = "web-server-ip"
}

resource "aws_lightsail_static_ip_attachment" "attach_ip" {
  static_ip_name = aws_lightsail_static_ip.static_ip.name
  instance_name  = aws_lightsail_instance.web_server.name
}

# Output the public IP and key details
