  value = aws_lightsail_static_ip.static_ip.ip_address
}

output "ssh_key_pair_private_key" {
  value     = aws_lightsail_key_pair.main.private_key
  sensitive = true
}

output "instance_state" {
  value = aws_lightsail_instance.web_server.state
