terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"  # Lightsail dualstack supported in us-west-2, us-east-1, eu-west-1, etc.
}

# Create Lightsail instance with dualstack IPv4/IPv6
resource "aws_lightsail_instance" "dualstack_instance" {
  name              = "dualstack-lightsail-instance"
  availability_zone = "us-west-2a"
  blueprint_id      = "amazon_linux_2"  # Amazon Linux 2 blueprint
  bundle_id         = "nano_2_0"        # nano bundle with dualstack support

  # Enable dualstack networking (IPv4 + IPv6)
  networking {
    dualstack_ip = true
  }

  # Optional: Add user data for IPv6 configuration
  user_data = <<-EOF
#!/bin/bash
# Ensure IPv6 is enabled and configured
sysctl -w net.ipv6.conf.all.disable_ipv6=0
sysctl -w net.ipv6.conf.default.disable_ipv6=0
sed -i 's/^GRUB_CMDLINE_LINUX=.*/GRUB_CMDLINE_LINUX="ipv6.disable=0"/' /etc/default/grub
update-grub
  EOF
}

# Output the instance details including dualstack IPs
output "instance_public_ip" {
  description = "IPv4 Public IP"
  value       = aws_lightsail_instance.dualstack_instance.public_ip_address
}

output "instance_ipv6_addresses" {
  description = "IPv6 Addresses"
  value       = aws_lightsail_instance.dualstack_instance.ipv6_addresses
}

output "instance_id" {
  description = "Lightsail Instance ID"
  value       = aws_lightsail_instance.dualstack_instance.id
}

