    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# Create a Lightsail SSH key pair
resource "aws_lightsail_key_pair" "lightsail_ssh_key" {
  name              = "my-lightsail-ssh-key"
  public_key        = file("~/.ssh/lightsail_key.pub")  # Path to your public SSH key
}

# Create Lightsail instance
resource "aws_lightsail_instance" "lightsail_instance" {
  name              = "my-lightsail-instance"
  availability_zone = "us-east-1a"  # Change to your preferred AZ
  blueprint_id      = "amazon_linux_2"  # Amazon Linux 2 blueprint ID
  bundle_id         = "nano_2_0"  # nano bundle (smallest instance)

  key_pair_name     = aws_lightsail_key_pair.lightsail_ssh_key.name
}

# Output the instance details
output "instance_ip" {
  description = "Public IP of the Lightsail instance"
  value       = aws_lightsail_instance.lightsail_instance.public_ip_address
