# Create a Lightsail managed database
resource "aws_lightsail_database" "managed_db" {
  relational_database_name      = "my-managed-database"
  relational_database_blueprint_id = "mysql_8_0"  # Options: mysql_8_0, mariadb_10_6, postgresql_15, postgresql_14
  relational_database_bundle_id = "micro_1_0"     # Options: micro_1_0, small_2_0, medium_2_0, large_2_0, xlarge_2_0

  # Master database settings
  master_database_name     = "mydb"
  master_username          = "admin"
  master_user_password     = "SecurePassword123!"  # Use variables/secrets in production

  # Backup settings (optional)
  backup_retention_enabled = true
  preferred_backup_window  = "03:00-04:00"
  preferred_maintenance_window = "Sun:05:00-Sun:06:00"

  # Availability zone (optional, defaults to random)
  availability_zone = "us-east-1a"

  # Database parameters (optional)
  relational_database_parameter {
    name  = "character_set_server"
    value = "utf8mb4"
  }

  # Final snapshot on deletion (optional)
  final_snapshot_name = "final-snapshot-my-db"

  tags = {
    Name        = "My Lightsail Managed Database"
    Environment = "production"
  }
}

# Output the database endpoint
output "database_endpoint" {
  description = "The endpoint for the Lightsail database"
  value       = aws_lightsail_database.managed_db.endpoint[0].port
}

output "database_arn" {
  description = "ARN of the Lightsail database"
  value       = aws_lightsail_database.managed_db.arn
}

