  instance_name   = aws_lightsail_instance.example.id
  disk_path       = "/dev/xvdf"

  # Note: Instance must be stopped before attaching disk
  # You may need to add a lifecycle rule or separate apply if needed
}

# Optional: Output important information
output "instance_id" {
  value = aws_lightsail_instance.example.id
}

output "disk_id" {
  value = aws_lightsail_disk.example.id
}

output "attachment_id" {
  value = aws_lightsail_disk_attachment.example.id
}
```

**Important Notes:**
1. The Lightsail instance must be **stopped** before attaching a disk. You may need to:
   - Manually stop the instance via AWS Console/CLI before `terraform apply`
   - Or add a `null_resource` with `local-exec` to stop/start the instance
2. The `disk_path` `/dev/xvdf` is the mount point on the instance
3. After attachment, SSH into the instance and format/mount the disk manually:
   ```bash
   sudo mkfs.ext4 /dev/xvdf
   sudo mkdir /mnt/newdisk
   sudo mount /dev/xvdf /mnt/newdisk
   ```

