provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

# Create an S3 bucket
resource "aws_s3_bucket" "lightsail_bucket" {
  bucket = "my-lightsail-bucket-${random_id.bucket_suffix.hex}"
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Enable bucket versioning (optional, but recommended)
resource "aws_s3_bucket_versioning" "lightsail_bucket_versioning" {
  bucket = aws_s3_bucket.lightsail_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Create Lightsail static IP
resource "aws_lightsail_static_ip" "lightsail_static_ip" {
  name = "lightsail-static-ip"
}

# Create Lightsail instance
resource "aws_lightsail_instance" "lightsail_instance" {
  name              = "lightsail-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"  # or your preferred blueprint
  bundle_id         = "nano_2_0"        # or your preferred bundle

  # Attach static IP
  static_ip_name = aws_lightsail_static_ip.lightsail_static_ip.id
}

# Create IAM role for Lightsail instance to access S3
resource "aws_iam_role" "lightsail_s3_role" {
  name = "lightsail-s3-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "lightsail.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# Attach S3 access policy to the role
resource "aws_iam_role_policy" "lightsail_s3_policy" {
  name = "lightsail-s3-access-policy"
  role = aws_iam_role.lightsail_s3_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.lightsail_bucket.arn,
          "${aws_s3_bucket.lightsail_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Create Lightsail instance networking (optional - for outbound access)
resource "aws_lightsail_instance_public_ports" "lightsail_ports" {
  instance_name = aws_lightsail_instance.lightsail_instance.name
  port_info {
    from_port = 22
    to_port   = 22
    protocol  = "tcp"
  }
  port_info {
    from_port = 80
    to_port   = 80
    protocol  = "tcp"
  }
}

# Output important values
output "s3_bucket_name" {
  value = aws_s3_bucket.lightsail_bucket.bucket
}

output "lightsail_instance_ip" {
  value = aws_lightsail_static_ip.lightsail_static_ip.ip_address
}

output "iam_role_arn" {
  value = aws_iam_role.lightsail_s3_role.arn
}

