terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket for origin
resource "aws_s3_bucket" "origin_bucket" {
  bucket = "my-lightsail-distribution-origin-bucket"
}

resource "aws_s3_bucket_ownership_controls" "origin_bucket" {
  bucket = aws_s3_bucket.origin_bucket.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_acl" "origin_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.origin_bucket]

  bucket = aws_s3_bucket.origin_bucket.id
  acl    = "private"
}

resource "aws_s3_bucket_public_access_block" "origin_bucket" {
  bucket = aws_s3_bucket.origin_bucket.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Upload a sample object to the bucket
resource "aws_s3_object" "index_html" {
  bucket       = aws_s3_bucket.origin_bucket.id
  key          = "index.html"
  content      = "<html><body><h1>Hello from S3 Origin!</h1></body></html>"
  content_type = "text/html"
}

# Lightsail bucket access identity for origin access
resource "aws_lightsail_bucket" "origin_access_bucket" {
  name              = "lightsail-origin-access-bucket"
  bundle_id         = "small_1_0"
  enable_versioning = false
}

# OAI equivalent for Lightsail - create a bucket policy for origin access
data "aws_iam_policy_document" "origin_access_policy" {
  statement {
    sid    = "LightsailOriginAccess"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["lightsail.amazonaws.com"]
    }
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.origin_bucket.arn}/*"]
  }
}

resource "aws_s3_bucket_policy" "origin_bucket_policy" {
  bucket = aws_s3_bucket.origin_bucket.id
  policy = data.aws_iam_policy_document.origin_access_policy.json
}

# Lightsail CDN Distribution with S3 bucket as origin
resource "aws_lightsail_distribution" "main" {
  name      = "my-distribution"
  bundle_id = "starter"
  domain_name = "example.com"  # Replace with your domain
  certificate_name = "my-certificate"  # Create certificate first or use default

  origin {
    name       = "s3-origin"
    region_name = "us-east-1"
    protocol_policy = "http-only"
  }

  default_cache_behavior {
    target_origin_id       = "s3-origin"
    viewer_protocol_policy = "redirect-to-https"
  }

  # Cache behavior for static assets
  cache_behavior {
    target_origin_id       = "s3-origin"
    viewer_protocol_policy = "redirect-to-https"
    path_pattern           = "*.css|*.js|*.png|*.jpg|*.gif|*.ico"
    cache_ttl              = 86400  # 24 hours
  }

  # Custom domain (optional)
  # domain_name_aliases = ["www.example.com"]
}

# Output the distribution URL
output "distribution_url" {
  value = aws_lightsail_distribution.main.url
}

output "s3_bucket_name" {
  value = aws_s3_bucket.origin_bucket.id
}
```

**Note:** Before applying, you need to:
1. Replace `example.com` with your actual domain
2. Create a Lightsail certificate using `aws lightsail create-certificate` or use the default ACM certificate
3. Update DNS records to point to the Lightsail distribution domain
4. The S3 bucket policy allows Lightsail service access to the origin

