resource "aws_lightsail_instance" "origin_instance" {
  name              = "web-origin-instance"
  availability_zone = "us-east-1a"
  blueprint_id      = "amazon_linux_2"  # Use a blueprint with web server, e.g., Amazon Linux 2
  bundle_id         = "nano_2_0"        # Smallest bundle for demo

  # Optional: User data to install and start a simple web server
  user_data = <<-EOF
    #!/bin/bash
    yum update -y
    yum install -y httpd
    systemctl start httpd
    systemctl enable httpd
    echo "<h1>Hello from Lightsail Origin!</h1>" > /var/www/html/index.html
  EOF

  tags = {
    Name = "lightsail-origin"
  }
}

# Get the static IP of the Lightsail instance for origin use
resource "aws_lightsail_static_ip" "origin_static_ip" {
  name = "origin-static-ip"
}

resource "aws_lightsail_static_ip_attachment" "origin_ip_attachment" {
  static_ip_name = aws_lightsail_static_ip.origin_static_ip.id
  instance_name  = aws_lightsail_instance.origin_instance.name
}

# Create a Lightsail CDN Distribution using the instance as origin
resource "aws_lightsail_distribution" "web_distribution" {
  name               = "web-distribution"
  domain_name        = "example.com"  # Replace with your domain
  alternate_domain_names = ["www.example.com"]  # Optional

  origin {
    name       = "OriginInstance"
    region_name = "us-east-1"
    protocol_policy = "http-only"
    domain_name = aws_lightsail_static_ip.origin_static_ip.ip_address
  }

