    behavior = "cache"
    # Standard TTL settings
    cached_http_methods        = ["GET", "HEAD"]
    forwarded_cookies {
      option = "none"
    }
    forwarded_values {
      headers {
        option = "none"
      }
      query_strings {
        option = "none"
      }
    }
    ttl_days         = 1
    ttl_hours        = 0
    ttl_minutes      = 0
    ttl_seconds      = 0
  }

  certificate_name = "example-com-cert"  # Requires a Lightsail certificate for HTTPS

  tags = {
    Name = "lightsail-cdn-distribution"
  }
}

# Output the distribution domain name
