provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# S3 Bucket for long-term data storage (Infrequent Access)
resource "aws_s3_bucket" "long_term_storage" {
  bucket = "my-long-term-storage-bucket-${random_id.bucket_suffix.hex}"

  tags = {
    Name        = "Long Term Storage"
    Environment = "Production"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "long_term_storage_lifecycle" {
  bucket = aws_s3_bucket.long_term_storage.id

  rule {
    id     = "long-term-storage-rule"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "STANDARD_IA"  # Infrequent Access for long-term storage
    }

    noncurrent_version_transition {
      noncurrent_days = 90
      storage_class   = "GLACIER"
    }

    expiration {
      days = 3650  # 10 years
    }
  }
}

# S3 Bucket for backups (with versioning and Glacier Deep Archive)
resource "aws_s3_bucket" "backup_storage" {
  bucket = "my-backup-storage-bucket-${random_id.bucket_suffix.hex}"

  tags = {
    Name        = "Backup Storage"
    Environment = "Production"
  }
}

resource "aws_s3_bucket_versioning" "backup_storage_versioning" {
  bucket = aws_s3_bucket.backup_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_lifecycle_configuration" "backup_storage_lifecycle" {
  bucket = aws_s3_bucket.backup_storage.id

  rule {
    id     = "backup-storage-rule"
    status = "Enabled"

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER_INSTANT_RETRIEVAL"
    }

    noncurrent_version_transition {
      noncurrent_days = 180
      storage_class   = "GLACIER"
    }

    noncurrent_version_transition {
      noncurrent_days = 547
      storage_class   = "DEEP_ARCHIVE"
    }

    noncurrent_version_expiration {
      noncurrent_days = 3650  # 10 years
    }
  }
}

# Server-side encryption for both buckets
resource "aws_s3_bucket_server_side_encryption_configuration" "long_term_encryption" {
  bucket = aws_s3_bucket.long_term_storage.bucket

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "backup_encryption" {
  bucket = aws_s3_bucket.backup_storage.bucket

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Bucket policies for public access block
resource "aws_s3_bucket_public_access_block" "long_term_public_access" {
  bucket = aws_s3_bucket.long_term_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_public_access_block" "backup_public_access" {
  bucket = aws_s3_bucket.backup_storage.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Random ID to ensure unique bucket names
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Output bucket names and endpoints
output "long_term_storage_bucket_name" {
  value = aws_s3_bucket.long_term_storage.bucket
}

output "backup_storage_bucket_name" {
  value = aws_s3_bucket.backup_storage.bucket
}

output "long_term_storage_endpoint" {
  value = aws_s3_bucket.long_term_storage.bucket_regional_domain_name
}

output "backup_storage_endpoint" {
  value = aws_s3_bucket.backup_storage.bucket_regional_domain_name
}

