provider "aws" {
  region = "us-west-2"
}

# S3 Glacier Vault (now called S3 Glacier Storage Class in Lifecycle Policies)
# Note: Direct S3 Glacier Vaults are managed via S3 Lifecycle Policies on Buckets.
# AWS Data Lifecycle Manager (DLM) is used for EBS snapshots, not S3/Glacier directly.
# This config creates an S3 bucket with Glacier lifecycle policy.
# DLM example for EBS snapshots with Glacier-like retention is included.

resource "aws_s3_bucket" "glacier_bucket" {
  bucket = "my-glacier-bucket-${random_string.bucket_suffix.result}"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
}

resource "aws_s3_bucket_lifecycle_configuration" "glacier_lifecycle" {
  bucket = aws_s3_bucket.glacier_bucket.id

  rule {
    id     = "glacier-transition-rule"
    status = "Enabled"

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    transition {
      days          = 365
      storage_class = "GLACIER_DEEP_ARCHIVE"
    }

    noncurrent_version_expiration {
      noncurrent_days = 90
    }
  }
}

resource "aws_s3_bucket_versioning" "glacier_bucket_versioning" {
  bucket = aws_s3_bucket.glacier_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

# AWS Data Lifecycle Manager Policy for EBS Snapshots (with retention mimicking Glacier)
resource "aws_dlm_lifecycle_policy" "ebs_glacier_like_retention" {
  description        = "EBS snapshot policy with long-term retention"
  execution_role_arn = aws_iam_role.dlm_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "DailySnapshots"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["00:00"]
      }

      retain_rule {
        count = 30
      }

      tags_to_add = {
        SnapshotCreatedByDLM = "true"
      }
    }

    # Long-term retention mimicking Glacier (1 year)
    schedule {
      name = "YearlyArchive"

      create_rule {
        interval      = 30
        interval_unit = "DAYS"
        times         = ["00:00"]
      }

      retain_rule {
        count         = 12
        interval      = 30
        interval_unit = "DAYS"
      }

      tags_to_add = {
        ArchiveSnapshot = "true"
      }
    }
  }

  tags = {
    Name = "EBS-GlacierLike-DLM-Policy"
  }
}

# IAM Role for DLM
resource "aws_iam_role" "dlm_role" {
  name = "AWSDataLifecycleManagerDefaultRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dlm_role_policy" {
  role       = aws_iam_role.dlm_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSDataLifecycleManagerDefaultRole"
}

# Outputs
output "s3_bucket_name" {
  value = aws_s3_bucket.glacier_bucket.bucket
}

output "dlm_policy_id" {
  value = aws_dlm_lifecycle_policy.ebs_glacier_like_retention.id
}

