        interval_unit = "HOURS"
        times         = ["00:00"]
      }

      retain_rule {
        count = 30
      }

      tags_to_add = {
        SnapshotCreatedByDLM = "true"
      }
    }

    # Long-term retention mimicking Glacier (1 year)
    schedule {
      name = "YearlyArchive"

      create_rule {
        interval      = 30
        interval_unit = "DAYS"
        times         = ["00:00"]
      }

      retain_rule {
        count         = 12
        interval      = 30
