        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "dlm_role_policy" {
  role       = aws_iam_role.dlm_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSDataLifecycleManagerDefaultRole"
}

# Outputs
output "s3_bucket_name" {
  value = aws_s3_bucket.glacier_bucket.bucket
}

output "dlm_policy_id" {
  value = aws_dlm_lifecycle_policy.ebs_glacier_like_retention.id
}
```

**Note:** S3 Glacier vault functionality is implemented via S3 bucket lifecycle policies transitioning to GLACIER/GLACIER_DEEP_ARCHIVE storage classes. AWS DLM manages EBS snapshot lifecycles (not S3 directly), so a DLM policy with long-term retention mimicking Glacier behavior is included. Apply this configuration to create the infrastructure.

