terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

# Provider configuration (update region as needed)
provider "aws" {
  region = "us-east-1"
}

# S3 bucket for Glacier vault (storage for Glacier archives)
resource "aws_s3_bucket" "glacier_vault" {
  bucket = "my-glacier-vault-${random_id.bucket_suffix.hex}"
}

# Random suffix for unique bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Enable versioning
resource "aws_s3_bucket_versioning" "glacier_vault_versioning" {
  bucket = aws_s3_bucket.glacier_vault.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Glacier storage class (vault-like storage)
resource "aws_s3_bucket_lifecycle_configuration" "glacier_vault_lifecycle" {
  bucket = aws_s3_bucket.glacier_vault.id

  rule {
    id     = "glacier-transition"
    status = "Enabled"

    transition {
      days          = 1
      storage_class = "GLACIER"
    }

    noncurrent_version_transition {
      noncurrent_days = 1
      storage_class   = "GLACIER"
    }
  }
}

# SNS topic for notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"
}

# S3 bucket notification to SNS (triggers on object create events)
resource "aws_s3_bucket_notification" "glacier_bucket_notification" {
  bucket = aws_s3_bucket.glacier_vault.id

  topic {
    topic_arn     = aws_sns_topic.glacier_notifications.arn
    events        = ["s3:ObjectCreated:*"]
    filter_suffix = ".glacier"
  }

  depends_on = [aws_s3_bucket.glacier_vault]
}

# Optional: SNS topic policy to allow S3 to publish
resource "aws_sns_topic_policy" "glacier_sns_policy" {
  arn = aws_sns_topic.glacier_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.glacier_notifications.arn
        Condition = {
          ArnEquals = {
            "aws:SourceArn" = aws_s3_bucket.glacier_vault.arn
          }
        }
      }
    ]
  })
}

# Output the bucket name and SNS topic ARN
output "glacier_vault_bucket_name" {
  value = aws_s3_bucket.glacier_vault.bucket
}

output "sns_topic_arn" {
  value = aws_sns_topic.glacier_notifications.arn
}

