    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

# IAM role for Glacier Vault Lock policy
resource "aws_iam_role" "glacier_vault_lock_role" {
  name = "glacier-vault-lock-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "glacier.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Glacier Vault Lock
resource "aws_iam_role_policy" "glacier_vault_lock_policy" {
  name = "glacier-vault-lock-policy"
  role = aws_iam_role.glacier_vault_lock_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "glacier:InitiateVaultLock",
          "glacier:AbortVaultLock"
        ]
        Resource = aws_glacier_vault.vault.arn
      }
    ]
  })
}

# Glacier Vault
resource "aws_glacier_vault" "vault" {
  name = "my-glacier-vault"
}

# Vault Lock configuration
resource "aws_glacier_vault_lock" "vault_lock" {
  vault_name       = aws_glacier_vault.vault.name
  policy           = jsonencode({
    "Type"  : "AWSGlacierVaultLockPolicy",
    "Version": "2012-10-17",
    "Statement": [
      {
        "Sid": "EnforceCompliance",
        "Effect": "Deny",
        "Principal": "*",
        "Action": "glacier:DeleteArchive",
        "Resource": aws_glacier_vault.vault.arn,
        "Condition": {
          "DateGreaterThan": {
            "aws:CurrentTime": "2025-01-01T00:00:00Z"
          }
        }
      }
    ]
  })
  complete_lock   = true
  ignore_resource_policy = false
}

# Attach IAM role to vault lock (required for vault lock operations)
resource "aws_glacier_vault_lock_access_policy" "vault_lock_access" {
  vault_name = aws_glacier_vault.vault.name
  policy     = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.glacier_vault_lock_role.arn
        }
        Action   = "glacier:InitiateVaultLock"
        Resource = aws_glacier_vault.vault.arn
      }
    ]
  })
}

output "vault_arn" {
  value = aws_glacier_vault.vault.arn
}

output "vault_name" {
  value = aws_glacier_vault.vault.name
}

output "vault_lock_id" {
  value = aws_glacier_vault_lock.vault_lock.id
}

reference:
provider "aws" {
  region     = "us-east-1"
}

resource "aws_glacier_vault" "example" {
  name = "example"
}

data "aws_iam_policy_document" "example" {
  statement {
    actions   = ["glacier:DeleteArchive"]
    effect    = "Deny"
    resources = [aws_glacier_vault.example.arn]

    condition {
      test     = "NumericLessThanEquals"
      variable = "glacier:ArchiveAgeinDays"
      values   = ["365"]
    }
  }
}

resource "aws_glacier_vault_lock" "example" {
  complete_lock = false
  policy        = data.aws_iam_policy_document.example.json
  vault_name    = aws_glacier_vault.example.name
}

