      type        = "AWS"
      identifiers = ["arn:aws:iam::123456789012:root"] # Replace with your account ID
    }

    actions = [
      "glacier:InitiateArchiveRetrieval",
      "glacier:GetJobOutput",
      "glacier:ListJobs",
      "glacier:DescribeJob",
      "glacier:GetDataRetrievalPolicy"
    ]

    resources = ["arn:aws:glacier:us-east-1:123456789012:vaults:my-glacier-vault"] # Replace region and account ID
  }
}

# Glacier Vault
resource "aws_glacier_vault" "my_glacier_vault" {
