        "Effect": "Deny",
        "Principal": "*",
        "Action": "glacier:DeleteArchive",
        "Resource": "arn:aws:glacier:*:*:vaults/${aws_glacier_vault.my_glacier_vault.name}/*",
        "Condition": {
