provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# S3 bucket for Glacier notifications (SNS topic will publish here)
resource "aws_s3_bucket" "notification_bucket" {
  bucket = "glacier-notifications-bucket-unique"  # Must be globally unique
}

resource "aws_s3_bucket_notification" "glacier_bucket_notification" {
  bucket = aws_s3_bucket.notification_bucket.id

  topic {
    topic_arn     = aws_sns_topic.glacier_retrieval_complete.arn
    events        = ["s3:ObjectCreated:*"]
    filter_prefix = "glacier-retrievals/"
  }
}

# SNS topic for Glacier archive retrieval completion notifications
resource "aws_sns_topic" "glacier_retrieval_complete" {
  name = "glacier-archive-retrieval-complete"
}

# Optional: SNS topic policy to allow S3 to publish
resource "aws_sns_topic_policy" "default" {
  arn = aws_sns_topic.glacier_retrieval_complete.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
        Action   = "sns:Publish"
        Resource = aws_sns_topic.glacier_retrieval_complete.arn
        Condition = {
          ArnEquals = {
            "aws:SourceArn" = aws_s3_bucket.notification_bucket.arn
          }
        }
      }
    ]
  })
}

# AWS Glacier Vault
