```hcl
# Terraform configuration for an AWS Application Load Balancer with Elastic IPs
# Note: Elastic IPs are associated with Network Load Balancers (NLB) via Target Groups or ENIs.
# This example uses an NLB with Elastic IPs associated to the load balancer subnets.

terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "lb-vpc"
  }
}

# Public Subnets for Load Balancer
resource "aws_subnet" "public_a" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-a"
  }
}

resource "aws_subnet" "public_b" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet-b"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Public Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_a" {
  subnet_id      = aws_subnet.public_a.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "public_b" {
  subnet_id      = aws_subnet.public_b.id
  route_table_id = aws_route_table.public.id
}

# Elastic IPs for NLB
resource "aws_eip" "nlb_eip_a" {
  domain = "vpc"
  tags = {
    Name = "nlb-eip-a"
  }
}

resource "aws_eip" "nlb_eip_b" {
  domain = "vpc"
  tags = {
    Name = "nlb-eip-b"
  }
}

# Network Load Balancer
resource "aws_lb" "main" {
  name               = "my-nlb-with-eips"
  internal           = false
  load_balancer_type = "network"
  subnets            = [aws_subnet.public_a.id, aws_subnet.public_b.id]

  # Associate Elastic IPs with subnets
  subnet_mapping {
    subnet_id     = aws_subnet.public_a.id
    allocation_id = aws_eip.nlb_eip_a.id
  }

  subnet_mapping {
    subnet_id     = aws_subnet.public_b.id
    allocation_id = aws_eip.nlb_eip_b.id
  }

  enable_deletion_protection = false

  tags = {
    Name = "nlb-with-eips"
  }
}

# Target Group
resource "aws_lb_target_group" "main" {
  name        = "my-tg"
  port        = 80
  protocol    = "TCP"
  vpc_id      = aws_vpc.main.id
  target_type = "ip"

  health_check {
    protocol = "TCP"
    port     = "traffic-port"
  }

  tags = {
    Name = "my-tg"
  }
}

# Listener
resource "aws_lb_listener" "main" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.main.arn
  }
}

# Output the DNS name and Elastic IPs
output "nlb_dns_name" {
  value = aws_lb.main.dns_name
}

output "elastic_ip_a" {
  value = aws_eip.nlb_eip_a.public_ip
}

output "elastic_ip_b" {
  value = aws_eip.nlb_eip_b.public_ip
}
```

This configuration creates:
- A VPC with public subnets
- Elastic IPs explicitly assigned to NLB subnets
- A Network Load Balancer (NLB) that uses the specified Elastic IPs
- A target group and listener on port 80/TCP

**Key points:**
- Only NLBs support static Elastic IPs via `subnet_mapping`
- ALBs use dynamic IPs from subnet pools
- The EIPs are statically assigned and survive NLB recreation
- Run `terraform apply` to deploy and check outputs for DNS/EIP addresses

