  availability_zone = "us-west-2b"
  tags = {
    Name = "private-subnet-b"
  }
}

# Internet Gateway (for NAT gateway if needed, but not directly required for internal LB)
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# NAT Gateway (optional, for outbound internet access from private subnets)
resource "aws_eip" "nat" {
  domain = "vpc"
}

resource "aws_nat_gateway" "main" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.private_a.id
  tags = {
    Name = "main-nat"
  }
  depends_on = [aws_internet_gateway.main]
}

# Route tables
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.main.id
  }

  tags = {
    Name = "private-rt"
  }
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_a.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.private.id
}

# Target Group
resource "aws_lb_target_group" "internal" {
  name     = "internal-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    enabled             = true
    healthy_threshold   = 2
    interval            = 30
    matcher             = "200"
    path                = "/"
    port                = "traffic-port"
    protocol            = "HTTP"
    timeout             = 5
    unhealthy_threshold = 2
  }

  tags = {
    Name = "internal-target-group"
  }
}

# Network Load Balancer (Internal-facing with specific private IP addresses)
resource "aws_lb" "internal_nlb" {
  name               = "internal-nlb"
  internal           = true
  load_balancer_type = "network"
  subnets            = [aws_subnet.private_a.id, aws_subnet.private_b.id]

  # Specify private IP addresses for each subnet
  subnet_mapping {
    subnet_id     = aws_subnet.private_a.id
    private_ipv4  = "10.0.1.100"  # Specific private IP in subnet 10.0.1.0/24
  }

  subnet_mapping {
    subnet_id     = aws_subnet.private_b.id
    private_ipv4  = "10.0.2.100"  # Specific private IP in subnet 10.0.2.0/24
  }

  enable_deletion_protection = false

  tags = {
    Name = "internal-nlb"
    Environment = "production"
  }
}

# Listener
resource "aws_lb_listener" "internal_nlb" {
  load_balancer_arn = aws_lb.internal_nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.internal.arn
  }
}

# Security Group for Load Balancer (allow internal traffic)
resource "aws_security_group" "nlb_sg" {
  name_prefix = "nlb-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTP from VPC"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "nlb-security-group"
  }
}

resource "aws_security_group" "target_sg" {
  name_prefix = "target-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "HTTP from NLB"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    security_groups = [aws_security_group.nlb_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "target-security-group"
  }
}

# Output the NLB DNS name and private IPs
output "nlb_dns_name" {
  description = "DNS name of the internal NLB"
  value       = aws_lb.internal_nlb.dns_name
}

output "nlb_private_ips" {
  description = "Private IP addresses assigned to the NLB"
  value = {
    subnet_a = aws_lb.internal_nlb.subnet_mappings[0].private_ipv4
    subnet_b = aws_lb.internal_nlb.subnet_mappings[1].private_ipv4
  }
}

