  security_groups    = [aws_security_group.alb.id]
  subnets            = [aws_subnet.public.id]

  enable_deletion_protection = false

  tags = {
    Name = "app-alb"
  }
}

# Security Group for ALB
resource "aws_security_group" "alb" {
  name_prefix = "alb-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg"
  }
}

# Listener with Fixed Response Rule
resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.main.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "fixed-response"

    fixed_response {
      content_type = "text/plain"
      message_body = "Fixed response from ALB! 200 OK"
      status_code  = "200"
    }
  }
}

# Output
output "alb_dns_name" {
  value = aws_lb.main.dns_name
}
```

This configuration creates an AWS Application Load Balancer (ALB) with a listener on port 80 that returns a fixed HTTP 200 response with a custom message body, regardless of backend targets. The setup includes complete networking infrastructure (VPC, subnet, IGW) and security group for public access.

