# EC2 instances with static private IPs (IP targets)
resource "aws_instance" "target1" {
  ami           = "ami-0c02fb55956c7d316" # Amazon Linux 2 AMI (update for your region)
  instance_type = "t3.micro"
  subnet_id     = aws_subnet.public1.id
  vpc_security_group_ids = [aws_security_group.target_sg.id]

  private_ip = "10.0.1.10"

  user_data = <<-EOF
              #!/bin/bash
              echo "Target 1" > /var/www/html/index.html
