  target_group_arn = aws_lb_target_group.ip_tg.arn
  target_id        = aws_instance.target1.private_ip
  port             = 80
}

resource "aws_lb_target_group_attachment" "target2" {
  target_group_arn = aws_lb_target_group.ip_tg.arn
  target_id        = aws_instance.target2.private_ip
  port             = 80
}

# Listener
