  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# VPC for the RDS instance
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "postgres-vpc"
  }
}

# Public subnet
resource "aws_subnet" "public_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "public-subnet-a"
  }
}

# Private subnet
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-subnet-a"
  }
}

# Private subnet b (for Multi-AZ)
resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-subnet-b"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

# Route Table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
  tags = {
    Name = "public-rt"
  }
}

resource "aws_route_table_association" "public_a" {
  subnet_id      = aws_subnet.public_a.id
  route_table_id = aws_route_table.public.id
}

# DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "postgres-subnet-group"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]
  tags = {
    Name = "postgres-subnet-group"
  }
}

# Security Group for PostgreSQL
resource "aws_security_group" "postgres" {
  name_prefix = "postgres-sg"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgres-security-group"
  }
}

# Memory-optimized PostgreSQL RDS instance (r6g.2xlarge - 16GB RAM)
resource "aws_db_instance" "memory_optimized_postgres" {
  identifier              = "memory-postgres"
  engine                  = "postgres"
  engine_version          = "15.5"
  instance_class          = "db.r6g.2xlarge"  # Memory-optimized Graviton instance
  allocated_storage       = 100
  storage_type            = "gp3"
  storage_encrypted       = true
  db_subnet_group_name    = aws_db_subnet_group.main.name
  vpc_security_group_ids  = [aws_security_group.postgres.id]
  multi_az                = true
  db_name                 = "mydb"
  username                = "admin"
  password                = "SecurePassword123!"  # Use secrets manager in production
  backup_retention_period = 7
  skip_final_snapshot     = true
  publicly_accessible     = false
  performance_insights_enabled = true

  # Memory-optimized parameters
  parameter_group_name = aws_db_parameter_group.memory_optimized.name

  tags = {
    Name = "memory-optimized-postgres"
  }
}

# Custom parameter group for memory optimization
resource "aws_db_parameter_group" "memory_optimized" {
  name   = "memory-postgres-params"
  family = "postgres15"

  parameter {
    name  = "shared_preload_libraries"
    value = "pg_stat_statements"
  }

  parameter {
    name  = "effective_cache_size"
    value = "12GB"  # 75% of instance memory
  }

  parameter {
    name  = "work_mem"
    value = "64MB"
  }

  parameter {
    name  = "maintenance_work_mem"
    value = "512MB"
  }

  parameter {
    name  = "checkpoint_completion_target"
    value = "0.9"
  }

  parameter {
    name  = "wal_buffers"
    value = "16MB"
  }

  parameter {
    name  = "default_statistics_target"
    value = "100"
  }

  parameter {
    name  = "random_page_cost"
    value = "1.1"
  }

  parameter {
    name  = "effective_io_concurrency"
    value = "200"
  }
}

# Output the connection endpoint
output "postgres_endpoint" {
  description = "The cluster endpoint"
  value       = aws_db_instance.memory_optimized_postgres.endpoint
}

output "postgres_port" {
  description = "The database port"
  value       = aws_db_instance.memory_optimized_postgres.port
}

