terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

# S3 bucket containing the database backup (must exist beforehand)
resource "aws_s3_bucket" "backup_bucket" {
  bucket = "my-db-backup-bucket-unique"
}

# Upload a sample backup file to S3 (in real scenario, upload your actual DB backup)
resource "aws_s3_object" "db_backup" {
  bucket = aws_s3_bucket.backup_bucket.id
  key    = "backup.dump"
  source = "backup.dump"  # Local path to your backup file
}

# RDS DB instance restored from S3 backup
resource "aws_db_instance" "restored_from_s3" {
  identifier              = "db-restored-from-s3"
  engine                  = "postgres"  # or mysql, etc.
  engine_version          = "15.4"
  instance_class          = "db.t3.micro"
  allocated_storage       = 20
  storage_type            = "gp2"
  storage_encrypted       = true
  skip_final_snapshot     = true

  # Restore from S3
  s3_bucket_name         = aws_s3_bucket.backup_bucket.bucket
  s3_ingestion_role_arn  = aws_iam_role.s3_ingestion_role.arn
  s3_prefix              = "backup"  # Prefix matching the S3 object key

  # Database parameters
  username = "admin"
  password = "SecurePassword123!"
  publicly_accessible = false

  vpc_security_group_ids = [aws_security_group.db_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.main.name

  tags = {
    Name = "RestoredFromS3"
  }
}

# VPC for the database
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "db-vpc"
  }
}

# Subnets for DB subnet group
resource "aws_subnet" "db_subnet_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "db-subnet-1"
  }
}

resource "aws_subnet" "db_subnet_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "db-subnet-2"
  }
}

# DB subnet group
resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = [aws_subnet.db_subnet_1.id, aws_subnet.db_subnet_2.id]

  tags = {
    Name = "Main DB Subnet Group"
  }
}

# Security group for RDS
resource "aws_security_group" "db_sg" {
  name_prefix = "db-sg-"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 5432  # PostgreSQL port
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS Security Group"
  }
}

# IAM role for S3 ingestion into RDS
resource "aws_iam_role" "s3_ingestion_role" {
  name = "rds-s3-ingestion-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for S3 access
resource "aws_iam_role_policy" "s3_ingestion_policy" {
  name = "rds-s3-ingestion-policy"
  role = aws_iam_role.s3_ingestion_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject*",
          "s3:GetBucket*",
          "s3:List*"
        ]
        Resource = [
          aws_s3_bucket.backup_bucket.arn,
          "${aws_s3_bucket.backup_bucket.arn}/*"
        ]
      }
    ]
  })
}

# Internet gateway (optional, for VPC connectivity)
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

# Route table
resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "a" {
  subnet_id      = aws_subnet.db_subnet_1.id
  route_table_id = aws_route_table.public.id
}

resource "aws_route_table_association" "b" {
  subnet_id      = aws_subnet.db_subnet_2.id
  route_table_id = aws_route_table.public.id
}

