  vpc_security_group_ids = [aws_security_group.rds.id]
  # subnet_ids           = aws_subnet.example[*].id  # Uncomment and configure if using custom VPC

  skip_final_snapshot = true
}

# KMS Key Alias for RDS (uses default AWS managed key under the hood)
resource "aws_kms_key" "rds" {
  description             = "KMS key for RDS Secrets Manager"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

resource "aws_kms_alias" "rds" {
  name          = "alias/rds-secrets"
