  region = "us-west-2"  # Change to your preferred region
}

# VPC and subnets for EFS (required for EFS)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "efs-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${var.region}a"
  tags = {
    Name = "efs-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${var.region}b"
  tags = {
    Name = "efs-subnet-b"
  }
}

# EFS File System
resource "aws_efs_file_system" "main" {
  creation_token   = "my-efs-filesystem"
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"
  encrypted        = true

  tags = {
    Name = "my-efs-with-lifecycle"
  }

  # EFS Lifecycle Policy
  lifecycle_policy {
    transition_to_ia    = "AFTER_30_DAYS"
    transition_to_primary_storage_class = "AFTER_1_DAYS"
  }
}

# EFS Mount Targets
resource "aws_efs_mount_target" "mount_a" {
  file_system_id  = aws_efs_file_system.main.id
  subnet_id       = aws_subnet.subnet_a.id
