  vpc_id            = aws_vpc.efs_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "efs-subnet-1"
  }
}

# Subnet 2
resource "aws_subnet" "efs_subnet_2" {
  vpc_id            = aws_vpc.efs_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "efs-subnet-2"
  }
}

# EFS File System
resource "aws_efs_file_system" "efs_system" {
  creation_token   = "my-efs-system"
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"
  encrypted        = true

  tags = {
    Name = "my-efs-system"
  }

  # System policy for EFS (root-level access control)
  file_system_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "AllowRootAccess"
        Effect    = "Allow"
        Principal = {
          AWS = "*"
        }
        Action   = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource = "arn:aws:elasticfilesystem:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:file-system/${self.id}"
        Condition = {
          Bool = {
            "aws:SecureTransport" = "true"
          }
        }
      },
      {
        Sid       = "DenyInsecureAccess"
        Effect    = "Deny"
        Principal = "*"
        Action    = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite"
        ]
        Resource  = "arn:aws:elasticfilesystem:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:file-system/${self.id}"
        Condition = {
          Bool = {
            "aws:SecureTransport" = "false"
          }
        }
      }
    ]
  })
}

# Data sources for dynamic policy references
