# Configure the AWS Provider
provider "aws" {
  region = "us-west-2"  # Change to your preferred region
}

# AWS EFS File System with automatic backups enabled
resource "aws_efs_file_system" "example" {
  creation_token   = "my-efs-token"
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"
  encrypted        = true

  # Enable automatic backups
  tags = {
    Name = "example-efs"
  }
}

# EFS Backup Policy to enable automatic daily backups
resource "aws_efs_backup_policy" "example" {
  file_system_id = aws_efs_file_system.example.id

  backup_policy {
    status = "ENABLED"
  }
}

# Mount target for the EFS (optional, for accessibility)
resource "aws_efs_mount_target" "example" {
  count           = 2
  file_system_id  = aws_efs_file_system.example.id
  subnet_id       = element(data.aws_subnets.example.ids, count.index)
  security_groups = [aws_security_group.efs.id]
}

# Data source for subnets (adjust to your VPC)
data "aws_subnets" "example" {
  filter {
    name   = "vpc-id"
    values = ["vpc-12345678"]  # Replace with your VPC ID
  }
}

# Security group for EFS
