output "efs_dns_name" {
  description = "DNS name of the EFS file system"
  value       = aws_efs_file_system.example.dns_name
}
```

**Note:** Update the `vpc_id` and subnet filters with your actual VPC and subnet details before applying. The backup policy enables AWS Backup for daily automated backups of the EFS file system.

extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-west-2"  # Change to your desired region
}

# VPC and subnets (required for EFS mount targets)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "efs-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "${var.region}a"
  tags = {
    Name = "efs-subnet-a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "${var.region}b"
  tags = {
    Name = "efs-subnet-b"
  }
}

# Security group for EFS mount targets
resource "aws_security_group" "efs_sg" {
  vpc_id = aws_vpc.main.id

  ingress {
    description     = "NFS from VPC"
    from_port       = 2049
    to_port         = 2049
    protocol        = "tcp"
    cidr_blocks     = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-security-group"
  }
}

# EFS File System
resource "aws_efs_file_system" "main" {
  creation_token   = "my-efs-token"
  performance_mode = "generalPurpose"
  throughput_mode  = "bursting"
  encrypted        = true

  tags = {
    Name = "my-efs"
  }
}

# EFS Mount Targets
resource "aws_efs_mount_target" "mount_a" {
  file_system_id  = aws_efs_file_system.main.id
  subnet_id       = aws_subnet.subnet_a.id
  security_groups = [aws_security_group.efs_sg.id]
}

resource "aws_efs_mount_target" "mount_b" {
  file_system_id  = aws_efs_file_system.main.id
  subnet_id       = aws_subnet.subnet_b.id
  security_groups = [aws_security_group.efs_sg.id]
}

# EFS Access Point (optional but recommended)
resource "aws_efs_access_point" "main" {
  file_system_id = aws_efs_file_system.main.id

  posix_user {
    uid = 1000
    gid = 1000
  }

  root_directory {
    path = "/exported/path"
    creation_info {
      owner_gid   = 1000
      owner_uid   = 1000
      permissions = "755"
    }
  }
}

variable "region" {
  description = "AWS region"
  type        = string
  default     = "us-west-2"
}

output "efs_id" {
  description = "EFS File System ID"
  value       = aws_efs_file_system.main.id
}

output "mount_target_dns_a" {
  description = "Mount target DNS in subnet A"
  value       = aws_efs_mount_target.mount_a.mount_target_dns_name
}

output "mount_target_dns_b" {
  description = "Mount target DNS in subnet B"
  value       = aws_efs_mount_target.mount_b.mount_target_dns_name
}

