# Provider configuration (update region as needed)
provider "aws" {
  region = "us-west-2"
}

# Example VPC with IPv6 support (replace with your existing VPC ID if available)
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  assign_generated_ipv6_cidr_block = true

  tags = {
    Name = "main-vpc"
  }
}

# Egress-only Internet Gateway
resource "aws_egress_only_internet_gateway" "egress_only_igw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "egress-only-igw"
  }
}

# IPv6 Route Table
resource "aws_route_table" "ipv6_rt" {
  vpc_id = aws_vpc.main.id

  route {
    ipv6_cidr_block         = "::/0"
    egress_only_gateway_id  = aws_egress_only_internet_gateway.egress_only_igw.id
