  tags = {
    Name = "example-vpc"
  }
}

# DHCP Options Set named "pike" with Google DNS servers
resource "aws_vpc_dhcp_options" "pike" {
  domain_name          = "pike.example.com"
  domain_name_servers  = ["8.8.8.8", "8.8.4.4"]
  ntp_servers          = ["169.254.169.123"]
  netbios_name_servers = ["169.254.169.123"]
  netbios_node_type    = 2

  tags = {
    Name        = "pike"
    permissions = "true"
  }
}

# Associate DHCP options with the VPC
