extracted_code:
# Variables for customization
variable "subnet_id" {
  description = "ID of the subnet where the NAT Gateway will be deployed"
  type        = string
}

variable "eip_allocation_id" {
  description = "Elastic IP allocation ID to associate with the NAT Gateway"
  type        = string
}

# NAT Gateway resource
resource "aws_nat_gateway" "private_nat" {
  allocation_id = var.eip_allocation_id
  subnet_id     = var.subnet_id

  tags = {
    Name       = "private-nat-gateway"
    pike       = "permissions"
  }

  depends_on = [aws_internet_gateway.main] # Ensure IGW exists for EIP
}

# Example supporting resources (Internet Gateway and VPC for completeness)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "public-subnet"
  }
}

# Outputs
output "nat_gateway_id" {
  description = "ID of the created NAT Gateway"
  value       = aws_nat_gateway.private_nat.id
}

output "nat_gateway_public_ip" {
  description = "Public IP address of the NAT Gateway"
  value       = aws_nat_gateway.private_nat.public_ip
}

