}

# Example supporting resources (Internet Gateway and VPC for completeness)
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-igw"
  }
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  tags = {
    Name = "public-subnet"
  }
}

# Outputs
output "nat_gateway_id" {
  description = "ID of the created NAT Gateway"
  value       = aws_nat_gateway.private_nat.id
}

output "nat_gateway_public_ip" {
  description = "Public IP address of the NAT Gateway"
  value       = aws_nat_gateway.private_nat.public_ip
}
```

**Usage Notes:**
- Replace `var.subnet_id` and `var.eip_allocation_id` with your actual subnet ID and EIP allocation ID.
- Deploy in a public subnet for proper NAT functionality (internet access required).
- The `pike = "permissions"` tag is applied as specified.
- Supporting VPC/IGW/subnet resources are included for a complete working example.

