```hcl
provider "aws" {
  region = "us-east-1"  # Change to your desired region
}

resource "aws_default_network_acl" "default" {
  default_network_acl_id = aws_default_network_acl.default.id

  # Unrestricted ingress rule: allow all traffic from anywhere
  ingress {
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 65535
    protocol   = "all"
  }

  # Unrestricted egress rule: allow all traffic to anywhere
  egress {
    rule_no    = 100
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 65535
    protocol   = "all"
  }

  # Remove any existing deny rules (optional, ensures clean state)
  subnet_ids = []

  tags = {
    Name = "default-unrestricted-nacl"
  }
}
```

**Note:** This modifies the AWS **default** Network ACL for the region, which affects all subnets without explicit ACL associations. The default NACL cannot be destroyed, only modified. Use with caution in production environments. For a custom NACL instead, replace `aws_default_network_acl` with `aws_network_acl`.

extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"  # Change to your preferred region
}

# VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

# Network ACL
resource "aws_network_acl" "main" {
  vpc_id = aws_vpc.main.id
  subnet_ids = []  # Not associating with specific subnets; can be added later
  tags = {
    Name = "main-nacl"
  }

  # Ingress rule: Allow TCP port 80 from 10.3.0.0/18
  ingress {
    protocol   = "tcp"
    rule_no    = 100
    action     = "allow"
    cidr_block = "10.3.0.0/18"
    from_port  = 80
    to_port    = 80
  }

  # Egress rule: Allow TCP port 443 to 10.3.0.0/18
  egress {
    protocol   = "tcp"
    rule_no    = 100
    action     = "allow"
    cidr_block = "10.3.0.0/18"
    from_port  = 443
    to_port    = 443
  }

  # Default deny all ingress (rule 32766)
  ingress {
    protocol   = "all"
    rule_no    = 32766
    action     = "deny"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 65535
  }

  # Default deny all egress (rule 32766)
  egress {
    protocol   = "all"
    rule_no    = 32766
    action     = "deny"
    cidr_block = "0.0.0.0/0"
    from_port  = 0
    to_port    = 65535
  }

  # Ephemeral ports for return traffic (required for proper NACL functionality)
  ingress {
    protocol   = "tcp"
    rule_no    = 200
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 1024
    to_port    = 65535
  }

  egress {
    protocol   = "tcp"
    rule_no    = 200
    action     = "allow"
    cidr_block = "0.0.0.0/0"
    from_port  = 1024
    to_port    = 65535
  }
}

